#include <iostream>
#include <cmath>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        if (a == b) {
            std::cout << 0 << "\n";
            continue;
        }
        long long diff = std::abs(a - b);
        long long presses = 0;

        // Greedy approach: use largest denominations first
        // Number of 5s
        presses += diff / 5;
        diff %= 5;

        // Now diff is 0, 1, 2, 3, or 4
        if (diff == 0) {
            // No remaining difference
        } else if (diff == 1) {
            // Can use one '1' button
            presses += 1;
        } else if (diff == 2) {
            // Can use one '2' button
            presses += 1;
        } else if (diff == 3) {
            // Can use one '1' and one '2' button (2 presses)
            // Or one '5' button and then two '1' buttons (3 presses)
            // Or one '5' button and then one '2' button (2 presses)
            // The optimal is one '1' and one '2' (2 presses)
            presses += 2;
        } else if (diff == 4) {
            // Can use two '2' buttons (2 presses)
            // Or one '5' button and then one '1' button (2 presses)
            // The optimal is two '2's or one '5' and one '1' (2 presses)
            presses += 2;
        }
        std::cout << presses << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Item {
    int value;
    int original_index;
};

bool compareItems(const Item& a, const Item& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<Item> a(n);
        std::vector<Item> b(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i].value;
            a[i].original_index = i;
        }
        for (int i = 0; i < n; ++i) {
            std::cin >> b[i].value;
            b[i].original_index = i;
        }

        std::sort(a.begin(), a.end(), compareItems);
        std::sort(b.begin(), b.end(), compareItems);

        std::vector<int> result_x(n);
        std::vector<int> result_y(n);

        for (int i = 0; i < n; ++i) {
            result_x[a[i].original_index] = a[i].value;
            result_y[a[i].original_index] = b[i].value;
        }

        for (int i = 0; i < n; ++i) {
            std::cout << result_x[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << result_y[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
