int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, d;
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0];
        long long remaining_days = d;

        for (int i = 1; i < n; ++i) {
            // Cost to move one haybale from pile i+1 (0-indexed i) to pile 1 (0-indexed 0)
            // is i days.
            long long cost_per_haybale = i; 

            if (remaining_days >= cost_per_haybale) {
                // Calculate how many haybales we can move from this pile
                // based on available haybales and remaining days.
                long long haybales_to_move = std::min((long long)a[i], remaining_days / cost_per_haybale);

                current_a1 += haybales_to_move;
                remaining_days -= haybales_to_move * cost_per_haybale;
            } else {
                // Not enough days to move even one haybale from this pile.
                // Since piles are processed in increasing order of distance,
                // we won't be able to move haybales from any further piles either.
                break; 
            }
        }
        std::cout << current_a1 << std::endl;
    }
    return 0;
}

#include <iostream>
