void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    int current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the total value contributed by this power of two
        // up to 2048.
        // For example, if we have three 512s, we can combine two to make 1024.
        // The remaining 512 is also available.
        // So, we effectively have 1024 + 512.
        // This is equivalent to adding 512 * 3 to current_sum.
        current_sum += val * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

