void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation needed for this position.
        // The presence of +1 or -1 doesn't matter for this specific position,
        // but it might matter for future positions.
    }

    std::cout << "YES\n";
}

