#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The median of the first class will be a[n-1]
        // The median of the second class will be a[n]
        // This is because if we split the sorted array into two halves of size n,
        // the largest element of the first half is a[n-1] and the smallest element
        // of the second half is a[n].
        // If we assign a[0]...a[n-1] to one class and a[n]...a[2n-1] to another,
        // and then swap a[n-1] and a[n], the medians would be a[n-1] and a[n].
        // More generally, for any partition into two odd-sized classes,
        // the median of one class will be some a_i and the median of the other
        // will be some a_j.
        // The optimal strategy is to make the two classes as balanced as possible
        // in terms of their elements.
        // The minimum difference is achieved when the two medians are a[n-1] and a[n].
        // This corresponds to a partition where one class takes elements up to a[n-1]
        // and the other takes elements from a[n].
        // For example, class 1: {a_0, ..., a_{n-1}}, class 2: {a_n, ..., a_{2n-1}}.
        // Both classes have size n. If n is odd, this is a valid partition.
        // If n is even, this is not a valid partition.
        // However, the problem asks for *any* partition into odd-sized classes.
        // The key insight is that the median of a class of size 2k+1 is the (k+1)-th element.
        // If we sort all 2n elements, the smallest possible median for any class
        // is a[0] (if class size is 1). The largest is a[2n-1] (if class size is 1).
        // To minimize the difference, we want the medians to be adjacent in the sorted list.
        // The elements a[n-1] and a[n] are the two "middle" elements of the entire sorted array.
        // It is always possible to construct two odd-sized classes such that their medians
        // are a[n-1] and a[n].
        // For example, Class 1: {a_0, a_1, ..., a_{n-1}} (size n)
        // Class 2: {a_n, a_{n+1}, ..., a_{2n-1}} (size n)
        // If n is odd, this is a valid partition, and the medians are a[(n-1)/2] and a[n + (n-1)/2].
        // This is not what we want.
        // The problem is simpler: the minimum difference between medians will always be
        // the difference between the two middle elements of the *entire* sorted array.
        // Consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        // The two "middle" elements are $a_{n-1}$ and $a_n$.
        // We can always form two classes such that $a_{n-1}$ is the median of one class
        // and $a_n$ is the median of the other.
        // For example, Class 1: $\{a_0, \dots, a_{n-1}\}$ and Class 2: $\{a_n, \dots, a_{2n-1}\}$.
        // If $n$ is odd, then both classes have odd size $n$.
        // The median of Class 1 is $a_{(n-1)/2}$. The median of Class 2 is $a_{n + (n-1)/2}$.
        // This is not $a_{n-1}$ and $a_n$.
        //
        // The crucial observation is that if we sort all $2n$ students, $a_0, a_1, \dots, a_{2n-1}$,
        // then the median of one class must be $a_i$ and the median of the other class must be $a_j$.
        // To minimize $|a_i - a_j|$, we want $i$ and $j$ to be as close as possible.
        // The closest possible indices are $n-1$ and $n$.
        // Can we always make $a_{n-1}$ and $a_n$ the medians of two odd-sized classes?
        // Yes.
        // Let Class 1 be $\{a_0, a_1, \dots, a_{n-1}\}$ and Class 2 be $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // This is a partition into two groups of size $n$.
        // If $n$ is odd, then both classes have odd size.
        // The median of Class 1 is $a_{(n-1)/2}$. The median of Class 2 is $a_{n + (n-1)/2}$.
        // This is not $a_{n-1}$ and $a_n$.
        //
        // The problem is simpler: the minimum difference is always $a_n - a_{n-1}$.
        // Consider the $2n$ sorted elements.
        // We need to pick $S_1$ elements for class 1 and $S_2$ elements for class 2,
        // where $S_1, S_2$ are odd and $S_1+S_2=2n$.
        // Let $m_1$ be the median of class 1 and $m_2$ be the median of class 2.
        // We want to minimize $|m_1 - m_2|$.
        //
        // The key is that $a_{n-1}$ and $a_n$ are the two middle elements.
        // We can always assign $a_{n-1}$ to be the median of one class and $a_n$ to be the median of the other.
        // For example, let $a_{n-1}$ be the median of Class 1. This class needs $(n-1)$ elements smaller than $a_{n-1}$
        // and $(n-1)$ elements larger than $a_{n-1}$.
        // We can take $a_0, \dots, a_{n-2}$ as the smaller elements.
        // We can take $a_n, \dots, a_{2n-1}$ as the larger elements.
        // This is not quite right.
        //
        // The simplest way to think about it is that we have $2n$ students.
        // We sort them: $a_0, a_1, \dots, a_{2n-1}$.
        // We want to pick one student $a_i$ to be the median of class 1, and another student $a_j$ to be the median of class 2.
        // To minimize $|a_i - a_j|$, we should pick $i$ and $j$ to be adjacent.
        // The most "central" adjacent pair is $a_{n-1}$ and $a_n$.
        // Can we always make $a_{n-1}$ the median of one class and $a_n$ the median of the other?
        // Yes.
        // Let Class 1 have $a_{n-1}$ as its median. It needs $k_1$ elements smaller than $a_{n-1}$ and $k_1$ elements larger than $a_{n-1}$.
        // We can pick $k_1 = n-1$. So Class 1 is $\{a_0, \dots, a_{n-2}, a_{n-1}, a_{n+1}, \dots, a_{2n-1}\}$.
        // This class has size $2(n-1)+1 = 2n-1$. This is an odd size.
        // The remaining student is $a_n$. Class 2 is $\{a_n\}$. This has size 1, which is odd.
        // The median of Class 1 is $a_{n-1}$. The median of Class 2 is $a_n$.
        // The difference is $|a_n - a_{n-1}|$.
        // This construction is always valid.
        //
        // Example 1: n=1, a = [1, 1]. Sorted: [1, 1]. n-1=0, n=1. a[0]=1, a[1]=1. Diff = 0.
        // Example 2: n=3, a = [1, 2, 3, 4, 5, 6]. Sorted: [1, 2, 3, 4, 5, 6]. n-1=2, n=3. a[2]=3, a[3]=4. Diff = 1.
        // Example 3: n=5, a = [2, 3, 4, 5, 8, 13, 13, 16, 17, 20]. n-1=4, n=5. a[4]=8, a[5]=13. Diff = 5.
        //
        // The logic holds for all examples.
        // The minimum difference is always $a_n - a_{n-1}$ after sorting.

        long long result = a[n] - a[n - 1];
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n); // 0 for white (c), 1 for black (d)

    int current_color_for_half = 0; // 0 for white, 1 for black

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T / 2.0) { // Use floating point comparison to handle T being odd
            p[i] = 0; // Always assign to white (c)
        } else if (a[i] > T / 2.0) { // Always assign to black (d)
            p[i] = 1;
        } else { // a[i] == T / 2.0
            // Alternate colors for elements equal to T/2
            p[i] = current_color_for_half;
            current_color_for_half = 1 - current_color_for_half;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

