int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 1; // Cost for a 1-stair staircase
        long long k = 1;            // Represents the number of stairs in the current staircase (1, 3, 7, 15, ...)
                                    // k = 2^p - 1 for p = 1, 2, 3, ...
        while (x >= current_cost) {
            x -= current_cost;
            count++;
            k = k * 2 + 1; // Next number of stairs: 1 -> 3 -> 7 -> 15 -> ...
            // Cost for a staircase with k stairs is k * (k + 1) / 2
            // current_cost = k * (k + 1) / 2
            // This can be rewritten as:
            // current_cost = (2^p - 1) * (2^p) / 2
            // current_cost = (2^p - 1) * 2^(p-1)
            // The next cost will be for k' = 2^(p+1) - 1
            // next_cost = (2^(p+1) - 1) * 2^p
            // Notice that next_cost = (2k + 1) * (k+1) / 2
            // Or, more simply, the cost for k stairs is k * (k+1) / 2.
            // The sequence of k values is 1, 3, 7, 15, ...
            // The sequence of costs is 1*(1+1)/2 = 1
            // 3*(3+1)/2 = 6
            // 7*(7+1)/2 = 28
            // 15*(15+1)/2 = 120
            // The next cost is calculated based on the new k.
            // The formula for the cost of a nice staircase with k stairs is k * (k + 1) / 2.
            // Since k is always odd (1, 3, 7, ...), k+1 is always even.
            // So (k+1)/2 is an integer.
            // current_cost = k * ((k + 1) / 2);
            // This is equivalent to current_cost = k * (k+1)/2.
            // The previous current_cost was for k_old.
            // The new k is k_new = 2 * k_old + 1.
            // The new current_cost is k_new * (k_new + 1) / 2.
            // This is (2*k_old + 1) * (2*k_old + 2) / 2
            // = (2*k_old + 1) * (k_old + 1)
            // This is the correct recurrence for the cost.
            current_cost = k * (k + 1) / 2;
        }
        std::cout << count << "\n";
    }
    return 0;
}

