int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by three factors:
        // 1. The number of coders available (each team needs at least one coder).
        // 2. The number of mathematicians available (each team needs at least one mathematician).
        // 3. The total number of students available (each team needs three students).
        // So, the number of teams 'k' must satisfy:
        // k <= c
        // k <= m
        // 3 * k <= c + m + x
        // From the first two, k <= min(c, m).
        // From the third, k <= (c + m + x) / 3.
        // Therefore, k <= min(c, m, (c + m + x) / 3).
        // This is a necessary condition. Let's check if it's sufficient.

        // Let's assume we want to form 'k' teams.
        // We need 'k' coders and 'k' mathematicians.
        // The remaining 'k' spots (3 members per team - 1 coder - 1 mathematician = 1 remaining spot per team)
        // can be filled by any student: remaining coders, remaining mathematicians, or non-specialized students.
        // The total number of students available for these 'k' remaining spots is:
        // (c - k) + (m - k) + x
        // This sum must be at least 'k'.
        // (c - k) + (m - k) + x >= k
        // c + m + x - 2k >= k
        // c + m + x >= 3k
        // k <= (c + m + x) / 3

        // So, the maximum number of teams 'k' is indeed limited by:
        // k <= c
        // k <= m
        // k <= (c + m + x) / 3
        // The maximum 'k' is the minimum of these three values.

        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

