int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number used to generate k distinct differences (1 to k)

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between the smallest available and largest available numbers
    // from the range [1, k+1].
    // For example, if k=2, range is [1, 3].
    // p_1 = 1, p_2 = 3, p_3 = 2.
    // Differences: |1-3|=2, |3-2|=1. Distinct: {1,2}.
    // If k=3, range is [1, 4].
    // p_1 = 1, p_2 = 4, p_3 = 2, p_4 = 3.
    // Differences: |1-4|=3, |4-2|=2, |2-3|=1. Distinct: {1,2,3}.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index, take from left (smallest available)
            p[i] = left;
            left++;
        } else { // Odd index, take from right (largest available)
            p[i] = right;
            right--;
        }
    }

    // Fill the remaining n - (k+1) elements with the remaining numbers in increasing order.
    // These numbers are k+2, k+3, ..., n.
    // Since the previous elements used numbers from 1 to k+1, the next available number is left (which is k+2)
    // or right (which is k+1 if k is odd, or k+2 if k is even).
    // In the loop above, 'left' increments from 1 and 'right' decrements from k+1.
    // After the loop, 'left' will be (k+1)/2 + 1 if k is odd, or k/2 + 1 if k is even.
    // 'right' will be k+1 - (k+1)/2 if k is odd, or k+1 - k/2 if k is even.
    // The numbers not used are those between 'left' and 'right' (inclusive) if left <= right.
    // However, a simpler way to think about it is that all numbers from 1 to k+1 have been used.
    // The next available number is k+2.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // Fill with k+2, k+3, ..., n
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

