    // Or, if we have toys with magnitude >= 1 (from A or D), we can multiply them together first
    // to reduce the total number of toys, and then eventually multiply with a toy from B or C.
    // As long as B > 0 or C > 0, we can always ensure the final product has magnitude < 1.
    // The only way to guarantee magnitude >= 1 is if all initial toys have magnitude >= 1 (B=0, C=0).

    // If A + B is odd (final product is negative):
    if ((A + B) % 2 != 0) {
        // If B > 0 or C > 0, we have at least one toy with magnitude < 1.
        // We can always ensure the final product has magnitude < 1.
        // Example: -0.5 (Box 2) * 0.5 (Box 3) = -0.25 (Box 2).
        // Example: -0.5 (Box 2) * 2 (Box 4) = -1 (Box 1). This is a problem.
        // We need to ensure we can *force* the magnitude to be < 1.
        // This is possible if we have at least one toy in Box 2 or Box 3 (B > 0 or C > 0).
        // If B > 0 or C > 0, we can always pick a toy with magnitude < 1.
        // We can then multiply it with other toys with magnitude < 1 (from B or C) to keep it small.
        // If we run out of Box 2/3 toys, we might be forced to multiply with Box 1/4 toys.
        // But we can always choose to multiply Box 1/4 toys among themselves first.
        // As long as there is at least one toy with magnitude < 1 (B > 0 or C > 0),
        // and we have at least one other toy to multiply with (A+B+C+D > 1),
        // we can potentially end up with magnitude < 1.

        // The only way to guarantee magnitude >= 1 is if all initial toys have magnitude >= 1 (B=0, C=0).
        // If B=0 and C=0, then all toys are in (-inf, -1] or [1, inf). Their product will always be in (-inf, -1] or [1, inf).
        // So, if B=0 and C=0, Box 2 is impossible.
        if (B == 0 && C == 0) {
            return false;
        }
        // Otherwise, if A+B is odd and (B > 0 or C > 0), it's possible.
        return true;
    }
    // If A + B is even, the final product will be positive. So Box 2 is impossible.
    return false;
}

// Function to determine if Box 3 can be the special box
bool can_be_box3(long long A, long long B, long long C, long long D) {
    // Box 3: (0, 1)
    // Requires a positive final product with magnitude < 1.

    // Case 1: Final product is positive.
    // (A + B) must be even.

    // Case 2: Final product has magnitude < 1.
    // This means we must be able to make the magnitude small.
    // This is possible if B > 0 or C > 0.
    // If B=0 and C=0, then all toys are in (-inf, -1] or [1, inf). Their product will always be in (-inf, -1] or [1, inf).
    // So, if B=0 and C=0, Box 3 is impossible.

    // If A + B is even (final product is positive):
    if ((A + B) % 2 == 0) {
        // If B > 0 or C > 0, we have at least one toy with magnitude < 1.
        // We can always ensure the final product has magnitude < 1.
        if (B == 0 && C == 0) {
            return false;
        }
        // Otherwise, if A+B is even and (B > 0 or C > 0), it's possible.
        return true;
    }
    // If A + B is odd, the final product will be negative. So Box 3 is impossible.
    return false;
}

// Function to determine if Box 4 can be the special box
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // Box 4: [1, inf)
    // Requires a positive final product with magnitude >= 1.

    // Case 1: Final product is positive.
    // (A + B) must be even.

    // Case 2: Final product has magnitude >= 1.
    // This means we must be able to make the magnitude large.
    // This is possible if A > 0 or D > 0.
    // If A=0 and D=0, then all toys are in (-1, 1). Their product will always be in (-1, 1).
    // So, if A=0 and D=0, Box 4 is impossible.

    // If A + B is even (final product is positive):
    if ((A + B) % 2 == 0) {
        // If A > 0 or D > 0, we have at least one toy with magnitude >= 1.
        // We can always ensure the final product has magnitude >= 1.
        if (A == 0 && D == 0) {
            return false;
        }
        // Otherwise, if A+B is even and (A > 0 or D > 0), it's possible.
        return true;
    }
    // If A + B is odd, the final product will be negative. So Box 4 is impossible.
    return false;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        // Special case: Only one toy initially.
        // The super toy is that single toy.
        if (A + B + C + D == 1) {
            std::cout << (A == 1 ? "Ya" : "Tidak") << " ";
            std::cout << (B == 1 ? "Ya" : "Tidak") << " ";
            std::cout << (C == 1 ? "Ya" : "Tidak") << " ";
            std::cout << (D == 1 ? "Ya" : "Tidak") << "\n";
            continue;
        }

        // For multiple toys, apply the logic.
        std::cout << (can_be_box1(A, B, C, D) ? "Ya" : "Tidak") << " ";
        std::cout << (can_be_box2(A, B, C, D) ? "Ya" : "Tidak") << " ";
        std::cout << (can_be_box3(A, B, C, D) ? "Ya" : "Tidak") << " ";
        std::cout << (can_be_box4(A, B, C, D) ? "Ya" : "Tidak") << "\n";
    }
