        int max_gap = 0;
        int last_R_pos = 0; // Represents the position of the last 'R' or the starting point (cell 0)
                            // If last_R_pos is 0, it means the frog is at cell 0.
                            // If last_R_pos is i, it means the frog is at cell i and s[i-1] is 'R'.
                            // We are interested in the distance from the current position to the next 'R' or the end.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // If s[i] is 'R', the frog can jump from last_R_pos to i+1.
                // The distance needed for this jump is (i+1) - last_R_pos.
                // We need to find the maximum such distance.
                max_gap = std::max(max_gap, (i + 1) - last_R_pos);
                last_R_pos = i + 1; // Update last_R_pos to the current 'R' cell (i+1)
            }
        }

        // After iterating through the string, we need to consider the jump from the last 'R'
        // (or cell 0 if no 'R's) to the target cell n+1.
        max_gap = std::max(max_gap, (n + 1) - last_R_pos);

        std::cout << max_gap << "\n";
    }
