int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long k_max = n / m;

        if (k_max == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        std::vector<int> cycle_last_digits;
        long long current_sum = 0;
        std::vector<bool> seen_last_digits(10, false); // To detect cycle start

        for (int i = 1; i <= 10; ++i) { // A cycle of last digits of (i*m)%10 is at most length 10
            int last_digit = (static_cast<long long>(i) * m) % 10;
            cycle_last_digits.push_back(last_digit);
            current_sum += last_digit;
            // The cycle length is at most 10 because (i*m)%10 depends only on (i%10) and (m%10).
            // Specifically, (i*m)%10 is ( (i%10) * (m%10) ) % 10.
            // So the sequence of last digits repeats every 10 terms.
            // We can just precompute 10 terms and sum them.
        }

        // The cycle length is effectively 10 for (i*m)%10.
        // The sum of last digits for i=1 to 10 is `current_sum`.
        // The number of full cycles of 10 terms is `k_max / 10`.
        // The remaining terms are `k_max % 10`.

        long long num_full_cycles = k_max / 10;
        long long remaining_terms = k_max % 10;

        long long total_sum = num_full_cycles * current_sum;

        for (int i = 0; i < remaining_terms; ++i) {
            total_sum += cycle_last_digits[i];
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a subarray is a permutation of its length
bool is_permutation(const std::vector<int>& arr, int start_idx, int end_idx, int expected_len) {
    if (expected_len <= 0) { // A permutation must have positive length
        return false;
    }
    if (end_idx - start_idx + 1 != expected_len) { // Length mismatch
        return false;
    }

    std::vector<bool> seen(expected_len + 1, false);
    for (int i = start_idx; i <= end_idx; ++i) {
        if (arr[i] < 1 || arr[i] > expected_len || seen[arr[i]]) {
            return false;
        }
        seen[arr[i]] = true;
    }
    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    int max_val = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] > max_val) {
            max_val = a[i];
        }
    }

    // Precompute prefix permutation checks
    // prefix_is_perm[i] is true if a[0...i-1] is a permutation of length i
    std::vector<bool> prefix_is_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max_prefix = 0;
    bool possible_prefix = true;
    for (int i = 0; i < n; ++i) {
        if (!possible_prefix) {
            break;
        }
        if (a[i] < 1 || a[i] > i + 1 || seen_prefix[a[i]]) {
            possible_prefix = false;
        } else {
            seen_prefix[a[i]] = true;
            if (a[i] > current_max_prefix) {
                current_max_prefix = a[i];
            }
            if (current_max_prefix == i + 1) { // All numbers from 1 to i+1 seen
                prefix_is_perm[i + 1] = true;
            }
        }
    }

    // Precompute suffix permutation checks
    // suffix_is_perm[i] is true if a[i...n-1] is a permutation of length n-i
    std::vector<bool> suffix_is_perm(n + 1, false); // suffix_is_perm[i] for suffix starting at index i
    std::vector<bool> seen_suffix(n + 1, false);
    int current_max_suffix = 0;
    bool possible_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        if (!possible_suffix) {
            break;
        }
        int len_suffix = n - i;
        if (a[i] < 1 || a[i] > len_suffix || seen_suffix[a[i]]) {
            possible_suffix = false;
        } else {
            seen_suffix[a[i]] = true;
            if (a[i] > current_max_suffix) {
                current_max_suffix = a[i];
            }
            if (current_max_suffix == len_suffix) { // All numbers from 1 to len_suffix seen
                suffix_is_perm[i] = true;
            }
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (prefix_is_perm[l1] && suffix_is_perm[l1]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

