            counts[c]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Iterate through R, S, P in a fixed order to ensure deterministic output
        // if counts are equal. The problem statement allows any optimal answer.
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
