#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    std::vector<bool> in_password(26, false);

    for (size_t i = 0; i < s.length(); ++i) {
        in_password[s[i] - 'a'] = true;
        if (i + 1 < s.length()) {
            adj[s[i] - 'a'].insert(s[i+1]);
            adj[s[i+1] - 'a'].insert(s[i]);
        }
    }

    for (int i = 0; i < 26; ++i) {
        if (adj[i].size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    // Find a starting point for a path
    // A starting point must be a character that is in the password
    // and has only one required neighbor (an endpoint of a path segment).
    // Or, if the password is just one character, that character itself.
    char start_char = 0;
    bool found_start = false;

    if (s.length() == 1) {
        start_char = s[0];
        found_start = true;
    } else {
        for (int i = 0; i < 26; ++i) {
            if (in_password[i] && adj[i].size() == 1) {
                start_char = (char)('a' + i);
                found_start = true;
                break;
            }
        }
    }

    // If no such start_char is found, it means all characters in the password
    // have 2 required neighbors (forming a cycle or a single long path where
    // we haven't found an endpoint yet).
    // Or, it means the password is empty (not possible by constraints)
    // or all characters in password have 0 neighbors (password length 1, handled above).
    // If all characters in password have 2 neighbors, it means they form a cycle.
    // A cycle is not possible on a single-row keyboard (which is a path).
    // However, if the password itself forms a path, and we pick any character
    // from the password, we can start building the layout from there.
    // The only case where `found_start` might be false is if `s` is empty,
    // or if all characters in `s` have degree 2 in the adjacency graph.
    // If all characters in `s` have degree 2, it means they form a cycle.
    // A cycle is not allowed.
    // Example: "abacaba" -> a-b, a-c. 'b' has 1 neighbor 'a'. 'c' has 1 neighbor 'a'.
    // So 'b' or 'c' would be a start.
    // Example: "abcde" -> 'a' has 1, 'e' has 1.
    // Example: "abac" -> 'b' has 1, 'c' has 1.
    // The only way `found_start` is false is if the graph formed by `s` is not a path.
    // If it's a path, it must have two endpoints with degree 1.
    // If it's a cycle, all nodes have degree 2. This is impossible for a linear keyboard.
    // So, if `found_start` is false here, it implies an impossible layout.
    // However, the problem statement guarantees no adjacent equal characters.
    // This implies that the graph formed by the password characters must be a path or a collection of paths.
    // If it's a path, it must have endpoints.
    // The only case where `found_start` could be false is if the password characters form a cycle.
    // For example, if s = "abac", a-b, b-a, a-c, c-a.
    // adj['a'] = {'b', 'c'} (size 2)
    // adj['b'] = {'a'} (size 1)
    // adj['c'] = {'a'} (size 1)
    // Here, 'b' or 'c' would be a start.
    // What if s = "abacaba"?
    // adj['a'] = {'b', 'c'} (size 2)
    // adj['b'] = {'a'} (size 1)
    // adj['c'] = {'a'} (size 1)
    // 'b' or 'c' would be a start.
    // The only way `found_start` is false is if all characters in `s` have degree 2.
    // This would mean the password forms a cycle, e.g., "abcad".
    // a-b, b-c, c-a, a-d.
    // adj['a'] = {'b', 'c', 'd'} (size 3) -> already caught by adj[i].size() > 2 check.
    // So, if we reach here, `found_start` must be true, unless `s` is empty (not possible).
    // If `s` is not empty, and all `adj[i].size() <= 2`, then there must be at least one character with `adj[i].size() <= 1`.
    // If `s.length() == 1`, `s[0]` has `adj[s[0]-'a'].size() == 0`.
    // If `s.length() > 1`, there must be at least two characters with `adj[i].size() == 1` (endpoints of the path).
    // So `found_start` will always be true if `s` is not empty.

    char current_char = start_char;
    if (found_start) {
        while (current_char != 0 && !visited[current_char - 'a']) {
            layout += current_char;
            visited[current_char - 'a'] = true;

            char next_char = 0;
            for (char neighbor : adj[current_char - 'a']) {
                if (!visited[neighbor - 'a']) {
                    next_char = neighbor;
                    break;
                }
            }
            current_char = next_char;
        }
    }

    // Check if all characters from the password are included in the layout
    for (int i = 0; i < 26; ++i) {
        if (in_password[i] && !visited[i]) {
            // This means there's a disconnected component or a cycle
            // that couldn't be traversed from the chosen start_char.
            // This implies an impossible layout.
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining characters not in the password
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

