    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_prob = 0.0;

    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char first_char = s[k_actual];

        std::vector<int> possible_k_values = char_indices[first_char - 'a'];

        if (possible_k_values.size() == 1) {
            total_prob += 1.0;
            continue;
        }

        double max_win_prob_for_k_actual = 0.0;

        for (int p = 1; p < L; ++p) {
            std::map<char, std::vector<int>> groups_by_second_char;
            for (int k_cand : possible_k_values) {
                char second_char = s[(k_cand + p) % L];
                groups_by_second_char[second_char].push_back(k_cand);
            }

            double current_p_win_prob = 0.0;
            for (auto const& [char_val, group] : groups_by_second_char) {
                if (group.size() == 1) {
                    current_p_win_prob += 1.0;
                }
            }
            max_win_prob_for_k_actual = std::max(max_win_prob_for_k_actual, current_p_win_prob);
        }
        total_prob += max_win_prob_for_k_actual / possible_k_values.size();
    }

    std::cout << std::fixed << std::setprecision(15) << total_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Precompute prefix sums for 'x', 'y', 'z'
    // count[0][i] stores count of 'x' in s[0...i-1]
    // count[1][i] stores count of 'y' in s[0...i-1]
    // count[2][i] stores count of 'z' in s[0...i-1]
    std::vector<std::vector<int>> count(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        count[0][i + 1] = count[0][i];
        count[1][i + 1] = count[1][i];
        count[2][i + 1] = count[2][i];
        if (s[i] == 'x') {
            count[0][i + 1]++;
        } else if (s[i] == 'y') {
            count[1][i + 1]++;
        } else { // s[i] == 'z'
            count[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r; // 1-indexed

        int len = r - l + 1;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        // Get counts of 'x', 'y', 'z' in the substring s[l-1...r-1]
        int count_x = count[0][r] - count[0][l - 1];
        int count_y = count[1][r] - count[1][l - 1];
        int count_z = count[2][r] - count[2][l - 1];

        // Check if the counts are "balanced" enough
        // The difference between max and min count must be at most 1
        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; ++i) {
        int block_start = std::max(1, current_val - k + 1);
        for (int j = 0; j < k && current_val >= 1; ++j) {
            p[i + j] = current_val;
            current_val--;
        }
        i += (k - 1); // Advance index by k-1 since k elements were placed
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

