// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// The sum can exceed 2^31-1.

// Memoization table for results:
// dp_x[i] stores the final x value if starting at (i, 0) and taking the first step (x+a[x], y+a[x])
// dp_y[i] stores the final y value if starting at (i, 0) and taking the first step (x+a[x], y+a[x])
// dp_x[i] = 0 means it terminates at x <= 0
// dp_x[i] = n+1 means it terminates at x > n
// dp_x[i] = -1 means it's part of an infinite loop
std::vector<long long> dp_x;
std::vector<long long> dp_y;
std::vector<bool> visited; // To detect cycles

int N;
std::vector<long long> A_vals; // a_2, ..., a_n. A_vals[0] corresponds to a_2, A_vals[N-2] to a_N.

// Function to get a[idx] where idx is 1-based.
// For idx=1, it's the current_a1_val.
// For idx > 1, it's A_vals[idx-2].
long long get_a_val(int idx, long long current_a1_val) {
    if (idx == 1) {
        return current_a1_val;
    }
    return A_vals[idx - 2];
}

// Recursive function to calculate the final (x, y) state starting from (start_x, start_y)
// after the first step (x+a[x], y+a[x]).
// This function is called for the state *after* the first 'add' operation.
// The 'current_a1_val' is the value of a[1] for the current run.
void solve(int start_x, long long current_a1_val) {
    if (start_x <= 0 || start_x > N) {
        // Already terminated. This should not happen if called correctly.
        // But as a safeguard, mark as terminated.
        dp_x[start_x] = start_x; // Use start_x to indicate termination type
        dp_y[start_x] = 0; // y doesn't matter here
        return;
    }

    if (visited[start_x]) {
        // Cycle detected. Mark as infinite loop.
        dp_x[start_x] = -1;
        dp_y[start_x] = -1;
        return;
    }
    if (dp_x[start_x] != 0) { // Already computed (and not 0, which is initial value)
        return;
    }

    visited[start_x] = true;

    long long val_at_start_x = get_a_val(start_x, current_a1_val);

    // Step 3: x = x - a[x], y = y + a[x]
    int next_x = start_x - val_at_start_x;
    long long current_y_contribution = val_at_start_x;

    if (next_x <= 0 || next_x > N) {
        // Terminates after step 3
        dp_x[start_x] = next_x;
        dp_y[start_x] = current_y_contribution;
    } else {
        // Continue to next pair of steps (step 2, then step 3)
        // The next state is (next_x, 0) for the purpose of memoization,
        // but the y value accumulates.

        // Step 2: x = x + a[x], y = y + a[x]
        long long val_at_next_x = get_a_val(next_x, current_a1_val);
        int next_next_x = next_x + val_at_next_x;
        long long next_y_contribution = val_at_next_x;

        if (next_next_x <= 0 || next_next_x > N) {
            // Terminates after step 2
            dp_x[start_x] = next_next_x;
            dp_y[start_x] = current_y_contribution + next_y_contribution;
        } else {
            // Recursively call for the state after the 'add' operation
            solve(next_next_x, current_a1_val);

            if (dp_x[next_next_x] == -1) { // Infinite loop
                dp_x[start_x] = -1;
                dp_y[start_x] = -1;
            } else {
                dp_x[start_x] = dp_x[next_next_x];
                dp_y[start_x] = current_y_contribution + next_y_contribution + dp_y[next_next_x];
            }
        }
    }

    visited[start_x] = false; // Backtrack for visited array
}


