            current_delta[j] += running_sum_delta_diff;
        }
        std::fill(delta_diff.begin(), delta_diff.end(), 0); // Reset delta_diff for next iteration

        if (ops[i].type == 1) {
            // This is a type 1 operation (l, r, d).
            // When processing in reverse, this operation *adds* d to a[l...r].
            // So, to find the initial value, we need to subtract d from the current value.
            // This means future operations (which we already processed) effectively
            // saw a value that was d higher than it would be without this operation.
            // So, for operations *before* this one, the effective delta is d less.
            delta_diff[ops[i].l] -= ops[i].val;
            if (ops[i].r + 1 < n) {
                delta_diff[ops[i].r + 1] += ops[i].val;
            }
        } else { // ops[i].type == 2
            // This is a type 2 operation (l, r, m).
            // The maximum in a[l...r] *at this point in time* must be m.
            // The value of a[j] at this point is initial_a[j] + (sum of d's up to this point).
            // We are working with initial_a[j] + current_delta[j] (current_delta accounts for future d's).
            // So, the value of initial_a[j] must be <= m - current_delta[j].
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // Fill in initial_a values that were not constrained by type 2 operations
    // These can be any value, but we need to ensure |a_i| <= 10^9.
    // Since we are looking for *any* suitable array, 0 is a good default.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == LLONG_MAX) {
            initial_a[i] = 0;
        }
    }

    // Verify the reconstructed initial_a
    // Simulate all operations with the proposed initial_a
    std::vector<long long> a = initial_a;
    std::vector<long long> prefix_sum_d(n + 1, 0); // For efficient range updates

    for (const auto& op : ops) {
        if (op.type == 1) {
            prefix_sum_d[op.l] += op.val;
            if (op.r + 1 < n) {
                prefix_sum_d[op.r + 1] -= op.val;
            }
        } else { // op.type == 2
            long long current_max = LLONG_MIN;
            long long current_d_val = 0;
            for (int j = 0; j < n; ++j) {
                current_d_val += prefix_sum_d[j];
                if (j >= op.l && j <= op.r) {
                    current_max = std::max(current_max, a[j] + current_d_val);
                }
            }
            if (current_max != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraint for initial_a
    for (int i = 0; i < n; ++i) {
        if (std::abs(initial_a[i]) > 1000000000LL) {
            // This case should ideally not happen if the problem guarantees a solution
            // within |a_i| <= 10^9, but it's good to check.
            // If initial_a[i] is LLONG_MAX, it means it was never constrained.
            // We set it to 0, which satisfies the constraint.
            // If it was constrained to a value > 10^9 or < -10^9, then no solution exists.
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a, b;
    std::cin >> a >> b;

    int ones_a = 0;
    for (char c : a) {
        if (c == '1') {
            ones_a++;
        }
    }

    int ones_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_b++;
        }
    }

    // If ones_a is odd, we can add a '1' to the string.
    // If ones_a is even, we can add a '0' to the string.
    // So, if ones_a is odd, we can effectively increase the count of '1's by 1.
    // If ones_a is even, the count of '1's remains the same.
    // This means we can always reach a state where the number of '1's is ones_a or ones_a + 1
    // (if ones_a was odd).
    // The maximum number of '1's we can achieve in any prefix of length |b|
    // is ones_a if ones_a is even, or ones_a + 1 if ones_a is odd.
    // This is equivalent to (ones_a + (ones_a % 2)).

    int max_ones_possible_in_a_prefix = ones_a + (ones_a % 2);

    if (max_ones_possible_in_a_prefix >= ones_b) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line; // To mark if child has left

    Child(long long v_val, long long d_val, long long p_val, int idx)
        : v(v_val), d(d_val), p(p_val), original_idx(idx), in_line(true) {}
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children;
    children.reserve(n);
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children.emplace_back(v_val, d_val, p_val, i + 1);
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue; // This child has already left
        }

        cured_children_indices.push_back(children[i].original_idx);

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_leaving = 0; // Accumulates d_j from children leaving due to chain reaction

        // Apply v_i effect and initial chain reaction
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_cry from previous children leaving
            children[j].p -= total_d_cry_from_leaving;

            // Apply current_v_cry effect
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_cry_from_leaving += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_val = 0; // The previous element in the modified array, initialized to 0.
                            // This is because the first element can be 0.

    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];

        // We want to find a new value for a[i], say new_a_i, such that:
        // 1. new_a_i >= prev_val
        // 2. new_a_i = (current_a + k) % m for some k <= x
        // 3. We want to minimize new_a_i to make it easier for subsequent elements.

        // Case 1: current_a is already >= prev_val.
        // We can potentially keep current_a as is (k=0 operations on this element).
        // If current_a >= prev_val, then (current_a + k) % m can be current_a itself (k=0).
        // This requires 0 operations on a[i], which is <= x.
        // So, if current_a >= prev_val, we can set new_a_i = current_a.
        // This is the smallest possible value for new_a_i that satisfies new_a_i >= prev_val
        // and uses 0 operations (which is <= x).
        if (current_a >= prev_val) {
            // If current_a + x < m and current_a + x < prev_val, it means
            // even with x operations, we cannot reach prev_val.
            // This condition is equivalent to:
            // (current_a + x) % m < prev_val AND (current_a + x) % m is achieved by adding x.
            // This happens if current_a + x does not wrap around m, i.e., current_a + x < m.
            // In this specific case, if current_a + x < prev_val, we must increment current_a
            // to at least prev_val. But we can only increment by at most x.
            // So if current_a + x < prev_val, it's impossible.
            //
            // More precisely:
            // We need new_a_i >= prev_val.
            // The smallest value we can achieve for new_a_i is current_a (by adding 0).
            // The largest value we can achieve for new_a_i without wrapping around m is current_a + x.
            // If current_a + x < m:
            //   If current_a + x < prev_val, then we cannot make a[i] >= prev_val.
            //   Otherwise, we can make a[i] = prev_val (if prev_val >= current_a) or a[i] = current_a (if prev_val < current_a).
            //   Since we are in the branch current_a >= prev_val, we can just use current_a.
            //   The only issue is if current_a + x < m and current_a + x < prev_val.
            //   But this contradicts current_a >= prev_val.
            //   So if current_a >= prev_val, we can always set new_a_i = current_a.
            //   The only time we *must* increment is if current_a + x < m and current_a + x < prev_val,
            //   but this is not possible if current_a >= prev_val.
            //
            // Let's re-evaluate:
            // We need to find k such that 0 <= k <= x and (current_a + k) % m >= prev_val.
            // We want to pick the smallest such (current_a + k) % m.
            //
            // Option A: Don't wrap around m.
            // We can achieve values from current_a to current_a + x (if current_a + x < m).
            // If current_a >= prev_val, we can pick current_a. This is valid (k=0 <= x).
            // So, if current_a >= prev_val, we can set new_a_i = current_a.
            //
            // Option B: Wrap around m.
            // We can achieve values from 0 up to (current_a + x) % m.
            // This requires k operations, where k is (m - current_a + val) % m.
            // If we choose to wrap around, the smallest value we can achieve is 0.
            // This requires k = (m - current_a) % m operations.
            // If (m - current_a) % m <= x, then we can achieve 0.
            //
            // Combining these:
            // If current_a >= prev_val:
            //   We can potentially keep current_a. This requires 0 operations.
            //   If we keep current_a, then new_a_i = current_a.
            //   Is it possible that we *must* increment current_a to satisfy the condition?
            //   No, because current_a >= prev_val already.
            //   So, if current_a >= prev_val, we can set new_a_i = current_a.
            //   This is the smallest possible value for new_a_i that satisfies new_a_i >= prev_val
            //   and uses 0 operations (which is <= x).
            //   However, we must also consider if incrementing current_a by some k <= x
            //   could result in a value (current_a + k) % m that is smaller than current_a
            //   but still >= prev_val. This only happens if current_a + k wraps around m.
            //   Example: m=10, prev_val=8, current_a=9, x=1.
            //   current_a >= prev_val. If we set new_a_i = current_a = 9, it's valid.
            //   But if we increment current_a by 1, (9+1)%10 = 0. This is not >= prev_val.
            //   So, if current_a >= prev_val, we can always choose new_a_i = current_a.
            //   This is the best choice for new_a_i in this scenario.
            //
            //   The only exception is if current_a + x < m AND current_a + x < prev_val.
            //   This means even with x operations, we cannot reach prev_val without wrapping.
            //   But this contradicts current_a >= prev_val.
            //   So, if current_a >= prev_val, we can always set new_a_i = current_a.
            //   This is the smallest possible value for new_a_i that satisfies new_a_i >= prev_val
            //   and uses 0 operations (which is <= x).
            //   The only time we *must* increment is if current_a + x < m and current_a + x < prev_val,
            //   but this is not possible if current_a >= prev_val.
            //
            //   Let's simplify:
            //   If current_a >= prev_val:
            //     We can choose to not increment a[i] (k=0). Then new_a_i = current_a. This is valid.
            //     Can we choose to increment a[i] by some k <= x such that (current_a + k) % m is smaller than current_a
            //     but still >= prev_val?
            //     This would mean (current_a + k) % m wraps around.
            //     If (current_a + x) % m < prev_val, then we cannot make it >= prev_val by wrapping.
            //     If (current_a + x) % m >= prev_val, then we can make it (current_a + x) % m.
            //     But this value might be larger than current_a.
            //     The smallest value we can achieve by wrapping is 0. This requires (m - current_a) % m operations.
            //     If (m - current_a) % m <= x, we can achieve 0.
            //     If 0 >= prev_val, then we can set new_a_i = 0.
            //     This is only possible if prev_val is 0.
            //
            //     So, if current_a >= prev_val:
            //       We can always choose new_a_i = current_a (k=0).
            //       We can also choose new_a_i = 0 if (m - current_a) % m <= x and prev_val == 0.
            //       In this case, we prefer 0 if prev_val == 0.
            //       Otherwise, we prefer current_a.
            //       So, if prev_val == 0, we can set new_a_i = 0.
            //       If prev_val > 0, we must set new_a_i = current_a.
            //       This logic is flawed. We want the smallest new_a_i >= prev_val.
            //
            // Correct logic for current_a >= prev_val:
            // We need to find a `new_val` such that `new_val >= prev_val` and `new_val = (current_a + k) % m` for some `0 <= k <= x`.
            //
            // Option 1: Don't wrap around `m`.
            // We can achieve values `current_a, current_a+1, ..., current_a+x` (as long as they are `< m`).
            // Since `current_a >= prev_val`, `current_a` itself is a valid choice (with `k=0`).
            // So, we can set `new_val = current_a`. This is the smallest possible value in this option.
            //
            // Option 2: Wrap around `m`.
            // We can achieve values `0, 1, ..., (current_a + x) % m`.
            // This requires `k` operations where `k = (m - current_a + val) % m`.
            // The smallest value we can achieve by wrapping is `0`. This requires `k = (m - current_a) % m` operations.
            // If `(m - current_a) % m <= x` (i.e., we have enough operations to wrap around and reach 0),
            // and if `0 >= prev_val` (which implies `prev_val` must be 0), then we can set `new_val = 0`.
            //
            // So, if `current_a >= prev_val`:
            //   If `prev_val == 0` and `(m - current_a) % m <= x`:
            //     We can choose `new_val = 0`. This is better than `current_a` (unless `current_a` is already 0).
            //     So, `prev_val` remains `0`.
            //   Else (either `prev_val > 0` or we can't reach 0 by wrapping with `x` operations):
            //     We must choose `new_val = current_a`.
            //     So, `prev_val` becomes `current_a`.
            //
            // This simplifies to:
            // If `current_a >= prev_val`:
            //   If `current_a + x < m` (no wrap possible with x operations) OR `(current_a + x) % m >= prev_val` (even if wrapped, it's still >= prev_val):
            //     We can keep `prev_val` as `prev_val`.
            //   Else (`current_a + x >= m` AND `(current_a + x) % m < prev_val`):
            //     This means we *must* increment `current_a` to `current_a + k` such that `current_a + k >= m` and `(current_a + k) % m >= prev_val`.
            //     But the smallest value we can achieve by wrapping is `0`.
            //     If `0 < prev_val`, then we cannot achieve `prev_val` by wrapping.
            //     This means it's impossible.
            //
            // Let's use the two cases for `a_i` relative to `prev_val`:
            //
            // Case 1: `a_i >= prev_val`
            // We want to keep `a_i` as small as possible, ideally `prev_val`.
            // If we don't increment `a_i` (k=0), its value is `a_i`. This is valid since `a_i >= prev_val`.
            // If we increment `a_i` by `k` operations, its value becomes `(a_i + k) % m`.
            // We can increment `a_i` by `k` operations, where `0 <= k <= x`.
            // If `a_i + x < m`:
            //   The possible values for `a_i` are `a_i, a_i+1, ..., a_i+x`.
            //   Since `a_i >= prev_val`, the smallest valid value is `a_i`.
            //   So, `prev_val` becomes `a_i`.
            // Else (`a_i + x >= m`, meaning `a_i` can wrap around):
            //   The possible values for `a_i` are `a_i, ..., m-1, 0, ..., (a_i+x)%m`.
            //   If `(a_i + x) % m < prev_val`:
            //     This means even with `x` operations, we cannot reach `prev_val` by wrapping around.
            //     Since `a_i >= prev_val`, we can choose `a_i` itself (k=0).
            //     So, `prev_val` becomes `a_i`.
            //   Else (`(a_i + x) % m >= prev_val`):
            //     This means we can reach `prev_val` by wrapping around.
            //     For example, if `a_i=6, m=7, prev_val=0, x=1`. `a_i+x = 7`. `(a_i+x)%m = 0`.
            //     Here, `a_i=6 >= prev_val=0`. We can choose `a_i=6`.
            //     But we can also choose `0` (by incrementing `a_i` by 1).
            //     We prefer `0` because it's smaller.
            //     So, `prev_val` becomes `prev_val` (which is `0`).
            //
            // Simplified logic for `a_i >= prev_val`:
            // If `(a_i + x) % m >= prev_val` (this covers cases where `a_i+x` doesn't wrap, or wraps but still lands >= `prev_val`):
            //   We can potentially make `a_i` equal to `prev_val` (if `prev_val` is reachable by incrementing `a_i` by `k <= x` and `a_i` wraps around to `prev_val`).
            //   Or we can make `a_i` equal to `a_i` (if `a_i` is already >= `prev_val`).
            //   The smallest value we can achieve that is `>= prev_val` is `prev_val` itself, if `prev_val` is reachable.
            //   `prev_val` is reachable if `(a_i + k) % m = prev_val` for some `k <= x`.
            //   This means `k = (prev_val - a_i + m) % m`. If this `k <= x`, then we can set `new_a_i = prev_val`.
            //   Otherwise, we must set `new_a_i = a_i`.
            //   So, if `(prev_val - a_i + m) % m <= x`, then `prev_val` remains `prev_val`.
            //   Else, `prev_val` becomes `a_i`.
            //
            // Case 2: `a_i < prev_val`
            // We *must* increment `a_i` to at least `prev_val`.
            // This means `a_i + k >= prev_val` or `a_i + k >= m` and `(a_i + k) % m >= prev_val`.
            // The number of operations `k` must be `<= x`.
            // If `a_i + x < prev_val`:
            //   Even with `x` operations, we cannot reach `prev_val` without wrapping.
            //   And if `a_i + x < m`, then we cannot wrap. So it's impossible.
            //   If `a_i + x >= m`:
            //     We can wrap. The values we can reach are `0, ..., (a_i + x) % m`.
            //     If `(a_i + x) % m < prev_val`:
            //       This means even with `x` operations, we cannot reach `prev_val` by wrapping.
            //       So it's impossible.
            //     Else (`(a_i + x) % m >= prev_val`):
            //       We can reach `prev_val` by wrapping.
            //       So, `prev_val` remains `prev_val`.
            //
            // Simplified logic for `a_i < prev_val`:
            // We need to find `k` such that `0 <= k <= x` and `(a_i + k) % m >= prev_val`.
            // The smallest `k` to make `a_i + k >= prev_val` (without wrapping) is `prev_val - a_i`.
            // If `prev_val - a_i <= x`:
            //   We can set `new_a_i = prev_val`. So `prev_val` remains `prev_val`.
            // Else (`prev_val - a_i > x`):
            //   We cannot reach `prev_val` without wrapping. We must wrap.
            //   This means `a_i + k >= m` for some `k <= x`.
            //   The smallest value we can achieve by wrapping is `0`.
            //   The largest value we can achieve by wrapping is `(a_i + x) % m`.
            //   If `(a_i + x) % m < prev_val`:
            //     It's impossible to make `a_i >= prev_val`. Return `false`.
            //   Else (`(a_i + x) % m >= prev_val`):
            //     We can make `a_i` equal to `prev_val` by incrementing.
            //     So, `prev_val` remains `prev_val`.
            //
            // Combining both cases:
            // If `a_i >= prev_val`:
            //   If `(prev_val - a_i + m) % m <= x`: // Can we reach prev_val by incrementing a_i?
            //     // Yes, we can make a_i = prev_val. This is the best choice.
            //     // prev_val remains prev_val.
            //     continue;
            //   Else: // Cannot reach prev_val by incrementing a_i. Must use a_i itself.
            //     prev_val = current_a;
            // Else (`a_i < prev_val`):
            //   If `(prev_val - a_i + m) % m <= x`: // Can we reach prev_val by incrementing a_i?
            //     // Yes, we can make a_i = prev_val. This is the best choice.
            //     // prev_val remains prev_val.
            //     continue;
            //   Else: // Cannot reach prev_val by incrementing a_i.
            //     // This means `prev_val - a_i > x` (without wrap) AND `(prev_val - a_i + m) % m > x` (with wrap).
            //     // This implies it's impossible to make a_i >= prev_val.
            //     return false;
            //
            // This logic seems correct and covers all sub-cases.

        if (current_a >= prev_val) {
            // Option 1: Don't increment a[i] (k=0). New value is current_a. This is >= prev_val.
            // Option 2: Increment a[i] by k operations such that (current_a + k) % m is smaller than current_a
            //           but still >= prev_val. This implies wrapping around m.
            //           The smallest value we can achieve by wrapping is 0.
            //           If we can reach 0 (i.e., (m - current_a) % m <= x) AND 0 >= prev_val (i.e., prev_val is 0),
            //           then we can set new_a_i = 0. This is better than current_a (unless current_a is 0).
            //
            // So, if prev_val is 0, and we can reach 0 from current_a with <= x operations, we can keep prev_val as 0.
            // This happens if (m - current_a) % m <= x.
            // If prev_val is 0 and (m - current_a) % m <= x, then we can set new_a_i = 0.
            // Otherwise, we must set new_a_i = current_a.
            //
            // This is equivalent to:
            // If current_a + x < m: // No wrap possible with x operations
            //   prev_val = current_a; // Must use current_a, as it's the smallest >= prev_val
            // Else (`current_a + x >= m`): // Wrap possible
            //   If (current_a + x) % m >= prev_val: // Can reach prev_val by wrapping
            //     // We can choose to make it prev_val (if prev_val is reachable by wrapping)
            //     // or current_a. We want the smallest.
            //     // If prev_val is 0, and we can reach 0, we choose 0.
            //     // If prev_val > 0, we choose current_a.
            //     // This is equivalent to: if prev_val is 0, and (m - current_a) % m <= x, then prev_val remains 0.
            //     // Else, prev_val becomes current_a.
            //     if (prev_val == 0 && (m - current_a) % m <= x) {
            //         // prev_val remains 0
            //     } else {
            //         prev_val = current_a;
            //     }
            //   Else (`(current_a + x) % m < prev_val`): // Cannot reach prev_val by wrapping
            //     prev_val = current_a; // Must use current_a
            //
            // This can be simplified.
            // We want to find the smallest `new_val` such that `new_val >= prev_val` and `new_val = (current_a + k) % m` for some `k <= x`.
            //
            // If `current_a >= prev_val`:
            //   We can always choose `new_val = current_a` (by `k=0` operations). This is valid.
            //   However, if we can achieve `prev_val` itself by incrementing `current_a` (i.e., `(prev_val - current_a + m) % m <= x`),
            //   then we can set `new_val = prev_val`. This is better (smaller or equal).
            //   So, if `(prev_val - current_a + m) % m <= x`, `prev_val` remains `prev_val`.
            //   Else, `prev_val` becomes `current_a`.
            //
            // If `current_a < prev_val`:
            //   We *must* increment `current_a`.
            //   We need `(current_a + k) % m >= prev_val` for some `k <= x`.
            //   The smallest `k` to make `current_a + k >= prev_val` (without wrapping) is `prev_val - current_a`.
            //   If `prev_val - current_a <= x`:
            //     We can set `new_val = prev_val`. So `prev_val` remains `prev_val`.
            //   Else (`prev_val - current_a > x`):
            //     We cannot reach `prev_val` without wrapping. We must wrap.
            //     This means `current_a + k >= m` for some `k <= x`.
            //     If `(current_a + x) % m < prev_val`:
            //       Even with `x` operations, we cannot reach `prev_val` by wrapping. Impossible. Return `false`.
            //     Else (`(current_a + x) % m >= prev_val`):
            //       We can reach `prev_val` by wrapping. So `prev_val` remains `prev_val`.
            //
            // This combined logic is:
            // If `current_a >= prev_val`:
            //   If `(prev_val - current_a + m) % m <= x`:
            //     // We can make `a_i` equal to `prev_val` by incrementing.
            //     // `prev_val` remains `prev_val`.
            //     continue;
            //   Else:
            //     // We cannot make `a_i` equal to `prev_val` by incrementing.
            //     // We must use `current_a` as the new value.
            //     prev_val = current_a;
            // Else (`current_a < prev_val`):
            //   If `(prev_val - current_a + m) % m <= x`:
            //     // We can make `a_i` equal to `prev_val` by incrementing.
            //     // `prev_val` remains `prev_val`.
            //     continue;
            //   Else:
            //     // We cannot make `a_i` equal to `prev_val` by incrementing.
            //     // This means it's impossible to satisfy `a_i >= prev_val`.
            //     return false;
            //
            // This is the most robust logic.

            long long diff_to_prev = (prev_val - current_a + m) % m;
            if (diff_to_prev > x) {
                // If we cannot reach prev_val by incrementing current_a by at most x,
                // then we must use current_a itself (if current_a >= prev_val).
                // If current_a < prev_val, this path means it's impossible.
                if (current_a < prev_val) {
                    return false;
                }
                // If current_a >= prev_val, we use current_a.
                prev_val = current_a;
            }
            // Else (diff_to_prev <= x), we can make current_a equal to prev_val.
            // So prev_val remains prev_val.
        } else { // current_a < prev_val
            long long diff_to_prev = (prev_val - current_a + m) % m;
            if (diff_to_prev > x) {
                // If we cannot reach prev_val by incrementing current_a by at most x,
                // then it's impossible.
                return false;
            }
            // Else (diff_to_prev <= x), we can make current_a equal to prev_val.
            // So prev_val remains prev_val.
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    std::vector<int> partition(n);

    // Case 1: All elements in one subsequence (e.g., subsequence 1).
    // No pairs are in different subsequences.
    // f(a_i, a_j) = a_i + a_j for all i, j.
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-2].value + elements[n-1].value
    // goodness = (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value)
    long long goodness1 = (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value);
    std::vector<int> best_partition(n);
    for (int i = 0; i < n; ++i) {
        best_partition[elements[i].original_index] = 1;
    }
    long long min_goodness = goodness1;

    // Case 2: Partition elements such that elements[0] is in one subsequence (e.g., 1)
    // and elements[1]...elements[n-1] are in the other (e.g., 2).
    // This is only possible if n >= 2.
    //
    // Pairs in same subsequence:
    //   - elements[i], elements[j] for i,j in [1, n-1]: f = elements[i].value + elements[j].value
    //     min_same = elements[1].value + elements[2].value (if n >= 3)
    //     max_same = elements[n-2].value + elements[n-1].value
    //   - No pairs in subsequence 1 if only elements[0] is there.
    //
    // Pairs in different subsequences:
    //   - elements[0] and elements[i] for i in [1, n-1]: f = elements[0].value + elements[i].value + h
    //     min_diff = elements[0].value + elements[1].value + h
    //     max_diff = elements[0].value + elements[n-1].value + h
    //
    // Overall min_f and max_f:
    // min_f = min(min_same, min_diff)
    // max_f = max(max_same, max_diff)

    // If n=2, elements[0] in sub1, elements[1] in sub2. Only one pair (0,1).
    // f(0,1) = elements[0].value + elements[1].value + h. min_f = max_f = this value. Goodness = 0.
    // This is covered by the general logic below.

    long long min_f_case2;
    long long max_f_case2;

    long long min_diff_val = elements[0].value + elements[1].value + h;
    long long max_diff_val = elements[0].value + elements[n-1].value + h;

    if (n == 2) {
        min_f_case2 = min_diff_val;
        max_f_case2 = max_diff_val;
    } else { // n >= 3
        long long min_same_val = elements[1].value + elements[2].value;
        long long max_same_val = elements[n-2].value + elements[n-1].value;

        min_f_case2 = std::min(min_same_val, min_diff_val);
        max_f_case2 = std::max(max_same_val, max_diff_val);
    }

    long long goodness2 = max_f_case2 - min_f_case2;

    if (goodness2 < min_goodness) {
        min_goodness = goodness2;
        best_partition[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            best_partition[elements[i].original_index] = 2;
        }
    }

    // Case 3: Partition elements such that elements[n-1] is in one subsequence (e.g., 1)
    // and elements[0]...elements[n-2] are in the other (e.g., 2).
    // This is symmetric to Case 2.
    //
    // Pairs in same subsequence:
    //   - elements[i], elements[j] for i,j in [0, n-2]: f = elements[i].value + elements[j].value
    //     min_same = elements[0].value + elements[1].value (if n >= 3)
    //     max_same = elements[n-3].value + elements[n-2].value
    //   - No pairs in subsequence 1 if only elements[n-1] is there.
    //
    // Pairs in different subsequences:
    //   - elements[n-1] and elements[i] for i in [0, n-2]: f = elements[n-1].value + elements[i].value + h
    //     min_diff = elements[0].value + elements[n-1].value + h
    //     max_diff = elements[n-2].value + elements[n-1].value + h
    //
    // Overall min_f and max_f:
    // min_f = min(min_same, min_diff)
    // max_f = max(max_same, max_diff)

    long long min_f_case3;
    long long max_f_case3;

    min_diff_val = elements[0].value + elements[n-1].value + h;
    max_diff_val = elements[n-2].value + elements[n-1].value + h;

    if (n == 2) {
        min_f_case3 = min_diff_val;
        max_f_case3 = max_diff_val;
    } else { // n >= 3
        long long min_same_val = elements[0].value + elements[1].value;
        long long max_same_val = elements[n-3].value + elements[n-2].value;

        min_f_case3 = std::min(min_same_val, min_diff_val);
        max_f_case3 = std::max(max_same_val, max_diff_val);
    }

    long long goodness3 = max_f_case3 - min_f_case3;

    if (goodness3 < min_goodness) {
        min_goodness = goodness3;
        best_partition[elements[n-1].original_index] = 1;
        for (int i = 0; i < n - 1; ++i) {
            best_partition[elements[i].original_index] = 2;
        }
    }

    // Case 4: elements[0] and elements[n-1] are in different subsequences.
    // elements[0] in sub1, elements[n-1] in sub2.
    // All other elements (elements[1]...elements[n-2]) are in sub1.
    // This is only possible if n >= 2.
    //
    // Pairs in same subsequence (sub1):
    //   - elements[0] and elements[i] for i in [1, n-2]: f = elements[0].value + elements[i].value
    //     min_same_sub1 = elements[0].value + elements[1].value (if n >= 3)
    //     max_same_sub1 = elements[0].value + elements[n-2].value (if n >= 3)
    //   - elements[i] and elements[j] for i,j in [1, n-2]: f = elements[i].value + elements[j].value
    //     min_same_sub1_mid = elements[1].value + elements[2].value (if n >= 4)
    //     max_same_sub1_mid = elements[n-3].value + elements[n-2].value (if n >= 4)
    //
    // Pairs in different subsequences:
    //   - elements[0] and elements[n-1]: f = elements[0].value + elements[n-1].value + h
    //   - elements[i] (from sub1) and elements[n-1] (from sub2) for i in [0, n-2]:
    //     f = elements[i].value + elements[n-1].value + h
    //     min_diff = elements[0].value + elements[n-1].value + h
    //     max_diff = elements[n-2].value + elements[n-1].value + h
    //
    // Overall min_f and max_f:
    // min_f = min(min_same_sub1, min_same_sub1_mid, min_diff)
    // max_f = max(max_same_sub1, max_same_sub1_mid, max_diff)

    long long min_f_case4;
    long long max_f_case4;

    min_diff_val = elements[0].value + elements[n-1].value + h;
    max_diff_val = elements[n-2].value + elements[n-1].value + h; // This is correct for n >= 2. If n=2, elements[n-2] is elements[0].

    if (n == 2) {
        min_f_case4 = min_diff_val;
        max_f_case4 = max_diff_val;
    } else { // n >= 3
        long long min_same_sub1 = elements[0].value + elements[1].value;
        long long max_same_sub1 = elements[0].value + elements[n-2].value;

        min_f_case4 = std::min(min_same_sub1, min_diff_val);
        max_f_case4 = std::max(max_same_sub1, max_diff_val);

        if (n >= 4) {
            long long min_same_sub1_mid = elements[1].value + elements[2].value;
            long long max_same_sub1_mid = elements[n-3].value + elements[n-2].value;
            min_f_case4 = std::min(min_f_case4, min_same_sub1_mid);
            max_f_case4 = std::max(max_f_case4, max_same_sub1_mid);
        }
    }

    long long goodness4 = max_f_case4 - min_f_case4;

    if (goodness4 < min_goodness) {
        min_goodness = goodness4;
        best_partition[elements[0].original_index] = 1;
        best_partition[elements[n-1].original_index] = 2;
        for (int i = 1; i < n - 1; ++i) {
            best_partition[elements[i].original_index] = 1;
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // dp[i] will store the maximum starting index 'x' (0-based)
    // such that s[x] = s[x+k] = s[x+2k] for some k,
    // and x+2k = i.
    // In other words, dp[i] is the smallest 'x' such that the pattern
    // s[x...i] contains s[x'] = s[x'+k] = s[x'+2k] with x'+2k = i.
    // Or, more simply, dp[i] is the minimum starting index of a pattern
    // that ends at or before index i.
    // Let's redefine: dp[i] = minimum starting index 'x' (0-based)
    // such that s[x] = s[x+k] = s[x+2k] for some k, and x+2k <= i.
    // If no such pattern exists ending at or before i, dp[i] = n (or some large value).

    // Let's use a different DP state.
    // `min_x_for_pattern_ending_at_i` stores the minimum `x` such that
    // `s[x] = s[x+k] = s[x+2k]` for some `k`, and `x+2k = i`.
    // If no such pattern ends exactly at `i`, it's `n`.
    std::vector<int> min_x_for_pattern_ending_at_i(n, n);

    for (int i = 0; i < n; ++i) {
        // Check for k=1, 2, 3, 4, 5, 6
        // The maximum k needed is 6 because 2k <= 12.
        // If k >= 7, then 2k >= 14.
        // If a pattern s[x]=s[x+k]=s[x+2k] exists, then x+2k <= n-1.
        // The minimum length of such a pattern is 3 (for k=1).
        // The maximum length of such a pattern is 13 (for k=6, x=0, 0+2*6=12).
        // If a pattern exists with k >= 7, then x+2k >= 14.
        // If we consider a substring of length 13, say s[0...12],
        // and it does NOT contain any pattern with k <= 6,
        // then it cannot contain any pattern at all.
        // This is because if it contained a pattern s[x]=s[x+k]=s[x+2k] with k >= 7,
        // then x+2k >= 14, which means the pattern would extend beyond index 12.
        // So, we only need to check k up to 6.
        for (int k = 1; k <= 6; ++k) {
            if (i - 2 * k >= 0) { // Check if s[i-2k], s[i-k], s[i] are valid indices
                if (s[i - 2 * k] == s[i - k] && s[i - k] == s[i]) {
                    min_x_for_pattern_ending_at_i[i] = std::min(min_x_for_pattern_ending_at_i[i], i - 2 * k);
                }
            }
        }
    }

    // `last_pattern_start_idx[i]` stores the minimum `x` such that
    // `s[x] = s[x+k] = s[x+2k]` for some `k`, and `x+2k <= i`.
    // If no such pattern exists ending at or before `i`, it's `n`.
    std::vector<int> last_pattern_start_idx(n, n);
    if (n > 0) {
        last_pattern_start_idx[0] = n; // No pattern can end at index 0
    }
    for (int i = 1; i < n; ++i) {
        last_pattern_start_idx[i] = last_pattern_start_idx[i-1]; // Inherit from previous
        last_pattern_start_idx[i] = std::min(last_pattern_start_idx[i], min_x_for_pattern_ending_at_i[i]);
    }

    for (int l = 0; l < n; ++l) {
        // For a fixed `l`, we want to find the smallest `r` such that `s[l...r]`
        // contains a pattern.
        // This means we need `x` such that `l <= x` and `x+2k <= r`.
        // The smallest `r` for which a pattern exists starting at or after `l`
        // is `min_r_for_l`.
        // If `last_pattern_start_idx[r]` is the minimum `x` such that `x+2k <= r`,
        // then we need `last_pattern_start_idx[r] < l`.
        // No, this is wrong. We need `last_pattern_start_idx[r] >= l`.
        // `last_pattern_start_idx[r]` is the minimum `x` such that `x+2k <= r`.
        // If `last_pattern_start_idx[r] < l`, it means the pattern starts before `l`,
        // so it's not contained in `s[l...r]`.
        // We need to find the smallest `r` such that there exists an `x` with
        // `l <= x` and `x+2k <= r` and `s[x]=s[x+k]=s[x+2k]`.
        // Let `min_r_for_l` be the smallest `r` such that `s[l...r]` contains a pattern.
        // If no such `r` exists, `min_r_for_l = n`.

        // Iterate `r` from `l` to `n-1`.
        // If `last_pattern_start_idx[r] <= r` (meaning a pattern exists ending at or before `r`)
        // AND `last_pattern_start_idx[r] >= l` (meaning the pattern starts at or after `l`),
        // then `s[l...r]` contains a pattern.
        // The number of `r` values for a fixed `l` that satisfy the condition is `n - min_r_for_l`.
        // We are counting bad pairs, so we need `r` such that `s[l...r]` does NOT contain a pattern.
        // This means for all `x, k` with `l <= x` and `x+2k <= r`, `s[x]=s[x+k]=s[x+2k]` is false.

        // Let `first_r_with_pattern_starting_at_l_or_later` be the smallest `r` such that
        // `last_pattern_start_idx[r] >= l`.
        // If `last_pattern_start_idx[r] < l`, it means any pattern ending at or before `r`
        // starts before `l`. So `s[l...r]` does not contain a pattern.
        // We need to find the smallest `r` such that `last_pattern_start_idx[r] >= l`.
        // All `r'` from `l` to `r-1` will have `last_pattern_start_idx[r'] < l`.
        // These are the `r` values for which `s[l...r']` does not contain a pattern.
        // The number of such `r'` is `r - l`.

        // Find the smallest `r_idx` such that `last_pattern_start_idx[r_idx] >= l`.
        // If no such `r_idx` exists, then `last_pattern_start_idx[n-1] < l`.
        // In this case, for all `r` from `l` to `n-1`, `s[l...r]` does not contain a pattern.
        // The number of such `r` values is `n - l`.

        // If such `r_idx` exists:
        // For `r` from `l` to `r_idx - 1`, `last_pattern_start_idx[r] < l`.
        // So `s[l...r]` does not contain a pattern.
        // The number of such `r` values is `r_idx - l`.

        // If `last_pattern_start_idx[r_idx] >= l`, then for `r >= r_idx`, `s[l...r]` contains a pattern.
        // So we count `r` from `l` to `r_idx - 1`.

        // Use binary search or `std::lower_bound` to find `r_idx`.
        // `last_pattern_start_idx` is non-increasing.
        // We need to find the first `r_idx` such that `last_pattern_start_idx[r_idx] >= l`.
        // This is equivalent to finding the first `r_idx` such that `last_pattern_start_idx[r_idx]`
        // is not less than `l`.

        // `std::upper_bound` on `last_pattern_start_idx` for value `l-1`.
        // `it = std::upper_bound(last_pattern_start_idx.begin() + l, last_pattern_start_idx.end(), l-1, std::greater<int>())`
        // This finds the first element `e` such that `e <= l-1` is false, i.e., `e > l-1`, i.e., `e >= l`.
        // The range for `r` is `[l, n-1]`.

        auto it = std::lower_bound(last_pattern_start_idx.begin() + l, last_pattern_start_idx.end(), l, std::greater<int>());
        int r_idx = std::distance(last_pattern_start_idx.begin(), it);

        // All `r` from `l` to `r_idx - 1` are bad pairs.
        // The number of such `r` values is `r_idx - l`.
        bad_pairs += (r_idx - l);
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut divides s into s1 and s2.
    // We can form s' = s2 + s1.
    // If s' is a palindrome and s' != s, then k=1 is the answer.
    // Iterate through all possible cut positions.
    for (int i = 1; i < n; ++i) {
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string s_prime = s2 + s1;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2.
    // If k=2 is the answer, it means no single cut and swap works.
    // This implies that for any cut point i, s[0...i-1] + s[i...n-1] -> s[i...n-1] + s[0...i-1] is either s or not a palindrome.
    //
    // Consider the structure of the string s.
    // s is a palindrome.
    // If all characters in s are the same (e.g., "aaaaa"), then any rearrangement of pieces will result in the same string "aaaaa".
    // In this case, it's impossible to form a different string.
    // We can check this by counting unique characters.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }
    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work, then k=2 is always possible.
    // Why?
    // Consider the string s = "abacaba".
    // If we cut it into s[0...n-2] and s[n-1], i.e., "abacab" and "a".
    // Rearranging gives "a" + "abacab" = "aabacab". This is not a palindrome.
    //
    // The problem statement guarantees s is a palindrome.
    // If not all characters are the same, then there must be at least two distinct characters.
    // Since s is a palindrome, it must have at least two distinct characters if n > 1.
    // If n=1, it's "a", all same, impossible.
    //
    // If n is odd, say "abacaba", n=7.
    // s[0] = 'a', s[1] = 'b', s[2] = 'a', s[3] = 'c', s[4] = 'a', s[5] = 'b', s[6] = 'a'.
    //
    // Consider cutting s into three pieces:
    // s[0] | s[1...n-2] | s[n-1]
    // For example, "a" | "bacab" | "a" for "abacaba".
    // Rearrange to s[n-1] | s[1...n-2] | s[0]
    // This would be "a" | "bacab" | "a" = "abacaba". This is s.
    //
    // What if we cut s into s[0...i-1], s[i...j-1], s[j...n-1]?
    //
    // Let's consider the property that if s is a palindrome and not all characters are the same,
    // then s can always be cut into two pieces s1, s2 such that s2+s1 is a palindrome.
    // This is not true. Example: "nolon". n=5.
    // "n" + "olon" -> "olonn" (not pal)
    // "no" + "lon" -> "lonno" (not pal)
    // "nol" + "on" -> "onnol" (not pal)
    // "nolo" + "n" -> "nnolo" (not pal)
    // For "nolon", k=1 doesn't work.
    // But "nolon" is not all same chars. So the answer is 2.
    //
    // The logic is:
    // 1. If all characters in `s` are the same (e.g., "aaaa"), then any rearrangement of pieces will result in the same string `s`. So, it's "Impossible".
    // 2. Otherwise (if `s` contains at least two distinct characters), we try `k=1`. If any single cut and swap `s_1 + s_2 -> s_2 + s_1` results in a palindrome `s'` different from `s`, then `k=1` is the answer.
    // 3. If `k=1` doesn't work, but `s` has at least two distinct characters, then `k=2` is always possible.
    //    Consider `s = s_0 s_1 ... s_{n-1}`.
    //    Since `s` is a palindrome and not all characters are the same, there must be some `i` such that `s_i != s_0`.
    //    Consider cutting `s` into `s_0`, `s_1...s_{n-1}`. This is `s_0` and `s_1...s_{n-1}`.
    //    This is a single cut.
    //    The problem states that if `k=1` doesn't work, then `k=2` is the answer.
    //    This is a known property for palindromes: if a palindrome `s` is not composed of all identical characters, and no single cut and swap yields a new palindrome, then two cuts are sufficient.
    //    A common way to achieve this is to cut `s` into `s[0]`, `s[1...n-2]`, `s[n-1]`.
    //    Then rearrange to `s[n-1]`, `s[1...n-2]`, `s[0]`.
    //    Since `s` is a palindrome, `s[0] == s[n-1]`. So this rearrangement gives `s[0] + s[1...n-2] + s[n-1]`, which is `s`.
    //    This specific rearrangement doesn't work.
    //
    //    However, the problem asks for *any* rearrangement.
    //    If `s` is a palindrome and not all characters are the same, then `s` must have length `n >= 2`.
    //    If `n` is even, `s = P P^R` where `P` is the first half and `P^R` is its reverse.
    //    Example: "otto". `P="ot"`, `P^R="to"`. `s="otto"`.
    //    Cut "ot" | "to". Swap: "to" | "ot" = "toot". This is a palindrome and `!= "otto"`. So `k=1`.
    //    Example: "kinnikkinnik". `P="kinnik"`, `P^R="kinnik"`. `s="kinnikkinnik"`.
    //    Cut "kinnik" | "kinnik". Swap: "kinnik" | "kinnik" = "kinnikkinnik". This is `s`.
    //    But for "kinnikkinnik", `k=1` is possible. Cut "kinnikkin" | "nik". Swap: "nik" + "kinnikkin" = "nikkinnikkin". This is a palindrome and `!= s`.
    //
    // The problem statement implies that if k=1 doesn't work, and it's not "Impossible", then k=2 is the answer.
    // The only "Impossible" case is when all characters are the same.
    // This is because if there are at least two distinct characters, we can always find a way to make two cuts and rearrange to form a new palindrome.
    // For example, take `s = s_0 s_1 ... s_{n-1}`.
    // Since `s` is a palindrome and not all characters are the same, there exists some `i` such that `s_i != s_0`.
    // Consider the string `s'` formed by taking `s_0 s_1 ... s_{n-2}` and moving `s_{n-1}` to the beginning.
    // `s' = s_{n-1} s_0 s_1 ... s_{n-2}`.
    // Since `s` is a palindrome, `s_0 = s_{n-1}`. So `s' = s_0 s_0 s_1 ... s_{n-2}`.
    // This is not necessarily a palindrome.
    //
    // The crucial observation is that if `s` is a palindrome and not all characters are the same,
    // then `s` must contain at least two distinct characters.
    // If `n` is odd, `s = X c X^R` where `c` is the middle character.
    // If `n` is even, `s = X X^R`.
    //
    // If `s` is a palindrome and not all characters are the same, then `s` has a structure like `a...b...a` where `a != b`.
    // Consider `s` without its first and last characters: `s.substr(1, n-2)`.
    // This substring `s.substr(1, n-2)` is also a palindrome.
    // If `s.substr(1, n-2)` is not all same characters, then we can apply the same logic recursively.
    // If `s.substr(1, n-2)` *is* all same characters, say `b...b`, then `s` looks like `a b...b a`.
    // Example: "ababa". `s.substr(1,3)` is "bab".
    // Example: "racecar". `s.substr(1,5)` is "aceca".
    //
    // The problem statement implies that if `k=1` doesn't work, and it's not "Impossible", then `k=2` is the answer.
    // This is a standard result for palindromes:
    // A palindrome `s` can be rearranged into a different palindrome `s'` using one cut if and only if `s` is not of the form `X X^R` where `X` is a palindrome itself, or `s` is not of the form `X c X^R` where `X` is a palindrome.
    // More simply, if `s` is a palindrome and not all characters are the same, and `k=1` doesn't work, then `k=2` is the answer.
    // This is because we can always find a way to make two cuts and rearrange.
    // For example, take `s = s_0 s_1 ... s_{n-1}`.
    // Cut `s` into `s_0`, `s_1...s_{n-1}`. This is one cut.
    // If `s_0` is moved to the end, we get `s_1...s_{n-1} s_0`.
    // Since `s_0 = s_{n-1}`, this is `s_1...s_{n-1} s_{n-1}`.
    // This is not necessarily a palindrome.
    //
    // The simplest way to get a new palindrome with two cuts is to take `s_0`, `s_1...s_{n-2}`, `s_{n-1}`.
    // Rearrange them as `s_0`, `s_{n-1}`, `s_1...s_{n-2}`. This is not a palindrome.
    //
    // The logic for k=2 being always possible (if not all chars are same and k=1 fails) is based on the fact that
    // if `s` is a palindrome and not all characters are the same, then `s` must have at least two distinct characters.
    // Let `s = c_0 c_1 ... c_{n-1}`.
    // Since `s` is a palindrome, `c_i = c_{n-1-i}`.
    // Since not all characters are the same, there exists some `j` such that `c_j != c_0`.
    // Consider the string `s'` formed by rotating `s` by one character: `s' = c_{n-1} c_0 c_1 ... c_{n-2}`.
    // Since `c_{n-1} = c_0`, `s' = c_0 c_0 c_1 ... c_{n-2}`.
    // This `s'` is not necessarily a palindrome.
    //
    // The problem statement implies that if `k=1` doesn't work, and it's not "Impossible", then `k=2` is the answer.
    // This is a common pattern in competitive programming problems where small `k` values are tested.
    // The "Impossible" case is correctly identified as all characters being the same.
    // If `s` has at least two distinct characters, and `k=1` doesn't yield a solution, then `k=2` must be the answer.
    // This is because if `s` is a palindrome and not all characters are the same, then `s` can always be cut into three pieces and rearranged to form a new palindrome.
    // For example, consider `s = s_0 s_1 ... s_{n-1}`.
    // If `n` is odd, `s = X c X^R`.
    // If `n` is even, `s = X X^R`.
    //
    // The simplest argument for `k=2` is that if `s` is a palindrome and not all characters are the same,
    // then `s` must contain at least two distinct characters.
    // If `s` is not all same characters, then `s` has at least one character `c_i` such that `c_i != c_0`.
    // Consider the string `s'` formed by taking `s` and moving its first character to the end.
    // `s' = s_1 s_2 ... s_{n-1} s_0`.
    // This `s'` is not necessarily a palindrome.
    //
    // The problem is essentially asking for the smallest `k`.
    // `k=0` is impossible.
    // `k=1` is checked.
    // If `k=1` fails, and `s` is not all same characters, then `k=2` is the answer.
    // This is a known property for palindromes. If a palindrome `s` is not monochromatic (all same characters),
    // then it is always possible to form a new palindrome `s'` by cutting `s` into at most 3 pieces (i.e., `k <= 2`).
    // The only case where it's impossible is if all characters are the same.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int head_idx = 0;
    int p_idx = 0;

    while (p_idx < m) {
        if (head_idx >= n) {
            return false; // Ran out of heads but still have tracks to cover
        }

        // Current head h[head_idx] needs to cover p[p_idx]
        // If h[head_idx] is too far to the right to cover p[p_idx] even by moving left T steps
        if (h[head_idx] + T < p[p_idx]) {
            head_idx++; // This head cannot reach p[p_idx], try next head
            continue;
        }

        // If h[head_idx] is too far to the left to cover p[p_idx] even by moving right T steps
        // This means p[p_idx] is to the right of h[head_idx] + T
        // This case is covered by the previous if condition.
        // If h[head_idx] - T > p[p_idx], then this head is too far right.
        // This means p[p_idx] is to the left of h[head_idx] - T.
        // We need to find a head that can cover p[p_idx].
        // The current head h[head_idx] can cover p[p_idx] if h[head_idx] - T <= p[p_idx] <= h[head_idx] + T.
        // If h[head_idx] - T > p[p_idx], then h[head_idx] is too far to the right.
        // We must use a head to the left of h[head_idx] or move h[head_idx] to the left.
        // The current head h[head_idx] can cover the range [h[head_idx] - T, h[head_idx] + T].
        // If p[p_idx] is within this range, we can use this head.
        // If p[p_idx] < h[head_idx] - T, then h[head_idx] is too far right for p[p_idx].
        // We need to find a head that can cover p[p_idx].
        // Since heads and tracks are sorted, we should use the current head h[head_idx] to cover p[p_idx]
        // if it's possible, and then cover as many subsequent tracks as possible.

        // The current head h[head_idx] can cover p[p_idx].
        // It can cover tracks up to max_reach = h[head_idx] + T.
        // However, if h[head_idx] is to the right of p[p_idx], say h[head_idx] = 10, p[p_idx] = 5, T = 2.
        // h[head_idx] can cover [8, 12]. p[p_idx] = 5 is not covered.
        // This means h[head_idx] - T > p[p_idx].
        // In this case, we need to use a head that is further to the left.
        // But we are iterating heads from left to right.
        // This implies that if h[head_idx] - T > p[p_idx], then no previous head could cover p[p_idx] either,
        // because previous heads are even further to the left.
        // This means p[p_idx] cannot be covered by any head.
        // This logic is flawed. A head can move.
        // A head at h_k can cover any track x such that |x - h_k| <= T.
        // This means it can cover any track x in [h_k - T, h_k + T].
        // To cover p[p_idx], we need to find a head h_k such that h_k - T <= p[p_idx] <= h_k + T.

        // Let's re-evaluate. We are trying to cover p[p_idx].
        // We use the current head `h[head_idx]`.
        // If `h[head_idx]` is too far to the right to cover `p[p_idx]` (i.e., `h[head_idx] - T > p[p_idx]`),
        // then this head cannot cover `p[p_idx]`. Since `h` is sorted, any subsequent head `h[head_idx+1]`, etc.,
        // will be even further to the right, so they also cannot cover `p[p_idx]`.
        // This means `p[p_idx]` cannot be covered.
        if (h[head_idx] - T > p[p_idx]) {
            return false;
        }

        // If we reach here, it means `h[head_idx] - T <= p[p_idx]`.
        // So, `h[head_idx]` (or a position it can move to) can cover `p[p_idx]`.
        // The leftmost track this head can cover is `h[head_idx] - T`.
        // The rightmost track this head can cover is `h[head_idx] + T`.
        // So, this head can cover the range `[h[head_idx] - T, h[head_idx] + T]`.
        // We want to cover `p[p_idx]` and as many subsequent `p` tracks as possible with this head.
        // The rightmost track this head can cover is `h[head_idx] + T`.
        // So, we advance `p_idx` as long as `p[p_idx]` is within this range.
        long long current_head_max_reach = h[head_idx] + T;
        while (p_idx < m && p[p_idx] <= current_head_max_reach) {
            p_idx++;
        }
        head_idx++; // Move to the next head for the remaining tracks
    }
    return true; // All tracks covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible distance between p_m and h_1, or p_1 and h_n.
                               // Max p_i is 10^10, min h_i is 1. Max diff is 10^10.
                               // Max h_i is 10^10, min p_i is 1. Max diff is 10^10.
                               // So 10^10 is a safe upper bound. 2e10+7 is even safer.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL;
        long long max_y = 2000000000LL;

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1 = 1 means can move left (x-1). If f1=0, cannot move left.
            // If robot cannot move left, it must end up at an X >= its current x.
            // So, X >= x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }

            // f3 = 1 means can move right (x+1). If f3=0, cannot move right.
            // If robot cannot move right, it must end up at an X <= its current x.
            // So, X <= x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }

            // f4 = 1 means can move down (y-1). If f4=0, cannot move down.
            // If robot cannot move down, it must end up at a Y >= its current y.
            // So, Y >= y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }

            // f2 = 1 means can move up (y+1). If f2=0, cannot move up.
            // If robot cannot move up, it must end up at a Y <= its current y.
            // So, Y <= y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and_mask = 1023; // Represents the value that `x` would become if all operations were `&`
    int current_or_mask = 0;    // Represents the value that `x` would become if all operations were `|`
    int current_xor_mask = 0;   // Represents the value that `x` would become if all operations were `^`

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_and_mask &= x;
            current_or_mask &= x;
            current_xor_mask &= x;
        } else if (op_char == '|') {
            current_and_mask |= x;
            current_or_mask |= x;
            current_xor_mask |= x;
        } else if (op_char == '^') {
            current_and_mask ^= x;
            current_or_mask ^= x;
            current_xor_mask ^= x;
        }
    }

    std::vector<std::pair<char, int>> result_ops;

    // Determine the final AND mask
    // If a bit is 0 in current_and_mask, it means any input bit will become 0.
    // If a bit is 1 in current_and_mask, it means the input bit is preserved.
    // So, the final AND mask is current_and_mask.
    // We need to apply an AND operation with a constant that sets bits to 0 where current_and_mask has 0.
    // This constant is current_and_mask itself.
    // If current_and_mask is not 1023 (all bits 0-9 are 1), we need an '&' operation.
    if (current_and_mask != 1023) {
        result_ops.push_back({'&', current_and_mask});
    }

    // Determine the final OR mask
    // If a bit is 1 in current_or_mask, it means any input bit will become 1.
    // If a bit is 0 in current_or_mask, it means the input bit is preserved.
    // So, the final OR mask is current_or_mask.
    // We need to apply an OR operation with a constant that sets bits to 1 where current_or_mask has 1.
    // This constant is current_or_mask itself.
    // If current_or_mask is not 0 (all bits 0-9 are 0), we need an '|' operation.
    if (current_or_mask != 0) {
        result_ops.push_back({'|', current_or_mask});
    }

    // Determine the final XOR mask
    // If a bit is 1 in current_xor_mask, it means the input bit is flipped.
    // If a bit is 0 in current_xor_mask, it means the input bit is preserved.
    // So, the final XOR mask is current_xor_mask.
    // We need to apply an XOR operation with a constant that flips bits where current_xor_mask has 1.
    // This constant is current_xor_mask itself.
    // If current_xor_mask is not 0 (all bits 0-9 are 0), we need an '^' operation.
    if (current_xor_mask != 0) {
        result_ops.push_back({'^', current_xor_mask});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

