        }
        for (int i = 0; i < n; ++i) {
            std::cin >> b[i].value;
            b[i].original_index = i;
        }

        std::sort(a.begin(), a.end(), compareItems);
        std::sort(b.begin(), b.end(), compareItems);

        std::vector<int> x(n);
        std::vector<int> y(n);

        for (int i = 0; i < n; ++i) {
