void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees a solution exists.
    // A simple strategy that works for all n >= 2 is to reverse the permutation.
    // Let p' be the reversed permutation of p.
    // p' = [p_n, p_{n-1}, ..., p_2, p_1]
    // The adjacent sums for p are: [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n]
    // The adjacent sums for p' are: [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1]
    // These two sets of sums are identical, just in reverse order.
    // Since the fingerprint is the *sorted* array of sums, F(p) will be equal to F(p').
    // The only case where p' might be equal to p is if p is a palindrome.
    // However, a permutation cannot be a palindrome unless n=1 (which is not allowed, n>=2)
    // or if n is odd and the middle element is fixed, and elements are symmetric.
    // For example, [1,2,1] is not a permutation. [1,2,3,2,1] is not a permutation.
    // A permutation consists of distinct integers from 1 to n.
