    // But all elements in a permutation must be distinct.
    // So p_1 = p_n implies p_1 is not distinct from p_n unless n=1, which is not the case.
    // Thus, p is always different from its reverse p' for n >= 2.

    std::reverse(p.begin(), p.end());
    for (int i = 0; i < n; ++i) {
