#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n);

    bool flip_color = false; // State for elements equal to T/2

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T / 2.0) { // Use 2.0 for floating point comparison
            p[i] = 0; // White
        } else if (a[i] > T / 2.0) {
            p[i] = 1; // Black
        } else { // a[i] == T / 2.0
            // For elements equal to T/2, alternate colors
            if (flip_color) {
                p[i] = 1; // Black
            } else {
                p[i] = 0; // White
            }
            flip_color = !flip_color; // Flip for the next T/2 element
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, m;
    std::cin >> n >> m;
    std::vector<bool> row_has_one(n, false);
    std::vector<bool> col_has_one(m, false);

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            int val;
            std::cin >> val;
            if (val == 1) {
                row_has_one[i] = true;
                col_has_one[j] = true;
            }
        }
    }

    int free_rows = 0;
    for (int i = 0; i < n; ++i) {
        if (!row_has_one[i]) {
            free_rows++;
        }
    }

    int free_cols = 0;
    for (int j = 0; j < m; ++j) {
        if (!col_has_one[j]) {
            free_cols++;
        }
    }

    int num_moves = std::min(free_rows, free_cols);

    if (num_moves % 2 == 1) {
        std::cout << "Ashish\n";
    } else {
        std::cout << "Vivek\n";
    }
}

