int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue; // a_ii is 0, skip it
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is 0 (which happens if n=2 and p_i=1, p_j=2, then a_ij=1, but if p_i=1, p_j=1, this is not a permutation),
        // or if all other elements are 0 (which means p_i is 1 and all other p_j are >1),
        // then p_i must be n.
        // More generally, if max_val_in_row is less than n, it means p_i must be n.
        // This is because if p_i < n, then there must be some p_j = n.
        // Then min(p_i, p_j) = p_i. So max_val_in_row would be at least p_i.
        // If p_i = n, then for any j, min(p_i, p_j) = p_j.
        // The maximum of these p_j's (excluding p_i itself) would be n-1.
        // So if max_val_in_row is n-1, then p_i must be n.
        // If max_val_in_row is less than n-1, then p_i must be n.
        // The only case where max_val_in_row is not n-1 is if n=2 and p={1,2}.
        // For p_0=1, max_val_in_row = a_01 = min(p_0, p_1) = min(1,2) = 1.
        // For p_1=2, max_val_in_row = a_10 = min(p_1, p_0) = min(2,1) = 1.
        // In this case, p_1 should be n=2.
        // The logic is: if p_i is not n, then there is some p_k = n.
        // Then a_ik = min(p_i, p_k) = min(p_i, n) = p_i.
        // So max_val_in_row must be at least p_i.
        // If p_i = n, then for all j != i, a_ij = min(n, p_j) = p_j.
        // The maximum of these p_j's is n-1.
        // So, if max_val_in_row is n-1, then p_i must be n.
        // If max_val_in_row is less than n-1, it means that all other p_j are also less than n-1.
        // This implies that n itself is not present in the other positions, so p_i must be n.
        // This covers the edge case where n=2, p={1,2}. For p_0=1, max_val_in_row=1. For p_1=2, max_val_in_row=1.
        // In both cases, max_val_in_row is not n-1 (which is 1).
        // So if max_val_in_row < n-1, p_i = n.
        // If max_val_in_row == n-1, p_i = n.
        // This means if max_val_in_row is not n, then p_i must be n.
        // The only case where max_val_in_row could be n is if p_i is not n, and some p_j is n, and p_i is also n. This is impossible.
        // So, if max_val_in_row is less than n, then p_i must be n.
        // Otherwise, p_i = max_val_in_row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_suffix = a[n - 1]; // Initialize with the last price

    // Iterate from the second to last day backwards
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix, it means a[i] is
            // a new minimum for the suffix starting from i.
            min_suffix = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

