        int last_r_pos = -1; // Represents cell 0
        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                max_gap = std::max(max_gap, i - last_r_pos);
                last_r_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R'
        // to cell n+1. The distance is (n+1) - (last_r_pos + 1) = n - last_r_pos.
        // Or, more simply, the distance from last_r_pos to n is n - last_r_pos.
        // The cells are 0, 1, ..., n, n+1.
        // If last_r_pos is the index in string s, it corresponds to cell last_r_pos + 1.
        // The target is cell n+1.
        // The distance from cell (last_r_pos + 1) to cell (n+1) is (n+1) - (last_r_pos + 1) = n - last_r_pos.
        // This is the gap from the last 'R' to the end.
        max_gap = std::max(max_gap, (int)s.length() - last_r_pos);
        std::cout << max_gap << "\n";
