    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians for the minimum requirement.
            // Remaining coders: c - mid
            // Remaining mathematicians: m - mid
            // Remaining students without specialization: x
            // Total remaining students: (c - mid) + (m - mid) + x
            // Each team needs 3 members. 'mid' teams need 3 * mid members.
            // We've already accounted for 'mid' coders and 'mid' mathematicians.
            // So, we need 'mid' more members to fill the teams (3 * mid - mid - mid = mid).
            // These 'mid' additional members can come from remaining coders, mathematicians, or x.
            // The total pool of students available for these 'mid' additional slots is
            // (c - mid) + (m - mid) + x.
            // If this pool is >= mid, then it's possible to form 'mid' teams.
            if ((c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
