int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = n;
    bool use_left = true;

    // Generate k distinct differences
    // The first k+1 elements will generate k distinct differences
    // by alternating between the smallest available and largest available numbers.
    // This generates differences: n-1, n-2, ..., n-k.
    // Example: n=5, k=2
    // p_1 = 1 (left)
    // p_2 = 5 (right) -> diff = 4
    // p_3 = 2 (left) -> diff = 3
    // Now we have 2 distinct differences (4, 3). k=2.
    // The remaining elements (p_4, p_5) should not introduce new differences
    // or should introduce differences that are already present.
    // The simplest way is to continue in increasing order.
    // p_4 = 3, p_5 = 4.
    // Full sequence: 1 5 2 3 4
    // Differences: |1-5|=4, |5-2|=3, |2-3|=1, |3-4|=1
    // Distinct differences: {1, 3, 4}. This is 3 distinct differences, not k=2.

    // Let's rethink. We need exactly k distinct differences.
    // The strategy should be to generate k distinct differences using the first k+1 elements,
    // and then fill the rest of the permutation such that no new distinct differences are introduced.

    // To get k distinct differences, we can generate the largest possible differences first.
    // The largest differences are n-1, n-2, ..., n-k.
    // We can achieve this by alternating between the smallest available number and the largest available number.
    // p_1 = 1
    // p_2 = n
    // p_3 = 2
    // p_4 = n-1
    // ...
    // This generates differences: |1-n|=n-1, |n-2|=n-2, |2-(n-1)|=n-3, ...
    // This pattern generates k distinct differences using k+1 elements.
    // The differences generated are n-1, n-2, ..., n-k.

    for (int i = 0; i < k + 1; ++i) {
        if (use_left) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
        use_left = !use_left;
    }

    // After generating k distinct differences using the first k+1 elements,
    // the remaining n - (k+1) elements should be filled in a way that
    // doesn't introduce new distinct differences.
    // The simplest way to do this is to fill the remaining elements in increasing order.
    // Since 'left' now holds the smallest unused number, we can just append them.
    for (int i = k + 1; i < n; ++i) {
        p[i] = left;
        left++;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

