#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_one = false;
    bool has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = n - 1; i >= 1; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it's already correct.
            // The counts of 1s and -1s from elements before i remain the same.
            continue;
        } else if (a[i] < b[i]) {
            // Need to increase a[i]. This requires adding a positive value.
            // We must have seen a '1' at an index < i.
            if (!has_one) {
                std::cout << "NO\n";
                return;
            }
        } else { // a[i] > b[i]
            // Need to decrease a[i]. This requires adding a negative value.
            // We must have seen a '-1' at an index < i.
            if (!has_minus_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // Update has_one and has_minus_one for elements before index i
        // (which are relevant for indices < i).
        if (a[i] == 1) {
            has_one = false; // This '1' is now "used up" for future elements
                             // or its value has changed to b[i].
                             // It cannot be used to modify elements before i.
        } else if (a[i] == -1) {
            has_minus_one = false; // Same logic for -1.
        }
    }

    std::cout << "YES\n";
}

