    std::sort(a.begin(), a.end());

    int count = 0;
    int j = 0; // Pointer for elements to be placed (potential B[i])
    for (int i = 0; i < n; ++i) { // Pointer for original elements (A[i])
        // We are trying to find an element a[j] such that a[j] > a[i]
        // Since both arrays are sorted, we can advance j.
        // If a[j] is not greater than a[i], we need a larger element, so we increment j.
        // If a[j] is greater than a[i], we found a match, increment count, and move to the next a[i] and a[j].
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // If we found an element a[j] > a[i]
            count++;
            j++; // Move to the next element for placement
        } else {
            // No more elements in 'a' are greater than the current a[i]
            // All remaining a[i] cannot be matched with a larger element.
            break;
        }
    }

    std::cout << count << std::endl;

