struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<ElementB> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    std::sort(a_elements.begin(), a_elements.end(), compareA);
    std::sort(b_elements.begin(), b_elements.end(), compareB);

    std::vector<long long> result_a(m);
    for (int i = 0; i < m; ++i) {
        // The i-th smallest B value (b_elements[i].value) should be paired with
        // the (m-1-i)-th largest A value (a_elements[m-1-i].value).
        // The original index of this B value is b_elements[i].original_index.
        // So, result_a[original_index_of_B] = value_of_A.
        result_a[b_elements[i].original_index] = a_elements[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
