// Function to check if a subarray is a permutation
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) return true; // An empty sequence can be considered a permutation of length 0
    if (len > arr.size() - start_idx) return false; // Not enough elements

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int max_prefix_val = 0;
    bool prefix_valid = true;
    for (int i = 0; i < n; ++i) {
        int val = a[i];
        if (val < 1 || val > i + 1 || seen_prefix[val]) {
            prefix_valid = false;
        }
        if (prefix_valid) {
            seen_prefix[val] = true;
            if (val > max_prefix_val) {
                max_prefix_val = val;
            }
            if (max_prefix_val == i + 1) {
                is_prefix_perm[i + 1] = true;
            }
        }
    }

    std::vector<bool> is_suffix_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false);
    int max_suffix_val = 0;
    bool suffix_valid = true;
    for (int i = n - 1; i >= 0; --i) {
        int len = n - i;
        int val = a[i];
        if (val < 1 || val > len || seen_suffix[val]) {
            suffix_valid = false;
        }
        if (suffix_valid) {
            seen_suffix[val] = true;
            if (val > max_suffix_val) {
                max_suffix_val = val;
            }
            if (max_suffix_val == len) {
                is_suffix_perm[len] = true;
            }
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

