int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long N;
        std::cin >> N;
        long long chanek_coins = 0;
        long long opponent_coins = 0;

        while (N > 0) {
            if (N % 2 == 1) { // N is odd
                chanek_coins += 1;
                N -= 1;
            } else { // N is even
                if (N == 2) { // Special case: N=2, Chanek takes 1, N becomes 1. Opponent takes 1.
                    chanek_coins += 1;
                    N -= 1;
                } else if ((N / 2) % 2 == 1) { // N/2 is odd. Taking N/2 leaves an odd number for opponent.
                                               // Taking 1 leaves an odd number for opponent.
                                               // Both moves leave an odd number for opponent.
                                               // Chanek wants to maximize his coins.
                                               // Taking N/2 gives more coins to Chanek.
                    chanek_coins += N / 2;
                    N /= 2;
                } else { // N/2 is even. Taking N/2 leaves an even number for opponent.
                         // Taking 1 leaves an odd number for opponent.
                         // If Chanek takes N/2, opponent gets an even number, can take half.
                         // If Chanek takes 1, opponent gets an odd number, must take 1.
                         // Chanek wants to maximize his coins.
                         // Taking 1 coin is better for Chanek here.
                    chanek_coins += 1;
                    N -= 1;
                }
            }
            if (N == 0) break;

            // Opponent's turn (same logic as Chanek's, but for opponent_coins)
            if (N % 2 == 1) {
                opponent_coins += 1;
                N -= 1;
            } else {
                if (N == 2) {
                    opponent_coins += 1;
                    N -= 1;
                } else if ((N / 2) % 2 == 1) {
                    opponent_coins += N / 2;
                    N /= 2;
                } else {
                    opponent_coins += 1;
                    N -= 1;
                }
            }
        }
        std::cout << chanek_coins << "\n";
    }
    return 0;
}

