#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We want current_sum + S_app = 2 * (current_xor_sum ^ X_app)
    // Let S_app be the sum of appended elements and X_app be the XOR sum of appended elements.

    // Strategy: Append at most 2 elements.
    // Let's try to append two elements, say x and y.
    // New sum: current_sum + x + y
    // New XOR sum: current_xor_sum ^ x ^ y
    // We want: current_sum + x + y = 2 * (current_xor_sum ^ x ^ y)

    // Consider appending two elements: current_xor_sum and current_sum + current_xor_sum.
    // Let b1 = current_xor_sum
    // Let b2 = current_sum + current_xor_sum
    // This strategy is based on the observation that if we append X and S+X,
    // the new XOR sum becomes X_old ^ X ^ (S_old + X)
    // and the new sum becomes S_old + X + (S_old + X) = 2*S_old + 2*X.
    // This doesn't directly lead to S = 2X.

    // A simpler strategy:
    // Append two elements: X_0 and S_0 + X_0.
    // Let X_0 be the current_xor_sum.
    // Let S_0 be the current_sum.
    // We want to find b1, b2 such that:
    // (S_0 + b1 + b2) = 2 * (X_0 ^ b1 ^ b2)

    // Consider appending b1 = X_0.
    // New XOR sum becomes X_0 ^ X_0 = 0.
    // New sum becomes S_0 + X_0.
    // Now we need to append b2 such that:
    // (S_0 + X_0 + b2) = 2 * (0 ^ b2)
    // (S_0 + X_0 + b2) = 2 * b2
    // S_0 + X_0 = b2
    // So, if we append X_0 and (S_0 + X_0), the new array will be good.

    // Let's verify this:
    // Appended elements: b1 = current_xor_sum, b2 = current_sum + current_xor_sum.
    // New sum: S' = current_sum + b1 + b2
    //             = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    //             = 2 * current_sum + 2 * current_xor_sum
    // New XOR sum: X' = current_xor_sum ^ b1 ^ b2
    //                = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    //                = 0 ^ (current_sum + current_xor_sum)
    //                = current_sum + current_xor_sum
    // Check condition: S' = 2 * X'
    // (2 * current_sum + 2 * current_xor_sum) = 2 * (current_sum + current_xor_sum)
    // This is true!

    // So, we can always append two elements: current_xor_sum and current_sum + current_xor_sum.
    // The problem states we can append at most 3 elements. This solution uses 2.
    // The values can be large, up to 10^9 for initial elements, sum can be 10^5 * 10^9 = 10^14.
    // current_sum + current_xor_sum can be up to 10^14 + 10^9, which fits in long long.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we see a 'b', it can be jumped over by any 'a's to its left.
            // Each 'a' to its left will contribute 'count_a' steps when it jumps over this 'b'.
            // The 'b' itself will be duplicated, effectively doubling the number of 'a's that
            // can jump over subsequent 'b's.
            // So, if an 'a' jumps over this 'b', it becomes 'bba'. The 'a' is now followed by 'b'.
            // The 'a' effectively moves past the 'b'.
            // The number of 'a's that can jump over the next 'b' to the left doubles.
            // This is because each 'a' that jumps over this 'b' creates a new 'b' for the 'a's
            // to its left to jump over.
            // More simply, if we have X 'a's to the left of this 'b', they will all jump over it.
            // Each jump costs 1 step. So X steps.
            // After these X 'a's jump over this 'b', the 'b' effectively becomes 2 'b's for the
            // 'a's further to the left.
            // So, the number of 'a's that can jump over the next 'b' to the left doubles.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we see an 'a', it adds to the count of 'a's that are waiting to jump over 'b's.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <map>
#include <utility> // For std::pair

long long combinations_2(long long n) {
    if (n < 2) {
        return 0;
    }
    return n * (n - 1) / 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Count pairs with same x-coordinate
    for (auto const& [x_coord, count] : x_counts) {
        total_pairs += combinations_2(count);
    }

    // Count pairs with same y-coordinate
    for (auto const& [y_coord, count] : y_counts) {
        total_pairs += combinations_2(count);
    }

    // Subtract pairs that have both same x and same y (counted twice)
    for (auto const& [coords, count] : xy_counts) {
        total_pairs -= combinations_2(count);
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

// Function to convert a long long integer to its parity pattern string
// The pattern will always be 18 characters long, padded with '0's from the left
std::string to_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the right to make it 18 characters long
    // This corresponds to padding the number with '0's from the left
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the right to make it 18 characters long
            // This corresponds to padding the pattern with '0's from the left
            while (s.length() < 18) {
                s += '0';
            }
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // Step 1: Deduce '0's in w based on '0's in s
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', then both w[i-x] (if exists) and w[i+x] (if exists) must be '0'.
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce s
    std::string s_prime(n, '0'); // This will be the s generated from our w
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        // Check w[i-x]
        if (i - x >= 0 && w[i - x] == '1') {
            is_one = true;
        }
        // Check w[i+x]
        if (i + x < n && w[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_prime[i] = '1';
        } else {
            s_prime[i] = '0';
        }
    }

    // Compare s_prime with the given s
    if (s_prime == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

