#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            double discriminant = d * d - 4.0 * d;
            if (discriminant < 0) { // Should not happen if d >= 4, but for floating point safety
                std::cout << "N\n";
            } else {
                double sqrt_discriminant = std::sqrt(discriminant);
                double a = (d + sqrt_discriminant) / 2.0;
                double b = (d - sqrt_discriminant) / 2.0;

                // Ensure a and b are non-negative.
                // Since d >= 4, d^2 - 4d >= 0, so sqrt(d^2 - 4d) is real.
                // Also, d >= 0.
                // For a: d + sqrt(d^2 - 4d) >= 0, so a >= 0.
                // For b: d - sqrt(d^2 - 4d). We need to check if this is >= 0.
                // d >= sqrt(d^2 - 4d)
                // d^2 >= d^2 - 4d (since both sides are non-negative, we can square)
                // 0 >= -4d
                // 4d >= 0
                // This is true since d >= 0.
                // So both a and b calculated this way are non-negative.

                std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
            }
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum_w(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum_w[i + 1] = prefix_sum_w[i] + w[i];
    }

    long long min_total_energy = -1;

    // Iterate through all possible counts of items taken from the left side
    // `i` represents the number of items taken from the left
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right side

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum_w[i] * l;

        // Energy for items taken from the right
        // The sum of weights for items taken from the right is
        // (total sum of weights) - (sum of weights of items taken from left)
        // which is prefix_sum_w[n] - prefix_sum_w[i]
        current_energy += (prefix_sum_w[n] - prefix_sum_w[i]) * r;

        // Add penalty for unbalanced counts
        if (i > j) { // More items from left than right
            if (i - j > 1) { // If difference is more than 1, there must have been consecutive left picks
                current_energy += (long long)(i - j - 1) * Ql;
            }
        } else if (j > i) { // More items from right than left
            if (j - i > 1) { // If difference is more than 1, there must have been consecutive right picks
                current_energy += (long long)(j - i - 1) * Qr;
            }
        }

        if (min_total_energy == -1 || current_energy < min_total_energy) {
            min_total_energy = current_energy;
        }
    }

    std::cout << min_total_energy << std::endl;

    return 0;
}

