int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> next_char_pos(L, std::vector<int>(26, -1));
    for (int i = 0; i < L; ++i) {
        for (int j = 0; j < 26; ++j) {
            int current_pos = i;
            int count = 0;
            while (count < L) {
                if (s[current_pos] == 'a' + j) {
                    next_char_pos[i][j] = count;
                    break;
                }
                current_pos = (current_pos + 1) % L;
                count++;
            }
        }
    }

    std::vector<std::vector<int>> next_char_pos_rev(L, std::vector<int>(26, -1));
    for (int i = 0; i < L; ++i) {
        for (int j = 0; j < 26; ++j) {
            int current_pos = i;
            int count = 0;
            while (count < L) {
                if (s[current_pos] == 'a' + j) {
                    next_char_pos_rev[i][j] = count;
                    break;
                }
                current_pos = (current_pos - 1 + L) % L;
                count++;
            }
        }
    }

    std::vector<std::vector<int>> first_occurrence_dist(L, std::vector<int>(26, -1));
    for (int i = 0; i < L; ++i) {
        for (int char_code = 0; char_code < 26; ++char_code) {
            char target_char = 'a' + char_code;
            for (int j = 0; j < L; ++j) {
                if (s[(i + j) % L] == target_char) {
                    first_occurrence_dist[i][char_code] = j;
                    break;
                }
            }
        }
    }

    double total_win_prob = 0.0;

    // Group shifts by their first character
    std::map<char, std::vector<int>> shifts_by_first_char;
    for (int k = 0; k < L; ++k) {
        shifts_by_first_char[s[k]].push_back(k);
    }

    for (auto const& [first_char, k_indices] : shifts_by_first_char) {
        int num_k_for_char = k_indices.size();
        if (num_k_for_char == 0) continue; // Should not happen

        double max_win_prob_for_char = 0.0;

        // Vasya chooses p optimally for this first_char
        for (int p = 1; p < L; ++p) {
            int num_unique_pairs = 0;
            std::map<char, int> char_counts;
            for (int k_idx : k_indices) {
                char second_char = s[(k_idx + p) % L];
                char_counts[second_char]++;
            }
            for (auto const& [second_char, count] : char_counts) {
                if (count == 1) {
                    num_unique_pairs++;
                }
            }
            max_win_prob_for_char = std::max(max_win_prob_for_char, (double)num_unique_pairs / num_k_for_char);
        }
        total_win_prob += max_win_prob_for_char * num_k_for_char;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

