    std::cin >> n;

    if (n == 1) {
        std::cout << "1\n";
        return 0;
    }

    int k = static_cast<int>(std::sqrt(n));
    if (k * k < n) {
        k++;
    }

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; i += k) {
        int start_block = std::max(0, i);
        int end_block = std::min(n, i + k);

        for (int j = end_block - 1; j >= start_block; --j) {
            p[j] = current_val--;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_val0 = 0; // Value if input is 0
    int current_val1 = 1023; // Value if input is 1023 (all bits set for 10 bits)

    for (int k = 0; k < n; ++k) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val0 &= x;
            current_val1 &= x;
        } else if (op_char == '|') {
            current_val0 |= x;
            current_val1 |= x;
        } else if (op_char == '^') {
            current_val0 ^= x;
            current_val1 ^= x;
        }
    }

    int final_and_mask = 1023; // All bits initially 1
    int final_or_mask = 0;    // All bits initially 0
    int final_xor_mask = 0;   // All bits initially 0

    for (int i = 0; i < 10; ++i) {
        int bit0_i = (current_val0 >> i) & 1;
        int bit1_i = (current_val1 >> i) & 1;

        if (bit0_i == 0 && bit1_i == 0) {
            // If input bit is 0, output bit is 0. If input bit is 1, output bit is 0.
            // This means the bit is always 0, regardless of input.
            // To achieve this: AND with 0, OR with 0, XOR with 0.
            // Effectively, we need to force this bit to 0.
            final_and_mask &= ~(1 << i); // Set i-th bit of AND mask to 0
        } else if (bit0_i == 1 && bit1_i == 1) {
            // If input bit is 0, output bit is 1. If input bit is 1, output bit is 1.
            // This means the bit is always 1, regardless of input.
            // To achieve this: AND with 1, OR with 1, XOR with 0.
            // Effectively, we need to force this bit to 1.
            final_or_mask |= (1 << i); // Set i-th bit of OR mask to 1
        } else if (bit0_i == 0 && bit1_i == 1) {
            // If input bit is 0, output bit is 0. If input bit is 1, output bit is 1.
            // This means the bit is unchanged.
            // To achieve this: AND with 1, OR with 0, XOR with 0.
            // No change needed for this bit in final_and_mask, final_or_mask, final_xor_mask.
        } else if (bit0_i == 1 && bit1_i == 0) {
            // If input bit is 0, output bit is 1. If input bit is 1, output bit is 0.
            // This means the bit is flipped.
            // To achieve this: AND with 1, OR with 0, XOR with 1.
            final_xor_mask |= (1 << i); // Set i-th bit of XOR mask to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_mask != 1023) { // If any bit needs to be forced to 0
        result_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) { // If any bit needs to be forced to 1
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) { // If any bit needs to be flipped
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <algorithm>

long long binToDec(const std::string& s, int start, int end) {
    long long val = 0;
    long long power = 1;
    for (int i = end; i >= start; --i) {
        if (s[i] == '1') {
            val += power;
        }
        if (power > 2000000000000000000LL / 2) { // Prevent overflow for power itself
            if (i > start) return 2000000000000000000LL; // Value will exceed max_len, so return a large number
        }
        power *= 2;
    }
    return val;
}

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long count = 0;

    // Max length of s is 2e5.
    // Max value of f(s_l...s_r) is 2e5.
    // 2^17 = 131072, 2^18 = 262144.
    // So, if s_l is '1', the substring length can be at most 18.
    // If s_l is '0', it can have leading zeros.

    // Iterate through all possible starting positions l
    for (int l = 0; l < n; ++l) {
        // Case 1: Substring starts with '1'
        if (s[l] == '1') {
            long long current_val = 0;
            for (int r = l; r < n; ++r) {
                int len = r - l + 1;

                // Calculate current_val for s[l...r]
                // current_val = current_val * 2 + (s[r] - '0');
                // Check for overflow before multiplication
                if (current_val > (200000 - (s[r] - '0')) / 2) { // If current_val * 2 + (s[r]-'0') would exceed 200000
                    break; // Further increasing length will only increase value, so it won't match
                }
                current_val = current_val * 2 + (s[r] - '0');

                if (current_val > 200000) { // Max possible length is 2e5
                    break;
                }
                if (current_val == len) {
                    count++;
                }
            }
        } else { // Case 2: Substring starts with '0'
            // We need to find the first '1' to determine the actual binary value.
            // Let's say s[l...k-1] are all '0's and s[k] is '1'.
            // The value of s[l...r] is f(s[k...r]).
            // The length is r - l + 1.
            // We need r - l + 1 = f(s[k...r]).

            // Find the first '1' from l
            int first_one_idx = -1;
            for (int k = l; k < n; ++k) {
                if (s[k] == '1') {
                    first_one_idx = k;
                    break;
                }
            }

            if (first_one_idx == -1) { // All zeros from l to n-1
                // No '1' found, so f(s[l...r]) will always be 0.
                // We need r - l + 1 = 0, which is impossible for a non-empty string.
                // So no good substrings starting with '0' if all subsequent chars are '0'.
                break; // No more '1's in the string, so no more good substrings.
            }

            // Now, first_one_idx is the index of the first '1' after or at l.
            // The value of s[l...r] is f(s[first_one_idx...r]).
            // The length is r - l + 1.
            // We need r - l + 1 = f(s[first_one_idx...r]).

            long long current_val = 0;
            for (int r = first_one_idx; r < n; ++r) {
                // Calculate current_val for s[first_one_idx...r]
                if (current_val > (200000 - (s[r] - '0')) / 2) {
                    break;
                }
                current_val = current_val * 2 + (s[r] - '0');

                if (current_val > 200000) {
                    break;
                }

                // Now check the condition: r - l + 1 == current_val
                // The length of the substring is (r - l + 1).
                // The value is current_val (which is f(s[first_one_idx...r])).

                // The number of leading zeros is first_one_idx - l.
                // The length of the significant part (from first_one_idx to r) is r - first_one_idx + 1.
                // The total length is (first_one_idx - l) + (r - first_one_idx + 1).
                // We need (first_one_idx - l) + (r - first_one_idx + 1) == current_val.

                // The maximum value of current_val is 2e5.
                // The maximum number of leading zeros (first_one_idx - l) can be up to 2e5.
                // The maximum length of the significant part (r - first_one_idx + 1) is about 18.
                // So, the total length can be up to 2e5.

                // The condition is: (r - l + 1) == current_val
                // This means: (first_one_idx - l) + (r - first_one_idx + 1) == current_val

                // The number of leading zeros is `zeros_count = first_one_idx - l`.
                // The length of the binary number part is `binary_len = r - first_one_idx + 1`.
                // Total length `total_len = zeros_count + binary_len`.
                // We need `total_len == current_val`.

                // The maximum value of current_val is 2e5.
                // The maximum length of the binary part (r - first_one_idx + 1) is about 18.
                // So, the number of leading zeros (first_one_idx - l) must be approximately current_val - 18.
                // This means first_one_idx - l must be non-negative.
                // And first_one_idx - l must be less than or equal to current_val - 1.
                // (Since current_val >= 1, and binary_len >= 1).

                // The number of leading zeros is `first_one_idx - l`.
                // The length of the substring from `first_one_idx` to `r` is `r - first_one_idx + 1`.
                // The total length of `s[l...r]` is `(first_one_idx - l) + (r - first_one_idx + 1)`.

                // We need `(first_one_idx - l) + (r - first_one_idx + 1) == current_val`.
                // This is equivalent to `(r - first_one_idx + 1) == current_val - (first_one_idx - l)`.
                // Let `len_binary_part = r - first_one_idx + 1`.
                // Let `num_leading_zeros = first_one_idx - l`.
                // We need `len_binary_part + num_leading_zeros == current_val`.

                // The number of leading zeros must be non-negative.
                // `num_leading_zeros = current_val - len_binary_part`.
                // So, `current_val - len_binary_part >= 0`.
                // And `num_leading_zeros` must be exactly `first_one_idx - l`.

                // So, we need to check if `current_val - (r - first_one_idx + 1)` is a valid number of leading zeros.
                // Let `required_leading_zeros = current_val - (r - first_one_idx + 1)`.
                // If `required_leading_zeros >= 0` AND `required_leading_zeros == (first_one_idx - l)`, then it's a match.
                // This simplifies to `l == first_one_idx - required_leading_zeros`.
                // Or simply `l == first_one_idx - (current_val - (r - first_one_idx + 1))`.

                // Let's re-evaluate the condition:
                // `r - l + 1 == current_val`
                // `l = r + 1 - current_val`
                // We need to check if this `l` is valid.
                // 1. `l >= 0` (start index must be non-negative)
                // 2. `l <= first_one_idx` (all characters from `l` to `first_one_idx - 1` must be '0')
                //    This is implicitly handled by how `first_one_idx` is found.
                //    If `l` calculated this way is less than `first_one_idx`, it means there are `first_one_idx - l` leading zeros.
                //    And we know `s[l...first_one_idx-1]` are all '0's because we started iterating `l` from `0` and found `first_one_idx`.
                //    So, we just need to check if `l` is valid and `l <= first_one_idx`.

                int potential_l = r + 1 - static_cast<int>(current_val);
                if (potential_l >= 0 && potential_l <= first_one_idx) {
                    count++;
                }
            }
            // After processing all r for the current first_one_idx,
            // we can skip to first_one_idx + 1 for the next l.
            // This optimization is crucial.
            l = first_one_idx; // The outer loop will increment l to first_one_idx + 1
        }
    }
    std::cout << count << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> L(n, 0), R(n, 0);

    // Calculate L_i: length of consecutive 0s ending at i, or 1s starting at i
    // L_i = k means a[i-k+1 ... i] are all 0s, and a[i-k] is 1 (or i-k < 0)
    // L_i = k means a[i ... i+k-1] are all 1s, and a[i+k] is 0 (or i+k >= n)
    // For 0s: L[i] is the length of the block of 0s ending at i.
    // For 1s: R[i] is the length of the block of 1s starting at i.

    // L[i] for 0s
    if (a[0] == 0) L[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            L[i] = L[i - 1] + 1;
        } else {
            L[i] = 0;
        }
    }

    // R[i] for 1s
    if (a[n - 1] == 1) R[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 1) {
            R[i] = R[i + 1] + 1;
        } else {
            R[i] = 0;
        }
    }

    int max_steps = 0;
    std::vector<int> final_a = a;

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0 && a[i - 1] == 1 && a[i + 1] == 1) { // 101 pattern
            int len_left_1 = R[i - 1]; // Length of 1s block ending at i-1
            int len_right_1 = L[i + 1]; // Length of 1s block starting at i+1 (this is wrong, should be R[i+1])
                                        // Correct: R[i-1] is length of 1s block starting at i-1.
                                        // L[i+1] is length of 0s block ending at i+1.
                                        // We need length of 1s block starting at i+1. This is R[i+1].

            // Let's re-evaluate L and R for the purpose of finding 1s blocks and 0s blocks.
            // L_i: length of consecutive identical values ending at i.
            // R_i: length of consecutive identical values starting at i.

            // Recalculate L and R to be general for blocks of same values
            std::vector<int> L_gen(n, 0), R_gen(n, 0);

            L_gen[0] = 1;
            for (int k = 1; k < n; ++k) {
                if (a[k] == a[k - 1]) {
                    L_gen[k] = L_gen[k - 1] + 1;
                } else {
                    L_gen[k] = 1;
                }
            }

            R_gen[n - 1] = 1;
            for (int k = n - 2; k >= 0; --k) {
                if (a[k] == a[k + 1]) {
                    R_gen[k] = R_gen[k + 1] + 1;
                } else {
                    R_gen[k] = 1;
                }
            }

            // Now, for a[i] = 0, a[i-1] = 1, a[i+1] = 1:
            // len_left_1 is L_gen[i-1] (length of 1s block ending at i-1)
            // len_right_1 is R_gen[i+1] (length of 1s block starting at i+1)

            int len_left_1 = L_gen[i - 1];
            int len_right_1 = R_gen[i + 1];

            int min_len = std::min(len_left_1, len_right_1);
            int current_steps = (min_len + 1) / 2;
            max_steps = std::max(max_steps, current_steps);

            if (len_left_1 == len_right_1) {
                // If lengths are equal, the middle 0s become 1s.
                // The middle element a[i] becomes 1.
                // The final state of a[i] is 1.
                final_a[i] = 1;
            } else if (len_left_1 < len_right_1) {
                // Left block is shorter, 0s propagate right.
                // The final state of a[i] is 0.
                // The 1s from the left will turn into 0s up to i - len_left_1 + 1.
                // The 0s from the right will turn into 1s up to i + len_left_1.
                // The middle element a[i] becomes 0.
                // This means the 0 at index i will remain 0.
            } else { // len_left_1 > len_right_1
                // Right block is shorter, 0s propagate left.
                // The final state of a[i] is 0.
                // The 1s from the right will turn into 0s up to i + len_right_1 - 1.
                // The 0s from the left will turn into 1s up to i - len_right_1.
                // The middle element a[i] becomes 0.
                // This means the 0 at index i will remain 0.
            }
        } else if (a[i] == 1 && a[i - 1] == 0 && a[i + 1] == 0) { // 010 pattern
            int len_left_0 = L_gen[i - 1]; // Length of 0s block ending at i-1
            int len_right_0 = R_gen[i + 1]; // Length of 0s block starting at i+1

            int min_len = std::min(len_left_0, len_right_0);
            int current_steps = (min_len + 1) / 2;
            max_steps = std::max(max_steps, current_steps);

            if (len_left_0 == len_right_0) {
                // If lengths are equal, the middle 1s become 0s.
                // The final state of a[i] is 0.
                final_a[i] = 0;
            } else if (len_left_0 < len_right_0) {
                // Left block is shorter, 1s propagate right.
                // The final state of a[i] is 1.
            } else { // len_left_0 > len_right_0
                // Right block is shorter, 1s propagate left.
                // The final state of a[i] is 1.
            }
        }
    }

    std::cout << max_steps << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
