    std::cin.tie(NULL);
    int n;
    long long m;
    std::cin >> n >> m;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1; // Maximum possible operations is m-1

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        bool possible = true;
