            long long current_b;

            // Case 1: a_i + mid >= prev_b
            // This means we can achieve b_i = a_i + x_i where x_i <= mid
            // and b_i >= prev_b.
            // The smallest possible b_i is max(prev_b, a_i).
            // If a_i >= prev_b, we can just use a_i (x_i=0).
            // If a_i < prev_b, we need to increment a_i to at least prev_b.
            // This requires x_i = prev_b - a_i operations.
            // If prev_b - a_i <= mid, then it's possible.
            // In this case, current_b = prev_b.

            // Case 2: a_i + mid < prev_b
            // This means we must use the wrap-around.
            // We need to achieve b_i = (a_i + x_i) % m >= prev_b.
            // The smallest value we can achieve is a_i.
            // The largest value we can achieve without wrap-around is a_i + mid.
            // If a_i + mid < prev_b, then we must use wrap-around.
            // This means b_i must be >= prev_b, and b_i is (a_i + x_i) % m.
            // The values we can achieve are [a_i, a_i+mid] (modulo m).
            // If a_i + mid < prev_b, then we must have a_i + x_i >= m.
            // The smallest such b_i is a_i.
            // If a_i >= prev_b, then we can set b_i = a_i. This requires x_i = 0.
            // If a_i < prev_b, then we need to increment a_i.
            // We can increment a_i to (a_i + x_i) % m.
            // If a_i + mid >= prev_b, we can choose b_i = prev_b.
            // This requires x_i = prev_b - a_i. This is valid if prev_b - a_i <= mid.
            // If a_i + mid < prev_b, then we cannot make a_i become prev_b without wrap-around.
            // We must use wrap-around.
            // The values we can achieve are [a_i, a_i+mid] (mod m).
            // If a_i + mid < prev_b, it means that all values in [a_i, a_i+mid] are less than prev_b.
            // This is only true if a_i itself is less than prev_b.
            // If a_i < prev_b and a_i + mid < prev_b, then we cannot satisfy b_i >= prev_b.
            // This is because all values (a_i + x) % m for x <= mid will be less than prev_b.
            // Example: m=7, a_i=0, mid=1, prev_b=6.
            // a_i + mid = 1. prev_b = 6. 1 < 6.
            // Values we can get: (0+0)%7=0, (0+1)%7=1. Neither is >= 6.
            // So, if a_i < prev_b AND (a_i + mid) % m < prev_b (and a_i + mid doesn't wrap around to be >= prev_b),
            // then it's impossible.

            // Let's simplify:
            // We need to find x_i such that 0 <= x_i <= mid and (a_i + x_i) % m >= prev_b.
            // If a_i >= prev_b:
            //   We can choose x_i = 0, so b_i = a_i. This is valid.
            //   So, current_b = a_i.
            // Else (a_i < prev_b):
            //   We need to increment a_i.
            //   We need (a_i + x_i) % m >= prev_b.
            //   The smallest value we can achieve is a_i.
            //   The largest value we can achieve is (a_i + mid) % m.
            //   If we can reach prev_b without wrapping around:
            //     i.e., a_i + mid >= prev_b.
            //     Then we can choose x_i = prev_b - a_i. Since prev_b - a_i <= mid, this is valid.
            //     So, current_b = prev_b.
            //   Else (a_i + mid < prev_b):
            //     This means even with mid increments, we cannot reach prev_b without wrapping.
            //     And if we wrap, (a_i + x_i) % m will be small.
            //     Specifically, if a_i < prev_b and a_i + mid < prev_b, then all values (a_i + x_i) % m for x_i <= mid
            //     will be in the range [a_i, a_i + mid], which are all less than prev_b.
            //     So, it's impossible.
            //     Set possible = false.

            if (current_a >= prev_b) {
                // We can potentially keep current_a as b_i.
                // If we increment current_a by mid, it becomes (current_a + mid) % m.
                // If (current_a + mid) % m < prev_b, it means we *must* increment current_a
                // to at least prev_b, but we can't.
                // This happens if current_a + mid wraps around and becomes smaller than prev_b.
                // Example: m=7, a_i=6, mid=1, prev_b=0.
                // a_i >= prev_b (6 >= 0).
                // (a_i + mid) % m = (6+1)%7 = 0. This is >= prev_b. So current_b = prev_b = 0.
                // Example: m=7, a_i=0, mid=1, prev_b=6.
                // a_i < prev_b (0 < 6).
                // a_i + mid = 1. prev_b = 6. 1 < 6. Impossible.

                // If a_i >= prev_b, we can choose b_i = a_i (x_i=0). This is valid.
                // So, current_b = a_i.
                current_b = current_a;
            } else { // current_a < prev_b
                // We must increment current_a.
                // We need (current_a + x_i) % m >= prev_b.
                // The smallest x_i to make (current_a + x_i) % m >= prev_b is prev_b - current_a.
                // If prev_b - current_a <= mid, then we can achieve prev_b.
                // So, current_b = prev_b.
                if (current_a + mid >= prev_b) { // This means prev_b - current_a <= mid
                    current_b = prev_b;
                } else {
                    // Even with mid increments, we cannot reach prev_b without wrapping.
                    // And if we wrap, (current_a + x_i) % m will be small.
                    // Specifically, if current_a < prev_b and current_a + mid < prev_b,
                    // then all values (current_a + x_i) % m for x_i <= mid
                    // will be in the range [current_a, current_a + mid], which are all less than prev_b.
                    possible = false;
                    break;
                }
            }
            prev_b = current_b;
        }

        if (possible) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// In the worst case, y could be n * max(a_i) which is 2*10^5 * 10^9 = 2*10^14.
// x can also be large, but it's constrained by n.
// The values a_x are used as offsets, so they can be large.

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1); // a[0] is unused, a[1] will be set for each run
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    // dp_val[i] stores the total y accumulated and dp_x[i] stores the final x
    // when starting at position i with an 'add' operation.
    // This is for the second type of move (x = x + a_x, y = y + a_x).
    // We need to compute this for all possible x values.
    std::vector<long long> dp_val(n + 1, -2); // -2 indicates not computed
    std::vector<long long> dp_x(n + 1, -2);   // -2 indicates not computed

    // Function to compute dp_val[start_x] and dp_x[start_x]
    // This function computes the result of the sequence of operations
    // starting from x = start_x, with the first operation being 'add'.
    // It returns a pair: {final_y_increment, final_x_position}.
    // If it loops, it returns {-1, -1}.
    auto solve_from_add = [&](int start_x, const std::vector<long long>& current_a) {
        if (start_x <= 0 || start_x > n) {
            return std::make_pair(0LL, (long long)start_x); // Already terminated
        }
        if (dp_val[start_x] != -2) {
            return std::make_pair(dp_val[start_x], dp_x[start_x]);
        }

        // Mark as currently computing to detect cycles
        dp_val[start_x] = -1; // Sentinel for cycle detection
        dp_x[start_x] = -1;   // Sentinel for cycle detection

        long long current_y_inc = 0;
        long long current_x = start_x;

        // First operation: x = x + a_x, y = y + a_x
        long long val_add = current_a[current_x];
        current_x += val_add;
        current_y_inc += val_add;

        if (current_x <= 0 || current_x > n) {
            dp_val[start_x] = current_y_inc;
            dp_x[start_x] = current_x;
            return std::make_pair(current_y_inc, current_x);
        }

        // Second operation: x = x - a_x, y = y + a_x
        long long val_sub = current_a[current_x];
        current_x -= val_sub;
        current_y_inc += val_sub;

        if (current_x <= 0 || current_x > n) {
            dp_val[start_x] = current_y_inc;
            dp_x[start_x] = current_x;
            return std::make_pair(current_y_inc, current_x);
        }

        // Now we are at current_x, and the next operation will be 'add'.
        // This is exactly the state that dp_val[current_x] and dp_x[current_x] represent.
        auto next_result = solve_from_add(current_x, current_a);

        if (next_result.first == -1) { // Cycle detected
            dp_val[start_x] = -1;
            dp_x[start_x] = -1;
            return std::make_pair(-1LL, -1LL);
        } else {
            dp_val[start_x] = current_y_inc + next_result.first;
            dp_x[start_x] = next_result.second;
            return std::make_pair(dp_val[start_x], dp_x[start_x]);
        }
    };

    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a_1 for the current run

        // Reset DP table for each run.
        // This is crucial because a[1] changes, which affects the entire graph.
        // A more optimized approach might be possible if a[1] only affects paths
        // that involve a[1], but the problem structure implies a full reset.
        // Given N=2e5, N*N operations for DP reset is too slow.
        // However, the DP state is only for 'add' operations.
        // The actual path for each i is short.
        // The total number of states visited across all i is what matters.
        // A single run of solve_from_add(1, a) will compute all necessary DP states
        // for the current a[1].
        // The DP table should be cleared for each i.
        // But wait, the problem states "run the program on the sequence i, a_2, a_3, ..., a_n".
        // This means a_1 is set to i, and a_2...a_n are fixed.
        // The DP states (dp_val[j], dp_x[j]) depend on a_j.
        // If a_1 changes, then any path that goes through a_1 will be affected.
        // But the DP states are for starting at *any* x.
        // If we start at x=1, and a[1] is i, then the path is 1 -> 1+i -> (1+i)-a[1+i] -> ...
        // The DP states for x > 1 are independent of a[1].
        // So, we only need to clear dp_val[1] and dp_x[1] for each run.
        // The other states (dp_val[j], dp_x[j] for j > 1) are constant across all runs.
        // This is the key optimization.

        // Initialize dp_val and dp_x for j > 1 only once.
        // For j = 1, it's specific to the current 'i'.
        // Let's re-evaluate the DP state definition.
        // dp_val[j] and dp_x[j] store the result of starting at 'j' with an 'add' operation.
        // This means the first value used is a[j].
        // If j > 1, a[j] is fixed. So dp_val[j] and dp_x[j] are fixed.
        // If j = 1, a[1] changes. So dp_val[1] and dp_x[1] change.

        // We can compute dp_val and dp_x for j = 2 to n once.
        // Then for each i, we compute for j = 1.

        // Let's use a separate DP table for each run, but only for the current path.
        // This is essentially memoized recursion.
        // The problem is that the values a_x are used.
        // If a_1 changes, then the path from 1 changes.
        // If the path from 1 goes to some x_k, and then from x_k it goes to x_k + a[x_k],
        // then the value a[x_k] is used.
        // The DP states are for starting at a given x, and then performing the 'add' operation.
        // So, dp_val[x] and dp_x[x] are the total y and final x if we start at x,
        // perform x = x + a[x], y = y + a[x], then x = x - a[x_new], y = y + a[x_new],
        // and then continue from the new x with an 'add' operation.

        // The DP states for x > 1 are independent of a[1].
        // So, we can compute them once.
        // For x = 1, we compute it for each i.

        // Reset dp_val and dp_x for the current run.
        // This is not efficient enough if done for all N states.
        // The total number of states visited by the recursive function `solve_from_add`
        // for a single call `solve_from_add(1, a)` is at most N.
        // If we clear the entire DP table for each `i`, it's O(N^2).
        // We need to clear only the states that are part of the current path.
        // Or, we can use a `visited` set for cycle detection and clear it.
        // The `dp_val` and `dp_x` arrays should be initialized to -2 (uncomputed).
        // When `solve_from_add` is called, it will compute and store.
        // If `a[1]` changes, then `solve_from_add(1, a)` needs to be recomputed.
        // But `solve_from_add(j, a)` for `j > 1` does not need to be recomputed.
        // So, we can initialize `dp_val` and `dp_x` to -2 once.
        // Then, for each `i`, we set `a[1] = i`, and call `solve_from_add(1, a)`.
        // The `solve_from_add` function will use the precomputed values for `j > 1`.
        // The only state that needs to be explicitly reset for each `i` is `dp_val[1]` and `dp_x[1]`.
        // But if `solve_from_add(1, a)` is called, it will overwrite `dp_val[1]` and `dp_x[1]` anyway.
        // The issue is cycle detection. If `dp_val[1]` is set to -1 (computing), and then `solve_from_add(1, a)` is called again, it will detect a cycle.
        // This is correct for a single run.
        // The problem is that `dp_val[1]` might be set to a final value from a previous `i`.
        // So, for each `i`, we must ensure `dp_val[1]` and `dp_x[1]` are marked as uncomputed.

        dp_val[1] = -2; // Mark as uncomputed for the current a[1]
        dp_x[1] = -2;   // Mark as uncomputed for the current a[1]

        auto result = solve_from_add(1, a);
        std::cout << result.first << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, LLONG_MAX); // Represents a_0[i]

    // For each type 2 query, we know that max(a_0[j] + delta[j]) = m.
    // This implies a_0[j] <= m - delta[j] for all j in [l, r].
    // We want to find the largest possible a_0[j] that satisfies this.
    // To do this, we iterate through the operations in reverse.
    // When we encounter a type 2 query, we update the upper bound for a_0[j].
    // When we encounter a type 1 query, we adjust the delta values.

    std::vector<long long> current_delta(n, 0); // Sum of d values applied to a[i] from future operations

    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 2) {
            // Type 2: max(a_j) = m_i
            // For all j in [l, r], a_0[j] + current_delta[j] <= m_i
            // So, a_0[j] <= m_i - current_delta[j]
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_delta[j]);
            }
        } else {
            // Type 1: a_j += d_i
            // This operation happened *before* the current point in time.
            // So, if we are looking at a_0, this d_i is part of the 'past' operations.
            // When we go backwards, this d_i is removed from the 'future' delta.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] -= ops[i].val;
            }
        }
    }

    // If initial_a[j] is still LLONG_MAX, it means no type 2 query constrained it.
    // We can set it to 0, as it satisfies |a_i| <= 10^9.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == LLONG_MAX) {
            initial_a[i] = 0;
        }
    }

    // Now, verify the solution.
    // Apply all operations in forward order to the reconstructed initial_a.
    // Check if all type 2 queries are satisfied.

    std::vector<long long> a = initial_a;
    std::vector<long long> actual_delta(n, 0); // Sum of d values applied to a[i] from past operations

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            // Type 1: a_j += d_i
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                a[j] += ops[i].val;
                actual_delta[j] += ops[i].val;
            }
        } else {
            // Type 2: max(a_j) = m_i
            long long max_val = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, a[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
            // Also, check if any a_0[j] + actual_delta[j] > m_i for j outside [l,r]
            // This is implicitly handled by the initial_a[j] <= m_i - current_delta[j] logic.
            // The initial_a[j] values are upper bounded by all m_i - current_delta[j] for ranges [l,r] that contain j.
            // If max_val == ops[i].val, it means there is at least one j in [l,r] such that a_0[j] + actual_delta[j] == m_i.
            // And for all other k in [l,r], a_0[k] + actual_delta[k] <= m_i.
            // This is exactly what the reverse pass ensures.
        }
    }

    // Final check for initial_a values: |a_i| <= 10^9
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] > 1000000000LL || initial_a[i] < -1000000000LL) {
            // This case should ideally not be reached if the problem guarantees a solution exists within bounds,
            // or if the constraints on m_i and d_i are such that initial_a[i] won't exceed this.
            // Given m_i is up to 5*10^7 and d_i up to 10^4, and m up to 5000,
            // current_delta can be up to 5000 * 10^4 = 5*10^7.
            // So m_i - current_delta[j] can be 5*10^7 - (-5*10^7) = 10^8, or -5*10^7 - (5*10^7) = -10^8.
            // These values are well within [-10^9, 10^9].
            // So this check is mostly for robustness, but should not fail.
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a, b;
    std::cin >> a >> b;

    int ones_a = 0;
    for (char c : a) {
        if (c == '1') {
            ones_a++;
        }
    }

    int ones_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_b++;
        }
    }

    // Calculate parity of initial 'a'
    int parity_a = ones_a % 2;

    // Calculate parity of initial 'b'
    int parity_b = ones_b % 2;

    // Condition 1: The number of ones in 'a' must be less than or equal to the number of ones in 'b'.
    // If ones_a > ones_b, it's impossible to form 'b' from 'a' by only adding characters or removing characters.
    // When we add a character, it's either '0' or '1'. If it's '0', ones_a doesn't change. If it's '1', ones_a increases.
    // When we remove a character, ones_a can only decrease or stay the same.
    // So, if initial ones_a > ones_b, it's impossible.
    if (ones_a > ones_b) {
        std::cout << "NO\n";
        return 0;
    }

    // Condition 2: The length of 'a' must be less than or equal to the length of 'b'.
    // If |a| > |b|, we would need to remove characters from 'a'.
    // The maximum number of '1's we can have in 'a' after removing characters is ones_a.
    // If we remove characters, the number of '1's can only decrease or stay the same.
    // If |a| > |b|, we must remove at least |a| - |b| characters.
    // The string 'b' must be a suffix of some 'a'' that can be generated from 'a'.
    // The length of 'a' can only increase by appending parity.
    // If |a| > |b|, we must remove characters from 'a' to match 'b's length.
    // The number of ones in 'a' after removing characters must be exactly ones_b.
    // This is covered by the logic below.

    // The core idea:
    // We can always append parity(a) to 'a'. This increases length by 1.
    // We can always remove the first character of 'a'. This decreases length by 1.
    // The crucial observation is that we can always make the length of 'a' equal to |b|
    // by a combination of appending parity and removing the first character.
    // For example, if |a| < |b|, we append |b| - |a| parities.
    // If |a| > |b|, we remove |a| - |b| characters from the beginning.
    // The question is whether the resulting string (after length adjustment) has the same parity as 'b'.

    // Let's consider the total number of '1's we can achieve in 'a' if we append parities until its length is at least |b|.
    // Each time we append a '1', ones_a increases by 1.
    // Each time we append a '0', ones_a stays the same.
    // The maximum number of '1's we can have in 'a' is its current ones_a plus the number of '1's we append.
    // The number of '1's we can append is at most the number of characters we append.
    // We can append characters until 'a' has length |b|.
    // If current |a| < |b|, we need to append |b| - |a| characters.
    // The maximum number of '1's we can get in 'a' is ones_a + (length_after_appends - current_length_a).
    // This is equivalent to ones_a + (length_b - length_a).
    // Let's call this `max_ones_possible_at_length_b`.
    int max_ones_possible_at_length_b = ones_a + (a.length() % 2); // Parity of initial 'a'
    // If a.length() is odd, parity_a is 1. If a.length() is even, parity_a is 0.
    // This is not correct. The parity is based on the count of '1's, not length.

    // The number of ones in 'a' can be increased by at most 1 for each character appended.
    // The maximum number of ones in 'a' after appending characters until its length is |b|
    // (or more, then truncating from the front) is `ones_a + (length_of_a_after_appends - initial_length_a)`.
    // The minimum length of 'a' we need to consider is |b|.
    // If we append characters to 'a' until its length is |b|, the number of '1's will be:
    // `ones_a` (initial) + `number of '1's appended`.
    // The number of '1's appended is `(b.length() - a.length())` if all appended characters were '1'.
    // This is the maximum possible `ones_a` if we only append.
    // So, `max_ones_a_after_appends = ones_a + std::max(0, (int)b.length() - (int)a.length())`.
    // This is the maximum number of ones we can achieve in 'a' if we only append characters.
    // However, we can also remove characters from the front.
    // The key insight is that we can always make the length of 'a' equal to |b|.
    // After making the length equal to |b|, we need to check if the parity matches.

    // Let's consider the parity of 'a' after it has been potentially extended to length |b| or more,
    // and then truncated from the front to length |b|.
    // The number of '1's in 'a' can be `ones_a`.
    // If `parity_a` is 1, we can append '1'. `ones_a` becomes `ones_a + 1`.
    // If `parity_a` is 0, we can append '0'. `ones_a` stays `ones_a`.
    // So, `ones_a` can become `ones_a` or `ones_a + 1` after one append operation.
    // This means the parity of `ones_a` can flip or stay the same.
    // Specifically, `(ones_a + parity_a) % 2` is the new parity.
    // If `parity_a` is 0, `(ones_a + 0) % 2 = ones_a % 2`. Parity stays same.
    // If `parity_a` is 1, `(ones_a + 1) % 2`. Parity flips.

    // The number of '1's in 'a' can be `ones_a`.
    // If we append `k` characters, the number of '1's can be anywhere from `ones_a` to `ones_a + k`.
    // This is not quite right. The appended character is determined by the current parity.
    // Let `current_ones` be the number of ones in `a`.
    // If `current_ones % 2 == 0`, we append '0'. `current_ones` remains `current_ones`.
    // If `current_ones % 2 == 1`, we append '1'. `current_ones` becomes `current_ones + 1`.
    // So, if `current_ones` is even, it stays even. If `current_ones` is odd, it becomes even.
    // This means after the first append operation (if `ones_a` is odd), all subsequent appends will be '0's.
    // Example: 01011 (3 ones, odd) -> 010111 (4 ones, even) -> 0101110 (4 ones, even) -> 01011100 (4 ones, even) ...
    // Example: 0011 (2 ones, even) -> 00110 (2 ones, even) -> 001100 (2 ones, even) ...

    // So, the number of ones in 'a' can be `ones_a` (if `ones_a` is even) or `ones_a + 1` (if `ones_a` is odd).
    // Let `final_ones_a` be the number of ones in 'a' after all possible appends.
    // `final_ones_a = ones_a` if `ones_a % 2 == 0`.
    // `final_ones_a = ones_a + 1` if `ones_a % 2 == 1`.
    // This `final_ones_a` is the number of ones in 'a' if we append characters until its length is arbitrarily large.
    // The parity of this `final_ones_a` will always be 0 (even).
    // This is the number of ones in the "longest possible" string `a` that we can generate.
    // Let's call this `effective_ones_a`.
    int effective_ones_a = ones_a;
    if (effective_ones_a % 2 != 0) { // If initial 'a' has odd number of ones
        effective_ones_a++; // It can become even by appending a '1'
    }
    // Now, `effective_ones_a` is the number of '1's in `a` after at most one '1' has been appended,
    // and then only '0's are appended.
    // The length of `a` can be increased to `b.length()`.
    // The number of '1's in `a` after this process will be `effective_ones_a`.

    // We need to check two conditions:
    // 1. The number of '1's in `b` (`ones_b`) must be less than or equal to `effective_ones_a`.
    //    This is because `effective_ones_a` represents the maximum number of '1's we can have in `a`
    //    if we only append characters. If `ones_b` is greater, it's impossible.
    // 2. The parity of `ones_b` must be the same as the parity of `effective_ones_a`.
    //    Since `effective_ones_a` is always even, `ones_b` must also be even.
    //    This is because once `effective_ones_a` is reached, any further appends are '0's,
    //    and any removals from the front don't change the parity of the *total* number of '1's
    //    that *could* be in the string if it were long enough.
    //    The crucial part is that we can always remove characters from the front.
    //    If `effective_ones_a` is the number of ones in the "source" string (after appends),
    //    and `ones_b` is the number of ones in the target string, then `ones_b` must be
    //    less than or equal to `effective_ones_a`.
    //    Also, `ones_b` and `effective_ones_a` must have the same parity.
    //    Since `effective_ones_a` is always even, `ones_b` must also be even.

    // Let's re-evaluate the parity logic.
    // The number of ones in `a` can be `ones_a`.
    // If `ones_a` is odd, we can append '1'. `a` becomes `a + '1'`. `ones_a` becomes `ones_a + 1`.
    // If `ones_a` is even, we can append '0'. `a` becomes `a + '0'`. `ones_a` remains `ones_a`.
    // After this, `ones_a` is always even.
    // Any subsequent appends will be '0's, so `ones_a` will remain even.
    // So, the number of '1's in the "extended" string `a` (before removing prefix) will be `ones_a` (if initial `ones_a` was even) or `ones_a + 1` (if initial `ones_a` was odd).
    // Let this value be `final_ones_count_in_a`.
    // `final_ones_count_in_a = ones_a + (ones_a % 2);`
    // This `final_ones_count_in_a` is always even.

    // Now, we need to check if `b` can be a suffix of such an extended `a`.
    // The length of `b` must be less than or equal to the length of `a` after appends.
    // We can always make `a` long enough by appending characters.
    // The number of '1's in `b` (`ones_b`) must be less than or equal to `final_ones_count_in_a`.
    // And `ones_b` must have the same parity as `final_ones_count_in_a`.
    // Since `final_ones_count_in_a` is always even, `ones_b` must also be even.

    if (ones_b <= effective_ones_a && ones_b % 2 == effective_ones_a % 2) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <list>

struct Child {
    int id;
    long long v, d, p;
    bool active;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children_data(n);
    for (int i = 0; i < n; ++i) {
        children_data[i].id = i + 1;
        std::cin >> children_data[i].v >> children_data[i].d >> children_data[i].p;
        children_data[i].active = true;
    }

    std::vector<int> treated_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children_data[i].active) {
            continue;
        }

        treated_children_ids.push_back(children_data[i].id);
        children_data[i].active = false;

        long long current_v_cry = children_data[i].v;
        long long total_d_cry_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children_data[j].active) {
                continue;
            }

            // Apply current_v_cry effect
            if (current_v_cry > 0) {
                children_data[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Apply accumulated d_cry effect
            children_data[j].p -= total_d_cry_effect;

            // Check if child j leaves
            if (children_data[j].p < 0) {
                children_data[j].active = false;
                total_d_cry_effect += children_data[j].d;
            }
        }
    }

    std::cout << treated_children_ids.size() << "\n";
    for (size_t i = 0; i < treated_children_ids.size(); ++i) {
        std::cout << treated_children_ids[i] << (i == treated_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

