int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            if (f1 == 0) { // Cannot move left, so X must be >= current x
                min_x = std::max(min_x, x);
            }
            if (f2 == 0) { // Cannot move up, so Y must be <= current y
                max_y = std::min(max_y, y);
            }
            if (f3 == 0) { // Cannot move right, so X must be <= current x
                max_x = std::min(max_x, x);
            }
            if (f4 == 0) { // Cannot move down, so Y must be >= current y
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1 cut
    // A single cut divides s into s[0...i-1] and s[i...N-1].
    // We can rearrange them as s[i...N-1] + s[0...i-1].
    // We need this new string to be a palindrome and not equal to s.
    for (int i = 1; i < n; ++i) { // i is the cut point, 0 < i < N
        std::string p1 = s.substr(0, i);
        std::string p2 = s.substr(i);
        std::string new_s = p2 + p1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 doesn't work, check for k=2 cuts.
    // With k=2 cuts, we get 3 pieces.
    // The problem statement implies that if k=1 doesn't work, k=2 might.
    // The only case where k=2 is the minimum is if all characters are the same,
    // or if the string is of the form "ababa" where 'a' and 'b' are distinct characters,
    // and 'a' appears at least twice.
    // For example, "nolon". n=5.
    // s[0...n-2] is "nolo". s[1...n-1] is "olon".
    // If all characters are the same (e.g., "aaaa"), then any rearrangement will result in "aaaa".
    // In this case, it's impossible to get a new string.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work,
        // it means that for any single cut, either the rearranged string is not a palindrome,
        // or it's equal to the original string.
        // Consider a string like "abacaba".
        // If we cut it into s[0...n-2] and s[n-1], we get "abacab" and "a".
        // Rearranging gives "aabacab", which is not a palindrome.
        //
        // The problem statement guarantees that s is a palindrome.
        // If not all characters are the same, we can always achieve a new palindrome with 2 cuts.
        // Example: "nolon" -> "no|l|on" -> "on|l|no"
        // Example: "abacaba" -> "abacab|a" -> "a|abacab" (not palindrome)
        //
        // If s is a palindrome and not all characters are the same,
        // then s[0...n-1] is a palindrome.
        // Consider s[0...n-2]. This is s without its last character.
        // If s[0...n-2] is NOT a palindrome, then we can cut s into s[0...n-2] and s[n-1].
        // And then rearrange them as s[n-1] + s[0...n-2].
        // This new string will be different from s.
        // Is it a palindrome? Not necessarily.
        //
        // The key insight for k=2 is that if not all characters are the same,
        // and k=1 doesn't work, then k=2 is always possible.
        // This is because we can always take the prefix s[0...N-2] and suffix s[N-1].
        // If s[0...N-2] is not a palindrome, then we can cut s into s[0...N-2] and s[N-1].
        // The new string s[N-1] + s[0...N-2] will be different from s.
        //
        // Let's re-evaluate the condition for k=1.
        // If s is a palindrome, and s[i...N-1] + s[0...i-1] is a palindrome,
        // and s[i...N-1] + s[0...i-1] != s.
        //
        // If all characters are the same, it's impossible.
        // Otherwise, there must be at least two distinct characters.
        //
        // Consider the string s. If we remove the first character and the last character,
        // we get s_inner = s.substr(1, n-2).
        // If s_inner is a palindrome, then s = c + s_inner + c.
        // If s_inner is NOT a palindrome, then s = c + s_inner + c.
        //
        // The problem states that if k=1 doesn't work, then k=2 is the answer.
        // This implies that if not all characters are the same, and k=1 fails,
        // then k=2 must be possible.
        //
        // Example: "nolon"
        // n=5. s[0]='n', s[1]='o', s[2]='l', s[3]='o', s[4]='n'
        // s[0...3] = "nolo", s[4] = "n". "n" + "nolo" = "nnolo" (not palindrome)
        // s[0...2] = "nol", s[3...4] = "on". "on" + "nol" = "onnol" (not palindrome)
        // s[0...1] = "no", s[2...4] = "lon". "lon" + "no" = "lonno" (not palindrome)
        // s[0] = "n", s[1...4] = "olon". "olon" + "n" = "olonn" (not palindrome)
        // So for "nolon", k=1 doesn't work.
        // Since not all characters are the same, the answer is 2.
        //
        // This logic seems to hold:
        // 1. If all characters are the same, impossible.
        // 2. Otherwise, try k=1. If successful, print 1.
        // 3. Otherwise (not all chars same, k=1 failed), print 2.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    long long min_goodness = std::numeric_limits<long long>::max();
    std::vector<int> best_partition(n);

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // This is only possible if n >= 2. If n=1, there are no pairs.
    // If n=0, problem constraints say n >= 2.
    // All f(a_i, a_j) = a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-1].value + a[n-2].value
    // Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    if (n >= 2) {
        long long current_goodness = (a[n - 1].value + a[n - 2].value) - (a[0].value + a[1].value);
        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            for (int i = 0; i < n; ++i) {
                best_partition[a[i].original_index] = 1;
            }
        }
    }

    // Case 2: Partition into two non-empty subsequences.
    // The minimum possible sum for same-subsequence elements is a[0].value + a[1].value.
    // The maximum possible sum for same-subsequence elements is a[n-1].value + a[n-2].value.
    // The minimum possible sum for cross-subsequence elements is a[0].value + a[1].value + h.
    // The maximum possible sum for cross-subsequence elements is a[n-1].value + a[n-2].value + h.
    //
    // Consider the partition where a[0] is in S1, and all other elements a[1]...a[n-1] are in S2.
    // S1 = {a[0]}
    // S2 = {a[1], ..., a[n-1]}
    //
    // Possible f values:
    // 1. From S2: a_i + a_j for i, j in [1, n-1].
    //    Min: a[1].value + a[2].value (if n-1 >= 2, i.e., n >= 3)
    //    Max: a[n-1].value + a[n-2].value (if n-1 >= 2, i.e., n >= 3)
    // 2. Cross: a[0].value + a_j + h for j in [1, n-1].
    //    Min: a[0].value + a[1].value + h
    //    Max: a[0].value + a[n-1].value + h
    //
    // Overall min_f and max_f for this partition:
    // min_f = min( (a[1].value + a[2].value if n>=3 else infinity), a[0].value + a[1].value + h )
    // max_f = max( (a[n-1].value + a[n-2].value if n>=3 else -infinity), a[0].value + a[n-1].value + h )

    long long current_min_f_val;
    long long current_max_f_val;

    // Option A: a[0] in S1, a[1]...a[n-1] in S2
    // This partition is valid if n >= 2.
    // min_f:
    //   If n >= 3, S2 has at least two elements, so a[1]+a[2] is a candidate.
    //   a[0]+a[1]+h is always a candidate (cross-subsequence).
    //   So, min_f = min(a[1].value + a[2].value, a[0].value + a[1].value + h) if n >= 3.
    //   If n = 2, S2 has only a[1], no pairs in S2. min_f = a[0].value + a[1].value + h.
    if (n >= 3) {
        current_min_f_val = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
    } else { // n == 2
        current_min_f_val = a[0].value + a[1].value + h;
    }

    // max_f:
    //   If n >= 3, S2 has at least two elements, so a[n-1]+a[n-2] is a candidate.
    //   a[0]+a[n-1]+h is always a candidate (cross-subsequence).
    //   So, max_f = max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h) if n >= 3.
    //   If n = 2, S2 has only a[1], no pairs in S2. max_f = a[0].value + a[1].value + h.
    if (n >= 3) {
        current_max_f_val = std::max(a[n - 1].value + a[n - 2].value, a[0].value + a[n - 1].value + h);
    } else { // n == 2
        current_max_f_val = a[0].value + a[1].value + h;
    }

    long long current_goodness = current_max_f_val - current_min_f_val;
    if (current_goodness < min_goodness) {
        min_goodness = current_goodness;
        best_partition[a[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            best_partition[a[i].original_index] = 2;
        }
    }

    // Option B: a[n-1] in S1, a[0]...a[n-2] in S2
    // This partition is valid if n >= 2.
    // min_f:
    //   If n >= 3, S2 has at least two elements, so a[0]+a[1] is a candidate.
    //   a[n-1]+a[0]+h is always a candidate (cross-subsequence).
    //   So, min_f = min(a[0].value + a[1].value, a[n-1].value + a[0].value + h) if n >= 3.
    //   If n = 2, S2 has only a[0], no pairs in S2. min_f = a[n-1].value + a[0].value + h.
    if (n >= 3) {
        current_min_f_val = std::min(a[0].value + a[1].value, a[n - 1].value + a[0].value + h);
    } else { // n == 2
        current_min_f_val = a[n - 1].value + a[0].value + h;
    }

    // max_f:
    //   If n >= 3, S2 has at least two elements, so a[n-2]+a[n-3] is a candidate.
    //   a[n-1]+a[n-2]+h is always a candidate (cross-subsequence).
    //   So, max_f = max(a[n-2].value + a[n-3].value, a[n-1].value + a[n-2].value + h) if n >= 3.
    //   If n = 2, S2 has only a[0], no pairs in S2. max_f = a[n-1].value + a[0].value + h.
    if (n >= 3) {
        current_max_f_val = std::max(a[n - 2].value + a[n - 3].value, a[n - 1].value + a[n - 2].value + h);
    } else { // n == 2
        current_max_f_val = a[n - 1].value + a[0].value + h;
    }

    current_goodness = current_max_f_val - current_min_f_val;
    if (current_goodness < min_goodness) {
        min_goodness = current_goodness;
        best_partition[a[n - 1].original_index] = 1;
        for (int i = 0; i < n - 1; ++i) {
            best_partition[a[i].original_index] = 2;
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int h_idx = 0; h_idx < n && p_idx < m; ++h_idx) {
        long long current_h = h[h_idx];
        long long min_reach = current_h - T;
        long long max_reach = current_h + T;

        // Find the first track p[p_idx] that can be reached by current_h
        // If p[p_idx] is too far to the left, current_h cannot reach it.
        // We need to find a p[p_idx] such that p[p_idx] >= min_reach.
        // If p[p_idx] is already covered by a previous head, we skip it.
        // The loop for p_idx advances only when a track is covered.

        // If current_h is too far to the right to cover p[p_idx],
        // it means p[p_idx] < min_reach. This head cannot cover p[p_idx].
        // We need to move to the next head.
        if (p[p_idx] < min_reach) {
            continue;
        }

        // If current_h can cover p[p_idx], it can cover a range of tracks.
        // We want to cover as many tracks as possible to the right.
        // The range covered by current_h is [p[p_idx], max_reach].
        // We need to find the largest k such that p[k] <= max_reach.
        // All tracks p[p_idx]...p[k] are covered.

        // Find the first track that is NOT covered by current_h
        // i.e., p[k] > max_reach
        int next_p_idx = p_idx;
        while (next_p_idx < m && p[next_p_idx] <= max_reach) {
            next_p_idx++;
        }
        p_idx = next_p_idx;
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance: 10^10 - 1 (approx) + 10^10 - 1 (approx) = 2 * 10^10.
                                    // A safe upper bound is 2 * 10^10.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_sum_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum_left[i + 1] = prefix_sum_left[i] + (a[i] == 1 ? 1 : -1);
    }

    std::vector<int> prefix_sum_right(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum_right[i + 1] = prefix_sum_right[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    std::map<int, int> right_diff_to_k; // Stores diff_R -> k (number of jars removed from right)
    for (int k = 0; k <= n; ++k) {
        int diff_R = prefix_sum_right[k];
        if (right_diff_to_k.find(diff_R) == right_diff_to_k.end()) {
            right_diff_to_k[diff_R] = k;
        }
    }

    int min_removed = 2 * n; // Max possible jars to remove

    for (int j = 0; j <= n; ++j) {
        int diff_L = prefix_sum_left[j];
        int target_diff_R = -diff_L; // We need diff_L + diff_R = 0

        if (right_diff_to_k.count(target_diff_R)) {
            int k = right_diff_to_k[target_diff_R];
            min_removed = std::min(min_removed, j + k);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1] at pos[1].
        // min_idx = pos[1], max_idx = pos[1]. Length = 1. Max value = 1.
        // Condition: max_val - min_val + 1 == length.
        // 1 - 1 + 1 == 1. True.
        // So m=1 is always beautiful.

        // For m > 1, we need to expand the current segment [current_min_idx, current_max_idx]
        // to include the number m.
        // The number m is at pos[m].
        // We update current_min_idx and current_max_idx to cover the range
        // from pos[1] up to pos[m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A segment p[l...r] is a permutation of 1...m if:
        // 1. It contains all numbers from 1 to m. (This is guaranteed by current_min_idx, current_max_idx)
        // 2. The minimum value in p[l...r] is 1. (Guaranteed)
        // 3. The maximum value in p[l...r] is m. (Guaranteed)
        // 4. The length of the segment (r - l + 1) is equal to m.

        // Here, l is current_min_idx and r is current_max_idx.
        // The length of the segment is (current_max_idx - current_min_idx + 1).
        // If this length equals m, then it's a beautiful number.
        if ((current_max_idx - current_min_idx + 1) == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_req: minimum value a[i] must have to satisfy a[0] < ... < a[i]
    // If a[i] is the i-th element (0-indexed), it must be at least i.
    // We can decrease a[i] to satisfy this.
    // So, a[i] must be at least i.
    // If a[i] < i, it's impossible to make a[0] < ... < a[i] with a[0] >= 0.
    // More precisely, a[i] must be at least a[0] + i.
    // Since a[0] can be decreased to 0, a[i] must be at least i.
    // So, we need a[i] >= i for all i in the increasing part.
    // This is equivalent to checking if a[i] >= i for all i up to k.
    // And a[i] >= 0 for all i.
    // The actual value of a[i] can be decreased to min(a[i], current_max_val_allowed_by_prev_element).
    // But for the *existence* of a sharpened array, we just need to check if a[i] is large enough.
    // For a[0] < a[1] < ... < a[k], we need a[i] >= i for all i <= k.
    // For a[k] > a[k+1] > ... > a[n-1], we need a[i] >= (n-1-i) for all i >= k.

    // Check if there exists a k such that:
    // For i from 0 to k-1: a[i] >= i
    // For i from k to n-1: a[i] >= (n-1-i)

    // Let's find the maximum possible 'k' for the increasing part.
    // This is the largest index 'k_inc' such that a[0] >= 0, a[1] >= 1, ..., a[k_inc] >= k_inc.
    // Or, more accurately, the largest index 'k_inc' such that a[i] >= i for all i from 0 to k_inc.
    int k_inc = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            break;
        }
        k_inc = i;
    }

    // Let's find the minimum possible 'k' for the decreasing part.
    // This is the smallest index 'k_dec' such that a[k_dec] >= (n-1-k_dec), a[k_dec+1] >= (n-1-(k_dec+1)), ..., a[n-1] >= 0.
    // Or, more accurately, the smallest index 'k_dec' such that a[i] >= (n-1-i) for all i from k_dec to n-1.
    int k_dec = n;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1 - i)) {
            break;
        }
        k_dec = i;
    }

    // If there is an overlap, i.e., k_inc >= k_dec, then we can choose any k in [k_dec, k_inc]
    // and satisfy the conditions.
    if (k_inc >= k_dec) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

