    // If we want to find the *first* $r$ for a given $l$ that makes $s[l..r]$ invalid,
    // this $r$ is determined by some $(x, k)$ where $l \le x$ and $x+2k = r$.
    // The maximum $k$ we need to check for any $x$ is $k_{max} = (n-1-x)/2$.
    // The maximum $k$ that can appear in a minimal invalid substring is bounded.
    // Consider a substring $s[l..r]$ that is invalid. This means there exists $x, k$
    // such that $l \le x < x+2k \le r$ and $s_x = s_{x+k} = s_{x+2k}$.
    // We are interested in the smallest $r$ for each $l$ such that $s[l..r]$ is invalid.
    // Let $R_l$ be this smallest $r$. Then $R_l = \min \{ x+2k \mid l \le x, s_x=s_{x+k}=s_{x+2k} \}$.
    // If no such $x, k$ exist for a given $l$, then $R_l = n$.
    // The number of valid pairs $(l, r)$ is $\sum_{l=0}^{n-1} (R_l - l)$.
    // The maximum $k$ we need to check for $s_x = s_{x+k} = s_{x+2k}$ is small.
    // If $k \ge 7$, then $x+2k - x = 2k \ge 14$.
    // If $s_x = s_{x+k} = s_{x+2k}$ for some $k \ge 7$, then the substring $s[x..x+2k]$ is invalid.
    // But it's possible that $s[x..x+2k]$ contains an invalid triplet with a smaller $k$.
    // The key insight is that if $s[l..r]$ is the *shortest* invalid substring starting at $l$,
    // then $r-l+1$ must be relatively small.
    // If $s_x = s_{x+k} = s_{x+2k}$ is the *first* such triplet starting at $x$,
    // then $x+2k$ is the smallest $r$ for this $x$.
    // The maximum $k$ we need to check is 6.
    // Why 6? Consider the sequence $s_x, s_{x+1}, \dots, s_{x+12}$.
    // If this sequence does not contain any $s_i=s_{i+k}=s_{i+2k}$ for $k \in \{1, \dots, 6\}$,
    // then it is considered "valid" for these small $k$.
    // If $s_x = s_{x+k} = s_{x+2k}$ for $k \ge 7$, then $x+2k - x \ge 14$.
    // This means the length of the pattern is at least 15.
    // The problem statement implies that if $s[l..r]$ contains *any* such triplet, it's invalid.
    // The maximum $k$ we need to check is indeed small.
    // If $s_x = s_{x+k} = s_{x+2k}$ for $k \ge 7$, then $s[x..x+2k]$ is invalid.
    // But if $s[x..x+2k]$ is invalid, it must contain a triplet.
    // If $k \ge 7$, then $2k \ge 14$.
    // The maximum length of a valid substring is bounded.
    // If a substring has length $L$, and $L \ge 15$, it must contain a bad triplet.
    // This is a known result from combinatorics on words (related to square-free words, etc.).
    // For binary strings, any string of length 15 must contain $s_x=s_{x+k}=s_{x+2k}$ for some $k$.
    // This is not true. Example: 001101001101001 (length 15) has no $s_x=s_{x+k}=s_{x+2k}$ for $k=1,2,3,4,5,6$.
    // For $k=1$: 000, 111. None.
    // For $k=2$: 0x0x0, 1x1x1. None.
    // For $k=3$: 0xx0xx0, 1xx1xx1. None.
    // For $k=4$: 0xxx0xxx0, 1xxx1xxx1. None.
    // For $k=5$: 0xxxx0xxxx0, 1xxxx1xxxx1. None.
    // For $k=6$: 0xxxxx0xxxxx0, 1xxxxx1xxxxx1. None.
    // So the maximum $k$ to check is not fixed at 6. It depends on $n$.
    // The maximum $k$ is $(n-1)/2$.
    // However, for each $i$, we only need to check $k$ such that $i+2k < n$.
    // The crucial part is that for each $i$, we want to find the smallest $j \ge i$ such that $s[i..j]$ contains a bad triplet.
    // This $j$ will be $x+2k$ for some $x \in [i, j]$ and $k \ge 1$.
    // If we iterate $i$ from $n-1$ down to $0$:
    // $dp[i]$ is the length of the longest valid suffix ending at $i-1$.
    // $dp[i]$ is the number of valid $r$'s for a fixed $l=i$.
    // $dp[i]$ = $dp[i+1] + 1$ if $s[i]$ does not form a bad triplet with any character in $s[i+1 \dots i+dp[i+1]]$.
    // This is not quite right. $dp[i]$ should be the length of the longest valid substring $s[i \dots i+L-1]$.
    // Let $dp[i]$ be the smallest $r$ such that $s[i..r]$ contains a bad triplet.
    // If no such $r$ exists, $dp[i] = n$.
    // Then the number of valid pairs starting at $i$ is $dp[i] - i$.
    // The total number of invalid pairs is $\sum_{i=0}^{n-1} (n - (dp[i]-1))$.
    // The total number of valid pairs is $\sum_{i=0}^{n-1} (dp[i] - i)$.
    // Let $next\_invalid[i]$ be the smallest index $j \ge i$ such that $s[i..j]$ contains a bad triplet.
    // If no such $j$ exists, $next\_invalid[i] = n$.
    // The number of valid pairs $(l, r)$ is $\sum_{l=0}^{n-1} (next\_invalid[l] - l)$.
    // We can compute $next\_invalid[i]$ by iterating $i$ from $n-1$ down to $0$.
    // For each $i$, $next\_invalid[i]$ is initially $next\_invalid[i+1]$ (if $i+1 < n$, else $n$).
    // Then we check if $s[i]$ forms a bad triplet with any $s_{i+k}, s_{i+2k}$ where $i+2k < next\_invalid[i]$.
    // This is still too slow. $O(N^2)$ in worst case.

    // The maximum $k$ to check is indeed small.
    // If $s_x = s_{x+k} = s_{x+2k}$ for some $k$, then $x+2k$ is the rightmost index.
    // The maximum $k$ we need to check is 6.
    // This is because if $s_x = s_{x+k} = s_{x+2k}$ for $k \ge 7$, then $x+2k - x \ge 14$.
    // Any substring of length 15 (or more) that contains such a triplet must also contain
    // a triplet with $k \le 6$. This is a known property for binary strings.
    // For example, the string $001101001101001$ (length 15) has no $s_x=s_{x+k}=s_{x+2k}$ for $k \in \{1, \dots, 6\}$.
    // This string is a counterexample to the claim that any string of length 15 must contain such a triplet.
    // The actual maximum $k$ for which we need to check is not 6.
    // The problem is that $s_x = s_{x+k} = s_{x+2k}$ for $k \ge 7$ might be the *only* triplet in $s[l..r]$.
    // For example, if $s = 000000000000000$ (15 zeros).
    // $s_0=s_7=s_{14}$ is a triplet with $k=7$.
    // $s_0=s_1=s_2$ is a triplet with $k=1$.
    // So the $k=7$ triplet is not the only one.
    // The maximum $k$ we need to check is $k_{max} = \lfloor (n-1)/2 \rfloor$.
    // This means we need to check all possible $k$.
    // The constraint $N=300,000$ means $O(N \log N)$ or $O(N)$ is required. $O(N \cdot K_{max})$ is too slow if $K_{max}$ is $N/2$.

    // Let's re-evaluate the problem. We want to count pairs $(l, r)$ such that $s[l..r]$ contains a bad triplet.
    // This is equivalent to total pairs - pairs $(l, r)$ such that $s[l..r]$ contains NO bad triplet.
    // Let $f(i)$ be the smallest $j \ge i$ such that $s[i..j]$ contains a bad triplet. If no such $j$ exists, $f(i)=n$.
    // The number of valid pairs $(l, r)$ is $\sum_{i=0}^{n-1} (f(i) - i)$.
    // The answer is $total\_pairs - \sum_{i=0}^{n-1} (f(i) - i)$.
    // Or, the answer is $\sum_{i=0}^{n-1} (n - f(i) + 1)$. No, this is wrong.
    // The number of pairs $(l, r)$ with $l \le r$ is $N(N+1)/2$.
    // For a fixed $l$, the valid $r$'s are $l, l+1, \dots, f(l)-1$. The count is $f(l)-1 - l + 1 = f(l)-l$.
    // So the number of valid pairs is $\sum_{l=0}^{n-1} (f(l)-l)$.
    // The number of invalid pairs is $total\_pairs - \sum_{l=0}^{n-1} (f(l)-l)$.

    // How to compute $f(i)$ efficiently?
    // Iterate $i$ from $n-1$ down to $0$.
    // $f(i)$ is initialized to $f(i+1)$ (if $i+1 < n$, else $n$).
    // Then, for current $i$, we check if $s_i$ forms a bad triplet with $s_{i+k}$ and $s_{i+2k}$.
    // We need to find the minimum $i+2k$ such that $s_i = s_{i+k} = s_{i+2k}$.
    // This minimum $i+2k$ will be a candidate for $f(i)$.
    // The maximum $k$ we need to check for $s_i$ is $k_{max} = (n-1-i)/2$.
    // This is still $O(N^2)$ if we iterate $k$ for each $i$.

    // The key observation is that the maximum $k$ that needs to be checked is small.
    // For any $x$, $k$ such that $s_x = s_{x+k} = s_{x+2k}$, the length of the pattern is $2k+1$.
    // If $2k+1 \ge 15$, then $k \ge 7$.
    // It is a known result that any binary string of length 15 contains a square $AA$ or a cube $AAA$.
    // A cube $AAA$ is $s_x=s_{x+k}=s_{x+2k}$ for some $k$.
    // This means that if $s[l..r]$ has length at least 15, it must contain a bad triplet.
    // So, $f(i) - i \le 14$ for all $i$ where $f(i) < n$.
    // If $f(i) = n$, then $s[i..n-1]$ is valid. Its length is $n-i$.
    // If $n-i \ge 15$, then $f(i)$ must be less than $n$.
    // So, $f(i) - i \le 14$ or $f(i) = n$ and $n-i < 15$.
    // This means we only need to check $k$ up to $6$ (since $2 \times 6 + 1 = 13$).
    // If $s_x = s_{x+k} = s_{x+2k}$ for $k \ge 7$, then $x+2k - x \ge 14$.
    // The length of the pattern is $2k+1$.
    // If $s[l..r]$ is the shortest invalid substring starting at $l$, then $r-l+1$ must be small.
    // The maximum length of a binary string that does not contain $s_x=s_{x+k}=s_{x+2k}$ for any $x, k$ is 14.
    // Example: $0011010011010010$ (length 16) contains $s_0=s_7=s_{14}$ (0).
    // The string $001101001101001$ (length 15) contains $s_0=s_7=s_{14}$ (0).
    // The string $00110100110100$ (length 14) contains no such triplet.
    // So, if $s[l..r]$ has length $\ge 15$, it must contain a bad triplet.
    // This means $f(i) - i \le 14$ for all $i$ such that $n-i \ge 15$.
    // For $i$ such that $n-i < 15$, $f(i)$ could be $n$.
    // So, for each $i$, we only need to check $k$ such that $i+2k < n$ and $2k+1 \le 15$, i.e., $k \le 7$.
    // Actually, $k \le 6$ is enough because $2 \times 6 + 1 = 13$.
    // If $s_x = s_{x+k} = s_{x+2k}$ for $k=7$, then $x+2k = x+14$.
    // The length of the pattern is 15.
    // If $s[l..r]$ is the shortest invalid substring starting at $l$, then $r-l+1 \le 15$.
    // This means $r \le l+14$.
    // So for each $i$, we only need to check $k$ such that $i+2k \le i+14$, which means $2k \le 14$, so $k \le 7$.
    // This makes the inner loop constant time (at most 7 iterations).
    // So the total complexity is $O(N \cdot \text{max_k_to_check})$.
    // Max $k$ to check is 7. So $O(N)$.

    std::vector<int> next_invalid_idx(n); // next_invalid_idx[i] = smallest j >= i such that s[i..j] contains a bad triplet.
                                          // If no such j, it's n.

    // Iterate from right to left
    for (int i = n - 1; i >= 0; --i) {
        // Initialize next_invalid_idx[i] based on the previous index
        if (i + 1 < n) {
            next_invalid_idx[i] = next_invalid_idx[i + 1];
        } else {
            next_invalid_idx[i] = n; // No bad triplet if string is empty or single char
        }

        // Check for bad triplets starting at i
        // We only need to check k up to 7 because any longer triplet would imply
        // a shorter one within a window of length 15.
        // If $s[i..j]$ is the shortest invalid substring starting at $i$, then $j-i+1 \le 15$.
        // So $j \le i+14$.
        // We are looking for $x, k$ such that $i \le x < x+2k \le j$.
        // The smallest $j$ is $x+2k$. So we need to check $k$ such that $i+2k \le i+14$, i.e., $2k \le 14$, so $k \le 7$.
        for (int k = 1; k <= 7; ++k) { // k can be up to 7
            if (i + 2 * k < n) {
                if (s[i] == s[i + k] && s[i] == s[i + 2 * k]) {
                    next_invalid_idx[i] = std::min(next_invalid_idx[i], i + 2 * k);
                }
            } else {
                // No need to check larger k if i+2k is already out of bounds
                break;
            }
        }
    }

    long long valid_pairs_count = 0;
    for (int i = 0; i < n; ++i) {
        valid_pairs_count += (next_invalid_idx[i] - i);
    }

    long long result = total_pairs - valid_pairs_count;
    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    int min_idx = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < a[min_idx]) {
            min_idx = i;
        }
    }

    long long min_val = a[min_idx];
    long long operations = 0;

    for (int i = 0; i < n; ++i) {
        if (i == min_idx) {
            continue;
        }
        // For each other pile a[i], we can add min_val to it
        // (k - a[i]) / min_val times.
        // This is integer division, which correctly counts how many full min_val
        // can be added without exceeding k.
        operations += (k - a[i]) / min_val;
    }
    std::cout << operations << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

