        long long diff = std::abs(a - b);
        long long count = 0;

        count += diff / 5;
        diff %= 5;

        if (diff == 1 || diff == 2) {
            count += 1;
        } else if (diff == 3 || diff == 4) {
            count += 2;
        }
        // If diff is 0, nothing is added.

        std::cout << count << "\n";
    }
    return 0;
}

