void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    if (n == 2) {
        // For n=2, the only other permutation is the reversed one.
        // p = [p1, p2], F(p) = [p1+p2]
        // p' = [p2, p1], F(p') = [p2+p1]
        // F(p) == F(p')
        std::cout << p[1] << " " << p[0] << std::endl;
    } else {
        // For n > 2, reversing the permutation p_rev = [p_n, ..., p_1]
        // gives F(p_rev) = sort([p_n+p_{n-1}, ..., p_2+p_1])
        // which is the same as F(p) = sort([p_1+p_2, ..., p_{n-1}+p_n])
        // because addition is commutative.
        // However, p_rev might be equal to p (e.g., if p is a palindrome).
        // The problem guarantees a solution exists.
        // A simple swap of the first two elements p_1 and p_2
        // will change p to p' = [p_2, p_1, p_3, ..., p_n].
        // The adjacent sums change as follows:
        // p_1+p_2 becomes p_2+p_1 (same sum)
        // p_2+p_3 remains p_2+p_3
        // ...
        // p_{n-1}+p_n remains p_{n-1}+p_n
        // So F(p') will be identical to F(p).
        // This new permutation p' is different from p unless p_1 == p_2,
        // which is impossible in a permutation.
        // So, swapping the first two elements always works for n > 1.
        std::cout << p[1] << " " << p[0];
        for (int i = 2; i < n; ++i) {
            std::cout << " " << p[i];
        }
        std::cout << std::endl;
    }
}

