#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    int current_a1 = a[0];
    int remaining_days = d;

    for (int i = 1; i < n; ++i) { // Iterate through piles from index 1 (pile 2) to n-1 (pile n)
        int pile_idx = i + 1; // Convert 0-indexed i to 1-indexed pile number
        int cost_per_haybale = pile_idx - 1; // Days to move one haybale from pile_idx to pile 1

        if (cost_per_haybale == 0) { // This should only happen for pile 1 itself, which is handled by current_a1
            continue;
        }

        // Calculate how many haybales can be moved from this pile
        // based on remaining days and cost per haybale
        int max_haybales_from_this_pile = remaining_days / cost_per_haybale;

        // The actual number of haybales we can move is limited by
        // either the haybales available in the pile or the days we have
        int haybales_to_move = std::min(a[i], max_haybales_from_this_pile);

        current_a1 += haybales_to_move;
        remaining_days -= haybales_to_move * cost_per_haybale;

        if (remaining_days <= 0) {
            break; // No more days left
        }
    }

    std::cout << current_a1 << std::endl;
}

