#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it was already made equal.
            // The flags for has_pos_one and has_neg_one should reflect elements
            // *before* index i.
            if (a[i] == 1) has_pos_one = true; // This element is 1, so it can be used for elements j > i
            if (a[i] == -1) has_neg_one = true; // This element is -1, so it can be used for elements j > i
            continue;
        }

        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) { // No '1' available from indices < i
                possible = false;
                break;
            }
        } else { // a[i] > b[i], need to decrease a[i]
            if (!has_neg_one) { // No '-1' available from indices < i
                possible = false;
                break;
            }
        }

        // If we reach here, it means a[i] can be made equal to b[i]
        // by adding 1s or -1s from previous elements.
        // The original value of a[i] (which is -1, 0, or 1) is now effectively
        // replaced by b[i] for future considerations.
        // However, the problem states that a_i is added to a_j, not b_i.
        // The crucial part is that the *original* a_i values are used for operations.
        // So, the has_pos_one and has_neg_one flags should only depend on the original a_k for k < i.
        // The current logic for updating has_pos_one and has_neg_one is correct:
        // it tracks if there was an original 1 or -1 at an index < current i.
        // The loop iterates from n-1 down to 0.
        // When considering a[i], has_pos_one and has_neg_one reflect if there's a 1 or -1
        // in the original array a at any index k < i.
        // This is because elements a_k (k < i) can be added to a_i.
        // The flags are updated *after* processing a[i] for the current iteration,
        // so they correctly reflect elements a_k for k < (current i).
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

