    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue; // Skip diagonal element a[i][i] = 0
            max_val_in_row = std::max(max_val_in_row, a[i][j]);
        }
        // If max_val_in_row is n-1, then p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This is because if p[i] is not n, then p[i] is one of the values 1 to n-1.
        // In this case, there must be some p[j] such that p[j] > p[i].
        // Then min(p[i], p[j]) = p[i].
        // So max_val_in_row would be p[i].
        // If p[i] is n, then for any p[j] (j != i), p[j] <= n-1.
        // So min(p[i], p[j]) = min(n, p[j]) = p[j].
        // The maximum of these p[j] values would be n-1 (since n is taken by p[i]).
        // So max_val_in_row would be n-1.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
