#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 3; // Cost for n=1 is 1. Cost for n=3 is 7. Cost for n=7 is 31.
                                    // The pattern is 2^(k+1) - 1 for k=0,1,2,...
                                    // n = 2^k - 1.
                                    // Cost for n=1 (k=1) is 1.
                                    // Cost for n=3 (k=2) is 7.
                                    // Cost for n=7 (k=3) is 31.
                                    // The cost of a staircase with 2^k-1 stairs is (2^k-1) * (2^k) / 2 = (2^k-1) * 2^(k-1).
                                    // This is not the cost of the staircase itself, but the cost of the *next* staircase in the sequence of nice staircases.
                                    // The sequence of nice staircases has n values: 1, 3, 7, 15, ... (2^k - 1)
                                    // The cost of a staircase with n stairs is n*(n+1)/2.
                                    // For n=1, cost = 1*(2)/2 = 1.
                                    // For n=3, cost = 3*(4)/2 = 6.
                                    // For n=7, cost = 7*(8)/2 = 28.
                                    // For n=15, cost = 15*(16)/2 = 120.
                                    // The problem states that the cost of a staircase with n stairs is n*(n+1)/2.
                                    // The sequence of costs for nice staircases is 1, 6, 28, 120, ...
                                    // The problem example says for x=8, we can build 1-stair (cost 1) and 3-stair (cost 6). Total 7. Count = 2.
                                    // This means we should greedily pick the smallest available nice staircase.
                                    // The costs are:
                                    // n=1: cost = 1
                                    // n=3: cost = 6
                                    // n=7: cost = 28
                                    // n=15: cost = 120
                                    // ...
                                    // n = 2^k - 1. Cost = (2^k - 1) * 2^(k-1).
                                    // Let's use `current_n` for the number of stairs and `cost_n` for its cell count.
        long long current_n = 1;
        long long cost_n = 1;

        while (x >= cost_n) {
            x -= cost_n;
            count++;

            // Calculate the next nice staircase's n and cost
            // The next n is 2 * current_n + 1
            // The next cost is (2 * current_n + 1) * (2 * current_n + 2) / 2
            // which simplifies to (2 * current_n + 1) * (current_n + 1)

            // To avoid overflow with current_n, we can calculate cost_n directly from previous cost_n.
            // cost_n_k = (2^k - 1) * 2^(k-1)
            // cost_n_{k+1} = (2^(k+1) - 1) * 2^k
            // cost_n_{k+1} = (2 * (2^k - 1) + 1) * 2^k
            // cost_n_{k+1} = (2 * current_n + 1) * (current_n + 1)

            // Let's use the formula for the next cost directly.
            // The current n is `current_n`. The cost is `cost_n`.
            // The next n is `2 * current_n + 1`.
            // The next cost is `(2 * current_n + 1) * ( (2 * current_n + 1) + 1 ) / 2`
            // = `(2 * current_n + 1) * (2 * current_n + 2) / 2`
            // = `(2 * current_n + 1) * (current_n + 1)`

            // Check for potential overflow before calculating next_n and next_cost
            // current_n can go up to 2^60 - 1 (approx 10^18).
            // If current_n is 2^30, then 2*current_n+1 is 2^31.
            // (2*current_n+1)*(current_n+1) would be (2^31)*(2^30) = 2^61, which fits in long long.
            // If current_n is 2^31, then 2*current_n+1 is 2^32.
            // (2*current_n+1)*(current_n+1) would be (2^32)*(2^31) = 2^63, which fits in long long.
            // If current_n is 2^32, then 2*current_n+1 is 2^33.
            // (2*current_n+1)*(current_n+1) would be (2^33)*(2^32) = 2^65, which overflows long long.
            // So current_n can go up to about 2^31.
            // The maximum x is 10^18.
            // The costs grow very fast: 1, 6, 28, 120, 496, 2016, 8128, 32640, 130816, 523776, 2096128, 8386560, 33550336, 134209536, 536854528, 2147450880, 8589869056, 34359607296, 137438634496, 549755289600, 2199022800896, 8796092891136, 35184366086144, 140737476797440, 562949949532160, 2251799799103488, 9007199190000000, 36028797400000000, 144115185000000000, 576460740000000000, 2305843000000000000.
            // The last value is > 10^18. So we will not overflow `cost_n` before `x` becomes too small.

            current_n = 2 * current_n + 1;
            cost_n = current_n * (current_n + 1) / 2;
        }
        std::cout << count << "\n";
    }
    return 0;
}

// The sequence of n for nice staircases is 1, 3, 7, 15, 31, ... which is 2^k - 1 for k=1, 2, 3, ...
// The cost for a staircase with n stairs is n * (n + 1) / 2.
// So the costs for nice staircases are:
// k=1, n=1: cost = 1 * 2 / 2 = 1
// k=2, n=3: cost = 3 * 4 / 2 = 6
// k=3, n=7: cost = 7 * 8 / 2 = 28
// k=4, n=15: cost = 15 * 16 / 2 = 120
// k=5, n=31: cost = 31 * 32 / 2 = 496
// ...
// The strategy is to greedily pick the smallest available nice staircase.
// This is because each cell used for a smaller staircase leaves more cells for subsequent staircases.
// If we have X cells, and we can build a staircase of cost C1 and another of cost C2 (C1 < C2).
// If we build C1, remaining cells = X - C1.
// If we build C2, remaining cells = X - C2.
// Since C1 < C2, X - C1 > X - C2.
// Having more remaining cells allows us to build more staircases.
// So, we always pick the smallest possible nice staircase.
// The costs are 1, 6, 28, 120, ...
// We keep subtracting the smallest available cost from x and incrementing the count, until x is less than the smallest available cost.
// The smallest available cost is always the next one in the sequence 1, 6, 28, ...
// So, we iterate:
// 1. Subtract 1 from x, count++. Next cost is 6.
// 2. If x >= 6, subtract 6 from x, count++. Next cost is 28.
// 3. If x >= 28, subtract 28 from x, count++. Next cost is 120.
// ... and so on.
// This is exactly what the code does.
// `current_n` tracks the `n` value (1, 3, 7, ...)
// `cost_n` tracks the cost for that `n` (1, 6, 28, ...)
// In each iteration, we use `cost_n`, then update `current_n` to `2 * current_n + 1` and `cost_n` to the new `current_n * (current_n + 1) / 2`.

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;

            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians as minimums.
            // Remaining coders: c - mid
            // Remaining mathematicians: m - mid
            // Remaining total students (including those without specialization): (c - mid) + (m - mid) + x
            // Each team needs 3 members. 'mid' teams need 3 * mid members.
            // We've already accounted for 'mid' coders and 'mid' mathematicians.
            // So, we need 'mid' additional members to fill up the teams (3 * mid - mid - mid = mid).
            // These 'mid' additional members can come from remaining coders, remaining mathematicians, or students without specialization.

            if ((c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

