#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    int p = n - 1;
    // Find the longest suffix that is non-decreasing
    while (p > 0 && a[p-1] <= a[p]) {
        p--;
    }
    // Now a[p...n-1] is non-decreasing.
    // If p is 0, the whole array is non-decreasing.

    // Find the longest suffix of a[0...p-1] that is non-increasing
    // This means we are looking for the first element from the right
    // that breaks the non-increasing sequence.
    // Example: [..., x, y, z] where x > y > z.
    // We want to find the first element from the right that is not part of this.
    // So, we are looking for the first index `q` such that a[q] < a[q+1]
    // while scanning from right to left starting from p-1.
    // Or, more simply, find the first index `q` from the right such that a[q] > a[q+1]
    // and all elements to its right are non-increasing.
    // The elements a[p...n-1] are already non-decreasing.
    // We need to find the point where the array stops being non-increasing from the right.
    // This means we are looking for the first index `q` from the right such that `a[q] < a[q+1]`.
    // All elements from `q+1` to `n-1` are part of the "good" suffix.
    // The elements `a[p...n-1]` are non-decreasing.
    // We need to find the largest `k` such that `a[k...n-1]` is good.
    // The current `p` is the start of the non-decreasing suffix.
    // We need to find the start of the non-increasing suffix that precedes it.
    // Let's find the first index `q` from `p-1` down to `0` such that `a[q] < a[q+1]`.
    // If such `q` exists, then `a[q+1...n-1]` is the candidate good array.
    // The elements `a[q+1...p-1]` are non-increasing, and `a[p...n-1]` are non-decreasing.
    // This forms the "valley" structure.

    int q = p; // q is the start of the non-increasing part
    while (q > 0 && a[q-1] >= a[q]) {
        q--;
    }
    // Now a[q...p-1] is non-increasing (if q < p).
    // And a[p...n-1] is non-decreasing.
    // The array a[q...n-1] is a good array.
    // The length of the prefix to erase is q.

    std::cout << q << std::endl;
}

