int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // Discriminant: D = d^2 - 4d
            // For real solutions, D >= 0. This is true for d >= 4.
            // a = (d + sqrt(d^2 - 4d)) / 2
            // b = (d - sqrt(d^2 - 4d)) / 2
            // Or vice versa. Since a and b are symmetric, order doesn't matter.
            // We need a, b >= 0.
            // Since d >= 4, d^2 - 4d >= 0, so sqrt(d^2 - 4d) is real.
            // Also, d >= 4 implies d > 0.
            // For b = (d - sqrt(d^2 - 4d)) / 2 to be non-negative:
            // d - sqrt(d^2 - 4d) >= 0
            // d >= sqrt(d^2 - 4d)
            // d^2 >= d^2 - 4d (since both sides are non-negative, we can square)
            // 0 >= -4d
            // 4d >= 0
            // d >= 0. This is true for the given constraints.
            // So both a and b will be non-negative.

            double discriminant_sqrt = std::sqrt(d * d - 4.0 * d);
            double a = (d + discriminant_sqrt) / 2.0;
            double b = (d - discriminant_sqrt) / 2.0;
            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

