void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1] at pos[1].
        // current_min_idx and current_max_idx are already initialized to pos[1].
        // The length is 1, which is m. The range of values is [1,1].
        // So m=1 is always beautiful.

        // For m > 1, we need to expand the current segment [current_min_idx, current_max_idx]
        // to include 'm'.
        // The number 'm' must be at pos[m].
        // We update current_min_idx and current_max_idx to cover the range from 1 to m.
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number 'm' is beautiful if the subsegment p[current_min_idx ... current_max_idx]
        // is a permutation of 1, 2, ..., m.
        // This means two conditions must be met:
        // 1. The length of the subsegment must be exactly m.
        //    Length = current_max_idx - current_min_idx + 1.
        // 2. The values in the subsegment must range from 1 to m.
        //    Since we are always expanding the segment to include 'm' and all numbers
        //    from 1 to m-1 are already covered by the previous iteration's min/max indices,
        //    the values condition is implicitly met if the length condition is met.
        //    (i.e., if length is m, and it contains 1..m, it must be a permutation of 1..m)

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

