    std::sort(a.begin(), a.end());
    int count = 0;
    int j = 0; // Pointer for elements to be placed (larger elements)
    for (int i = 0; i < n; ++i) { // Pointer for original positions (smaller elements)
        // We are trying to find an element a[j] such that a[j] > a[i]
        // To maximize matches, we should try to use the smallest possible a[j]
        // that satisfies the condition for the current a[i].
        // Since both arrays are sorted, if a[j] works for a[i], it might also work for a[i+1].
        // If a[j] is used for a[i], we move to a[j+1] for the next potential match.
        // If a[j] is not greater than a[i], we need a larger element, so we increment j.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // Found an element a[j] > a[i]
            count++;
            j++; // Move to the next element in the 'larger' pool
        } else {
            // No more elements in 'larger' pool to satisfy a[i] or subsequent elements
            break;
        }
    }
    std::cout << count << std::endl;
