void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    if (total_toys == 0) { // Should not happen based on constraints A+B+C+D > 0
        std::cout << "Tidak Tidak Tidak Tidak\n";
        return;
    }

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        if (A == 1) ans1 = "Ya";
        if (B == 1) ans2 = "Ya";
        if (C == 1) ans3 = "Ya";
        if (D == 1) ans4 = "Ya";
        std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
        return;
    }

    // General case: total_toys > 1
    // N_neg = A + B (number of negative toys)
    // N_pos = C + D (number of positive toys)
    // N_large = A + D (number of toys with magnitude >= 1)
    // N_small = B + C (number of toys with magnitude < 1)

    // Box 1: (-inf, -1]
    // Final product is negative.
    // Final product has magnitude >= 1.
    // This requires N_neg to be odd.
    // This requires N_large >= 1 (if N_small == 0) OR N_large >= 1 and N_small >= 1 (if N_small > 0 and we can make magnitude >= 1)
    // If N_small == 0, then all toys have magnitude >= 1. Product will have magnitude >= 1.
    // If N_small > 0, we need to be able to make the product magnitude >= 1.
    // This is possible if A+D >= 1 and B+C >= 1, or if A+D >= 2, or if A+D >= 1 and B+C >= 1 and we can make the product magnitude >= 1.
    // The only way to guarantee magnitude < 1 is if all toys are from B or C (B+C = total_toys).
    // If A+D > 0, it's always possible to make the magnitude >= 1.
    // If A+D == 0, then all toys are from B or C. Product magnitude will be < 1.
    if ((A + B) % 2 != 0) { // N_neg is odd, so final product is negative
        if (A + D > 0) { // At least one toy with magnitude >= 1
            ans1 = "Ya";
        } else { // All toys are from B or C, so magnitude will be < 1
            // This means A=0, D=0. All toys are from B or C.
            // If B is odd, product is negative. If C is even, product is positive.
            // If A=0, D=0, then N_neg = B. If B is odd, product is negative.
            // But magnitude will be < 1. So it can't be in Box 1.
        }
    }

    // Box 2: (-1, 0)
    // Final product is negative.
    // Final product has magnitude < 1.
    // This requires N_neg to be odd.
    // This requires N_small >= 1 (if N_large == 0) OR N_small >= 1 and N_large >= 1 (if N_large > 0 and we can make magnitude < 1)
    // If N_large == 0, then all toys have magnitude < 1. Product will have magnitude < 1.
    // If N_large > 0, we need to be able to make the product magnitude < 1.
    // This is possible if B+C >= 1 and A+D >= 1, or if B+C >= 2, or if B+C >= 1 and A+D >= 1 and we can make the product magnitude < 1.
    // The only way to guarantee magnitude >= 1 is if all toys are from A or D (A+D = total_toys).
    // If B+C > 0, it's always possible to make the magnitude < 1.
    // If B+C == 0, then all toys are from A or D. Product magnitude will be >= 1.
    if ((A + B) % 2 != 0) { // N_neg is odd, so final product is negative
        if (B + C > 0) { // At least one toy with magnitude < 1
            ans2 = "Ya";
        } else { // All toys are from A or D, so magnitude will be >= 1
            // This means B=0, C=0. All toys are from A or D.
            // If A is odd, product is negative. If D is even, product is positive.
            // If B=0, C=0, then N_neg = A. If A is odd, product is negative.
            // But magnitude will be >= 1. So it can't be in Box 2.
        }
    }

    // Box 3: (0, 1)
    // Final product is positive.
    // Final product has magnitude < 1.
    // This requires N_neg to be even.
    // This requires N_small >= 1.
    if ((A + B) % 2 == 0) { // N_neg is even, so final product is positive
        if (B + C > 0) { // At least one toy with magnitude < 1
            ans3 = "Ya";
        } else { // All toys are from A or D, so magnitude will be >= 1
            // This means B=0, C=0. All toys are from A or D.
            // If A is even, product is positive. If D is even, product is positive.
            // If B=0, C=0, then N_neg = A. If A is even, product is positive.
            // But magnitude will be >= 1. So it can't be in Box 3.
        }
    }

    // Box 4: [1, inf)
    // Final product is positive.
    // Final product has magnitude >= 1.
    // This requires N_neg to be even.
    // This requires N_large >= 1.
    if ((A + B) % 2 == 0) { // N_neg is even, so final product is positive
        if (A + D > 0) { // At least one toy with magnitude >= 1
            ans4 = "Ya";
        } else { // All toys are from B or C, so magnitude will be < 1
            // This means A=0, D=0. All toys are from B or C.
            // If B is even, product is positive. If C is even, product is positive.
            // If A=0, D=0, then N_neg = B. If B is even, product is positive.
            // But magnitude will be < 1. So it can't be in Box 4.
        }
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
}

