#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Check prefix for increasing sequence
    // We need a_i >= i-1 for the prefix to be potentially 0, 1, 2, ...
    // If a_i < i-1, it's impossible to make a_i >= i-1.
    // The first element a_0 must be at least 0.
    // The second element a_1 must be at least 1.
    // The i-th element a_{i-1} must be at least i-1.
    // So, a_i must be at least i.
    // Let's use 0-indexed array.
    // a_0 < a_1 < ... < a_{k-1}
    // This means a_i must be at least i.
    // If a_i < i for any i, then it's impossible to form the strictly increasing prefix.
    // We find the first index `i` where `a[i] < i`.
    // All elements before this `i` (i.e., `a[0]` to `a[i-1]`) can potentially form the increasing part.
    // The peak `k` must be at or before this `i-1`.
    int prefix_limit = n;
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            prefix_limit = i;
            break;
        }
    }

    // Check suffix for decreasing sequence
    // We need a_k > a_{k+1} > ... > a_{n-1}
    // This means a_{n-1} must be at least 0.
    // a_{n-2} must be at least 1.
    // a_{n-1-j} must be at least j.
    // If a_{n-1-j} < j for any j, then it's impossible to form the strictly decreasing suffix.
    // We find the first index `j` (from the right) where `a[n-1-j] < j`.
    // All elements after this `n-1-j` (i.e., `a[n-j]` to `a[n-1]`) can potentially form the decreasing part.
    // The peak `k` must be at or after this `n-j`.
    int suffix_limit = -1;
    for (int j = 0; j < n; ++j) {
        if (a[n - 1 - j] < j) {
            suffix_limit = n - 1 - j;
            break;
        }
    }

    // If prefix_limit is 0, it means a[0] < 0, which is impossible as a[i] are non-negative.
    // If prefix_limit is 0, it means a[0] < 0, which is impossible.
    // The condition a[i] < i means a[0] < 0, which is not possible.
    // So prefix_limit will be at least 1 if a[0] >= 0.
    // The first element a[0] must be >= 0.
    // The peak index `k` (0-indexed) must be such that `0 <= k < prefix_limit`
    // AND `suffix_limit < k < n`.
    // So we need to find if there exists a `k` such that `suffix_limit < k < prefix_limit`.
    // This is equivalent to checking if `suffix_limit + 1 < prefix_limit`.
    // If `suffix_limit` is -1, it means all elements from right can be part of decreasing sequence.
    // If `prefix_limit` is `n`, it means all elements from left can be part of increasing sequence.

    // Example: n=6, a = [100, 11, 15, 9, 7, 8]
    // prefix_limit:
    // i=0, a[0]=100 >= 0
    // i=1, a[1]=11 >= 1
    // i=2, a[2]=15 >= 2
    // i=3, a[3]=9 >= 3
    // i=4, a[4]=7 >= 4
    // i=5, a[5]=8 >= 5
    // prefix_limit = 6 (all elements can be part of increasing prefix)

    // suffix_limit:
    // j=0, a[5]=8 >= 0
    // j=1, a[4]=7 >= 1
    // j=2, a[3]=9 >= 2
    // j=3, a[2]=15 >= 3
    // j=4, a[1]=11 >= 4
    // j=5, a[0]=100 >= 5
    // suffix_limit = -1 (all elements can be part of decreasing suffix)

    // We need to find k such that suffix_limit < k < prefix_limit
    // -1 < k < 6. This means k can be 0, 1, 2, 3, 4, 5.
    // So, Yes.

    // Example: n=4, a = [0, 1, 1, 0]
    // prefix_limit:
    // i=0, a[0]=0 >= 0
    // i=1, a[1]=1 >= 1
    // i=2, a[2]=1 < 2 -> prefix_limit = 2

    // suffix_limit:
    // j=0, a[3]=0 >= 0
    // j=1, a[2]=1 >= 1
    // j=2, a[1]=1 < 2 -> suffix_limit = 1

    // We need to find k such that suffix_limit < k < prefix_limit
    // 1 < k < 2. No integer k satisfies this. So, No.

    if (suffix_limit + 1 < prefix_limit) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

