int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> b(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b[i];
    }

    // Sort A in ascending order
    std::sort(a.begin(), a.end());

    // Create pairs (B_i, original_index_i) and sort them by B_i in descending order
    std::vector<std::pair<long long, int>> b_indexed(m);
    for (int i = 0; i < m; ++i) {
        b_indexed[i] = {b[i], i};
    }
    std::sort(b_indexed.rbegin(), b_indexed.rend()); // Sort by B_i descending

    // Create the result array A'
    std::vector<long long> a_prime(m);

    // Assign elements from sorted A to A' based on sorted B_i
    // The largest B_i gets the smallest A_i, the second largest B_i gets the second smallest A_i, and so on.
    // This is because F(N, K) = N / (K+1). To maximize sum(N_i / (K_i+1)),
    // we want to pair small K_i+1 (large K_i) with small N_i, and large K_i+1 (small K_i) with large N_i.
    // Since B_i corresponds to K_i, we pair small B_i with large A_i, and large B_i with small A_i.
    // The current sorting of b_indexed is B_i descending.
    // The current sorting of a is A_i ascending.
    // So, b_indexed[0] has the largest B_i. We pair it with a[0], the smallest A_i.
    // b_indexed[1] has the second largest B_i. We pair it with a[1], the second smallest A_i.
    // And so on.
    for (int i = 0; i < m; ++i) {
        a_prime[b_indexed[i].second] = a[i];
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

