bool is_permutation(const std::vector<int>& arr, int len) {
    if (len == 0) return false; // Permutations must have non-zero length
    if (len > arr.size()) return false;

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        if (arr[i] < 1 || arr[i] > len) {
            return false;
        }
        if (seen[arr[i]]) {
            return false;
        }
        seen[arr[i]] = true;
        if (arr[i] > max_val) {
            max_val = arr[i];
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_max(n);
    std::vector<int> suffix_max(n);

    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
    }

    suffix_max[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<int> freq_p(n + 1, 0);
    int distinct_count_p = 0;
    for (int l1 = 1; l1 <= n; ++l1) {
        int val = a[l1 - 1];
        if (val <= l1) { // Only consider values within the current length
            if (freq_p[val] == 0) {
                distinct_count_p++;
            }
            freq_p[val]++;
        }

        if (prefix_max[l1 - 1] == l1 && distinct_count_p == l1) {
            is_prefix_perm[l1] = true;
        }
    }

    std::vector<bool> is_suffix_perm(n + 1, false);
    std::vector<int> freq_s(n + 1, 0);
    int distinct_count_s = 0;
    for (int l2 = 1; l2 <= n; ++l2) {
        int val = a[n - l2];
        if (val <= l2) { // Only consider values within the current length
            if (freq_s[val] == 0) {
                distinct_count_s++;
            }
            freq_s[val]++;
        }

        if (suffix_max[n - l2] == l2 && distinct_count_s == l2) {
            is_suffix_perm[l2] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be 1 to n-1
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

