    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // will eventually interact with this 'b'.
            // This 'b' effectively doubles the number of 'a's that
            // will be processed by subsequent 'b's to its right.
            // Or, more simply, it doubles the number of 'a's that
            // are "active" and need to move past 'b's.
            // Each 'b' encountered from right to left doubles the
            // number of 'a's that will be processed by the next 'b'
            // to its right (or rather, the 'a's that are currently
            // to its left and will move past it).
            // The number of 'a's that need to move past this 'b'
            // is `count_a`. Each such 'a' contributes 1 step.
            // After this 'b' is processed, it effectively becomes
            // two 'b's for the 'a's to its left.
            // So, the `count_a` for the next iteration (further left)
            // should be doubled.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' is now
            // "active" and needs to move past any 'b's to its right.
            // It adds 1 to the current count of active 'a's.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

