// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    if (n == 0) {
        return "0"; // Special case for 0, its parity pattern is "0"
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) {
            pattern += '0';
        } else {
            pattern += '1';
        }
        n /= 10;
    }
    std::reverse(pattern.begin(), pattern.end()); // Digits were extracted right-to-left, reverse to get left-to-right
    return pattern;
}

// Function to normalize a pattern string to a fixed length (18 for 10^18)
// by padding with '0's from the left.
// This is not strictly needed if we use a map where keys are the patterns themselves.
// The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left.
// Similarly, if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
// This means we should consider the effective pattern for a number.
// For example, 92 and pattern "010".
// 92 -> 0...092. Parity pattern for 92 is "10".
// "010" is the pattern.
// We need to compare "10" with "010".
// The rule implies that we should pad the shorter one with '0's from the left to match length.
// So "10" becomes "010" to match "010".
// This means the effective pattern for a number is its parity pattern, padded with '0's to the left to max length.
// Max length for 10^18 is 18 digits.
// So, we can convert all numbers to their 18-digit parity pattern.
std::string normalize_pattern(long long n) {
    std::string s = "";
    if (n == 0) {
        s = "0";
    } else {
        while (n > 0) {
            s += (((n % 10) % 2 == 0) ? '0' : '1');
            n /= 10;
        }
    }
    // Pad with '0's to the right to make it 18 characters long.
    // This is equivalent to padding with '0's to the left of the original number.
    // Example: 92 -> "10". Pad to 18: "100000000000000000".
    // This is wrong. The padding is from the left of the *number*.
    // So 92 becomes 00...092.
    // Parity of 0 is 0. So 00...010.
    // This means the pattern for 92 is "00...010" (16 zeros, then 1, then 0).
    // The string `s` generated above is "01" for 92.
    // We need to reverse `s` and then pad with '0's to the left to make it 18 chars.
    // No, the problem says "parity of the i-th from the right digit".
    // So for 92, rightmost is 2 (even), second from right is 9 (odd).
    // This gives "10" (odd, even).
    // If pattern is "010", it means rightmost is even, second is odd, third is even.
    // For 92, we compare "10" with "010".
    // The rule "If the pattern is shorter than this integer, it's supplemented with 0-s from the left.
    // Similarly, if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This means we should effectively compare two strings of equal length, padded with '0's.
    // The simplest way to handle this is to convert all numbers to their 18-digit parity pattern.
    // For example, 92:
    // 000000000000000092
    // Parity: 000000000000000010
    // This is the key.
    std::string result = "";
    for (int i = 0; i < 18; ++i) {
        if (n == 0 && i > 0 && s.empty()) { // If n was 0 initially, or we've processed all digits
            result += '0';
        } else {
            result += (((n % 10) % 2 == 0) ? '0' : '1');
            n /= 10;
        }
    }
    std::reverse(result.begin(), result.end()); // Reverse to get the correct order (most significant digit first)
    return result;
}

