    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[normalize_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[normalize_pattern(a)]--;
        } else { // type == '?'
            std::string s;
