int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left side
    // 'i' represents the number of items taken from the left (w_1 to w_i)
    // 'n-i' represents the number of items taken from the right side (w_n to w_{i+1})
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Energy for items taken from the left
        long long left_items_weight_sum = prefix_sum[i];
        current_energy += left_items_weight_sum * l;

        // Energy for items taken from the right
        long long right_items_weight_sum = prefix_sum[n] - prefix_sum[i];
        current_energy += right_items_weight_sum * r;

        // Additional energy for consecutive actions
        int left_count = i;
        int right_count = n - i;

        if (left_count > right_count) {
            // More items from left. The last item taken must be from the left.
            // The difference in counts is (left_count - right_count).
            // If this difference is 1, no extra Ql.
            // If this difference is > 1, then (left_count - right_count - 1) times
            // the robot took left consecutively after a left.
            current_energy += (left_count - right_count - 1) * Ql;
        } else if (right_count > left_count) {
            // More items from right. The last item taken must be from the right.
            // The difference in counts is (right_count - left_count).
            // If this difference is 1, no extra Qr.
            // If this difference is > 1, then (right_count - left_count - 1) times
            // the robot took right consecutively after a right.
            current_energy += (right_count - left_count - 1) * Qr;
        }
        // If left_count == right_count, no extra Ql or Qr is added based on this logic.
        // The problem statement implies that if the previous action was the same,
        // it spends extra. If counts are equal, the last action could be either.
        // However, the optimal strategy for equal counts would be to alternate,
        // so no consecutive penalties. The logic (diff - 1) correctly handles this.
        // E.g., if left_count = 3, right_count = 2, diff = 1. (1-1)*Ql = 0. Correct.
        // E.g., if left_count = 3, right_count = 0, diff = 3. (3-1)*Ql = 2*Ql. Correct.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

