long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    // q can be up to 10^9, so its prime factors are relatively small.
    // We only need to iterate up to sqrt(q)
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            // i is a prime factor of q
            long long current_p = p;
            while (current_p % i == 0 && current_p % q == 0) {
                current_p /= i;
            }
            max_x = std::max(max_x, current_p);

            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }

    // If temp_q is still greater than 1, it means temp_q itself is a prime factor
    if (temp_q > 1) {
        long long i = temp_q; // This is the remaining prime factor
        long long current_p = p;
        while (current_p % i == 0 && current_p % q == 0) {
            current_p /= i;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

