    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

