void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (char c = 'a'; c <= 'z'; ++c) {
        adj[c] = std::set<char>();
    }

    bool possible = true;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        char u = s[i];
        char v = s[i+1];
        adj[u].insert(v);
        adj[v].insert(u);
    }

    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout_str = "";
    std::vector<bool> visited(26, false); // 'a' -> 0, 'b' -> 1, etc.

    // Find a starting point (a character with only one neighbor in the password graph)
    char start_char = '\0';
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    // If all characters in the password graph have 2 neighbors (cycle) or 0 neighbors (isolated)
    // and there are no 1-neighbor nodes, pick any character from the password that has neighbors.
    if (start_char == '\0') {
        for (char c = 'a'; c <= 'z'; ++c) {
            if (!adj[c].empty()) { // If it's part of the password graph
                start_char = c;
                break;
            }
        }
    }

    // If start_char is still '\0', it means the password was empty or all characters are isolated.
    // In this case, any layout is fine. We'll handle this by just appending all unvisited chars later.

    if (start_char != '\0') {
        char current_char = start_char;
        char prev_char = '\0'; // Sentinel for the first step

        while (current_char != '\0' && !visited[current_char - 'a']) {
            layout_str += current_char;
            visited[current_char - 'a'] = true;

            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (neighbor != prev_char) {
                    next_char = neighbor;
                    break;
                }
            }
            prev_char = current_char;
            current_char = next_char;
        }
    }

    // Append any remaining unvisited characters (those not in the password or isolated)
    for (char c = 'a'; c <= 'z'; ++c) {
        if (!visited[c - 'a']) {
            layout_str += c;
        }
    }

    if (layout_str.length() != 26) {
        // This should ideally not happen if the logic is correct,
        // but as a safeguard, if the constructed string isn't 26 chars, it's an error.
        // Or, more likely, it means the graph was disconnected and we only traversed one component.
        // The current logic for appending unvisited characters should cover this.
        // The only way layout_str.length() != 26 is if there was a cycle in the password graph
        // and we started from a node in that cycle, but then couldn't add all nodes.
        // Let's re-check the cycle condition.
        // If a component is a cycle, all nodes have degree 2.
        // If we start from any node in a cycle, we will traverse the whole cycle.
        // If there are multiple components, we will traverse one.
        // The current logic for `start_char` picks a degree-1 node if available.
        // If not, it picks any node with neighbors.
        // If it picks a node in a cycle, it will traverse the cycle.
        // Then the remaining characters are added.
        // The only way it could be impossible is if there are multiple components that are paths/cycles
        // and they need to be merged, but they can't be.
        // E.g., 'ab' and 'cd'. This would mean 'a'-'b' and 'c'-'d' are separate components.
        // The current algorithm would pick 'a', traverse 'a'-'b', then add 'c', 'd', etc.
        // This is fine.
        // The only true impossibility is if a character has >2 neighbors.
        // So, if we reach here and layout_str.length() != 26, it implies a bug or a missed impossibility case.
        // However, the problem statement implies that if degree > 2 is the only impossibility.
        // Let's assume the current logic for `possible` is sufficient.
        // The only way `layout_str.length() != 26` could happen is if `start_char` was never found,
        // meaning all `adj[c]` were empty, and then `layout_str` would be empty before the loop.
        // But then all 26 chars would be added in the final loop.
        // So, `layout_str.length()` will always be 26.
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

