    // Initialize two values: one starting at 0, one starting at 1023 (all bits set)
    // These represent the state of the bits after all operations.
    // `val0` tracks what 0 becomes after all operations.
    // `val1023` tracks what 1023 becomes after all operations.
    int val0 = 0;
    int val1023 = 1023;

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val0 &= x;
            val1023 &= x;
        } else if (op_char == '|') {
            val0 |= x;
            val1023 |= x;
        } else if (op_char == '^') {
            val0 ^= x;
            val1023 ^= x;
        }
    }

    // Now, `val0` is the result for input 0, and `val1023` is the result for input 1023.
    // We need to find a minimal set of operations that transform any `input_val`
    // to `output_val` such that:
    // 1. If `input_val` is 0, `output_val` is `val0`.
    // 2. If `input_val` is 1023, `output_val` is `val1023`.
    // This implies that for each bit `j`:
    //   - If `j`-th bit of input 0 (which is 0) becomes `j`-th bit of `val0`.
    //   - If `j`-th bit of input 1023 (which is 1) becomes `j`-th bit of `val1023`.

    // Let's determine the final state of each bit based on its initial state (0 or 1).
    // For each bit `j` from 0 to 9:
    //   - `bit_0_becomes`: `(val0 >> j) & 1` (what 0 becomes)
    //   - `bit_1_becomes`: `(val1023 >> j) & 1` (what 1 becomes)

    // We can represent the transformation for each bit `j` as a pair (bit_0_becomes, bit_1_becomes).
    // There are 4 possible transformations for each bit:
    // (0,0): Always 0, regardless of input bit. (e.g., `& 0`)
    // (0,1): Stays the same. (e.g., `& 1`, `| 0`, `^ 0`)
    // (1,0): Flips. (e.g., `^ 1`)
    // (1,1): Always 1, regardless of input bit. (e.g., `| 1`)

    // We want to find `A_AND`, `A_OR`, `A_XOR` such that:
    // `(x & A_AND) | A_OR ^ A_XOR` (or some other order)
    // produces the desired `val0` and `val1023` for inputs 0 and 1023.

    // Let's try to construct the final operations.
    // We can maintain three values:
    // `final_and_mask`: The value to AND with. Initially all bits 1 (1023).
    // `final_or_mask`: The value to OR with. Initially all bits 0 (0).
    // `final_xor_mask`: The value to XOR with. Initially all bits 0 (0).

    // For each bit `j` from 0 to 9:
    int b0 = (val0 >> j) & 1; // What 0 becomes
    int b1 = (val1023 >> j) & 1; // What 1 becomes

    // Case 1: (0,0) - Input bit 0 becomes 0, Input bit 1 becomes 0.
    // This means the bit must end up as 0.
    // To achieve this, we must AND with 0 at this bit position.
    // `final_and_mask` should have 0 at bit `j`.
    // `final_or_mask` should have 0 at bit `j`.
    // `final_xor_mask` should have 0 at bit `j`.
    // (x & 0) | 0 ^ 0 = 0

    // Case 2: (0,1) - Input bit 0 becomes 0, Input bit 1 becomes 1.
    // This means the bit stays the same.
    // To achieve this, we must AND with 1, OR with 0, XOR with 0.
    // `final_and_mask` should have 1 at bit `j`.
    // `final_or_mask` should have 0 at bit `j`.
    // `final_xor_mask` should have 0 at bit `j`.
    // (x & 1) | 0 ^ 0 = x

    // Case 3: (1,0) - Input bit 0 becomes 1, Input bit 1 becomes 0.
    // This means the bit flips.
    // To achieve this, we must AND with 1, OR with 0, XOR with 1.
    // `final_and_mask` should have 1 at bit `j`.
    // `final_or_mask` should have 0 at bit `j`.
    // `final_xor_mask` should have 1 at bit `j`.
    // (x & 1) | 0 ^ 1 = ~x (for this bit)

    // Case 4: (1,1) - Input bit 0 becomes 1, Input bit 1 becomes 1.
    // This means the bit must end up as 1.
    // To achieve this, we must AND with 1, OR with 1, XOR with 0.
    // `final_and_mask` should have 1 at bit `j`.
    // `final_or_mask` should have 1 at bit `j`.
    // `final_xor_mask` should have 0 at bit `j`.
    // (x & 1) | 1 ^ 0 = 1

    // Let's construct the masks based on these observations.
    int and_val = 1023; // All bits 1 initially
    int or_val = 0;     // All bits 0 initially
    int xor_val = 0;    // All bits 0 initially

    for (int j = 0; j < 10; ++j) {
        int b0 = (val0 >> j) & 1;
        int b1 = (val1023 >> j) & 1;

        if (b0 == 0 && b1 == 0) { // (0,0) -> always 0
            and_val &= ~(1 << j); // Force bit to 0 by ANDing with 0
            // or_val and xor_val remain 0 at this bit
        } else if (b0 == 0 && b1 == 1) { // (0,1) -> identity
