#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long count = 0;

    // Precompute positions of '1's
    std::vector<int> ones_pos;
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            ones_pos.push_back(i);
        }
    }

    // Iterate over each '1' as the starting point of a potential good substring
    for (int i = 0; i < ones_pos.size(); ++i) {
        int l_idx = ones_pos[i]; // Current '1' is at index l_idx
        long long current_val = 0;

        // Iterate over possible lengths, up to a maximum that keeps current_val manageable
        // Max length for current_val to be <= 2*10^5 + 18 (max N + max_offset_for_18_bits)
        // is about 18-19 bits.
        // If current_val exceeds N + 18, then len will be much smaller than current_val
        // because len is at most N.
        // So we only need to check up to about 18-19 characters after the leading '1'.
        // The maximum value of N is 2e5.
        // If len = 19, max val is 2^19 - 1 = 524287.
        // If len = 20, max val is 2^20 - 1 = 1048575.
        // If len = 21, max val is 2^21 - 1 = 2097151.
        // The maximum possible length of a substring is N = 2e5.
        // If current_val > N, then it's impossible for len = current_val.
        // So we only need to consider substrings where current_val <= N.
        // The maximum number of bits to represent N (2e5) is ceil(log2(2e5)) = 18 bits.
        // So we only need to check up to 18 characters after the leading '1'.
        // However, the problem states r-l+1 = f(s_l...s_r).
        // If f(s_l...s_r) is large, say 200000, then r-l+1 must be 200000.
        // This means the substring itself must be 200000 characters long.
        // The maximum value of f(s_l...s_r) for a substring of length L is 2^L - 1.
        // If L = 18, max value is 2^18 - 1 = 262143.
        // If L = 19, max value is 2^19 - 1 = 524287.
        // So we need to check up to about 19-20 characters after the leading '1'.
        // Let's use a safe upper bound like 20.
        // The maximum length of a substring is N.
        // The maximum value of f(t) for a substring of length L is 2^L - 1.
        // If L > 20, then 2^L - 1 > 2^20 - 1 > 10^6.
        // But the length L itself is at most N = 2*10^5.
        // So if f(t) > N, it's impossible for L = f(t).
        // Thus, we only need to consider substrings where f(t) <= N.
        // The maximum number of bits required to represent N is 18 (since 2^17 < 2e5 < 2^18).
        // So, if a substring starts with '1', its length can be at most N.
        // If its value f(t) is greater than N, it cannot be a good substring.
        // This means we only need to consider substrings of length up to 18-19 characters
        // after the leading '1' to keep f(t) <= N.
        // Let's use a constant MAX_BITS = 20 for safety.
        const int MAX_BITS = 20; // log2(2e5) is approx 17.6, so 18 bits needed. 20 is safe.

        for (int j = 0; j < MAX_BITS && l_idx + j < n; ++j) {
            current_val = (current_val << 1) | (s[l_idx + j] - '0');
            int len = j + 1; // Length of current substring s[l_idx ... l_idx + j]

            if (current_val > n) { // Optimization: if value exceeds max possible length, break
                break;
            }
            if (current_val == len) {
                count++;
            }
        }
    }

    // Iterate over each '0' as the starting point of a potential good substring
    // For substrings starting with '0', the value f(t) is small.
    // f(0) = 0, length 1.
    // f(00) = 0, length 2.
    // f(01) = 1, length 2.
    // f(001) = 1, length 3.
    // f(011) = 3, length 3.
    // The maximum value of f(t) for a substring starting with '0'
    // that could potentially be equal to its length is small.
    // If s_l = '0', then f(s_l...s_r) is at most 2^(r-l) - 1.
    // We need r-l+1 = f(s_l...s_r).
    // If r-l+1 = 1, then f(s_l) = 1. But s_l='0', so f(s_l)=0. No match.
    // If r-l+1 = 2, then f(s_l s_{l+1}) = 2.
    //   If s_l='0', then f(0s_{l+1}) = s_{l+1}-'0'.
    //   So s_{l+1}-'0' = 2. Impossible as s_{l+1} is '0' or '1'.
    // If r-l+1 = 3, then f(s_l s_{l+1} s_{l+2}) = 3.
    //   If s_l='0', then f(0s_{l+1}s_{l+2}) = (s_{l+1}-'0')*2 + (s_{l+2}-'0').
    //   This can be 3 if s_{l+1}='1', s_{l+2}='1'. So "011" is good.
    // If r-l+1 = 4, then f(s_l s_{l+1} s_{l+2} s_{l+3}) = 4.
    //   If s_l='0', then f(0s_{l+1}s_{l+2}s_{l+3}) = (s_{l+1}-'0')*4 + (s_{l+2}-'0')*2 + (s_{l+3}-'0').
    //   This can be 4 if s_{l+1}='1', s_{l+2}='0', s_{l+3}='0'. So "0100" is good.
    // The maximum length for which f(t) can be equal to length, given s_l='0',
    // is when f(t) is roughly 2^(length-1).
    // We need length = f(t).
    // If length = 1, f(0) = 0. No.
    // If length = 2, f(00) = 0, f(01) = 1. No.
    // If length = 3, f(000)=0, f(001)=1, f(010)=2, f(011)=3. Yes, "011".
    // If length = 4, f(0100)=4. Yes, "0100".
    // If length = 5, f(00101)=5. Yes, "00101".
    // If length = 6, f(000110)=6. Yes, "000110".
    // The maximum length for which this can happen is small.
    // For a string of length L starting with '0', its value is at most 2^(L-1)-1.
    // We need L = f(t). So L <= 2^(L-1)-1.
    // This inequality holds for L >= 3.
    // The maximum value of L is N.
    // The maximum value of f(t) is N.
    // If s_l = '0', then f(s_l...s_r) is at most 2^(r-l) - 1.
    // We need r-l+1 = f(s_l...s_r).
    // So r-l+1 <= 2^(r-l) - 1.
    // Let k = r-l+1 be the length. Then k <= 2^(k-1) - 1.
    // This inequality holds for k >= 3.
    // The maximum value of k is N.
    // The maximum value of f(t) is N.
    // So we only need to check up to MAX_BITS characters after the leading '0'.
    // The logic is similar to the '1' case, but the value calculation is different.
    // For s_l...s_r, if s_l='0', then f(s_l...s_r) = f(s_{l+1}...s_r).
    // So we need r-l+1 = f(s_{l+1}...s_r).
    // Let's iterate over all possible starting positions `l`.
    // If s[l] == '0', we need to find `r` such that `r - l + 1 == f(s_{l+1}...s_r)`.
    // This is equivalent to `r - (l+1) + 1 == f(s_{l+1}...s_r) - 1`.
    // This is not quite right.
    // The definition of f(t) is "decimal representation of integer t written in binary form (possibly with leading zeroes)".
    // So f(011) = 3, f(00101) = 5.
    // This means we calculate the value of the entire substring s_l...s_r.
    // The previous loop already handles all substrings starting with '1'.
    // For substrings starting with '0', we need to iterate over them.
    // The maximum length of a substring is N.
    // The maximum value of f(t) is N.
    // If s[l] == '0', then f(s_l...s_r) is at most 2^(r-l) - 1.
    // We need r-l+1 = f(s_l...s_r).
    // If r-l+1 > MAX_BITS, then f(s_l...s_r) would be at most 2^(r-l) - 1.
    // If r-l+1 = 20, f(s_l...s_r) <= 2^19 - 1 = 524287.
    // If r-l+1 = 21, f(s_l...s_r) <= 2^20 - 1 = 1048575.
    // The maximum length is N = 2e5.
    // If a substring starts with '0', its value is at most 2^(len-1)-1.
    // We need len = value.
    // So len <= 2^(len-1)-1.
    // This holds for len >= 3.
    // For len = 1, s_l = '0', value = 0. len != value.
    // For len = 2, s_l s_{l+1} = "00" or "01". Values 0, 1. len != value.
    // So we only need to check for len >= 3.
    // The maximum length we need to check is still MAX_BITS (approx 20).
    // For each starting '0', we can iterate up to MAX_BITS characters.

    // Iterate over all possible starting positions `l`
    for (int l = 0; l < n; ++l) {
        if (s[l] == '0') {
            long long current_val = 0;
            for (int r = l; r < std::min(n, l + MAX_BITS); ++r) {
                current_val = (current_val << 1) | (s[r] - '0');
                int len = r - l + 1;
                if (current_val == len) {
                    count++;
                }
            }
        }
    }

    std::cout << count << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

