    // This computes balances of prefixes of the right half.
    // a[n], a[n...n+1], ..., a[n...2n-1]
    for (int i = n; i < 2 * n; ++i) {
        current_balance += (a[i] == 1 ? 1 : -1);
        // Number of jars removed from right is `(2n-1) - i`.
        // This is `n - (i - n + 1)`.
        // `i - n + 1` is the number of jars remaining on the right.
        // So, jars removed = `n - (number of jars remaining)`.
        // The number of jars removed is `(i - n + 1)`.
        // No, this is wrong.
        // If we keep `k` jars from the right, these are `a[n ... n+k-1]`.
        // The number of jars removed is `n-k`.
        // Let `bal_right_rem[k]` be the balance of `a[n ... n+k-1]`.
        // `k` goes from 0 to `n`.
        // `bal_right_rem[0] = 0`. Jars removed = `n`.
        // `bal_right_rem[1] = (a[n] == 1 ? 1 : -1)`. Jars removed = `n-1`.
        // `bal_right_rem[k]` is `current_balance` after `k` iterations.
        // The number of jars removed is `n-k`.
        // So, `right_balances[current_balance] = n-k`.
        // The loop variable `i` goes from `n` up to `2n-1`.
        // When `i = n`, `k=1`. Jars removed = `n-1`.
        // When `i = 2n-1`, `k=n`. Jars removed = `0`.
        // So, `right_balances[current_balance] = n - (i - n + 1)`.
        if (right_balances.find(current_balance) == right_balances.end()) {
            right_balances[current_balance] = (2 * n - 1) - i; // Number of jars removed from right is `(2n-1) - i`
        }
    }
    // Add the case where all jars are removed from the right.
    // Balance is 0, jars removed is n.
    if (right_balances.find(0) == right_balances.end()) {
        right_balances[0] = n;
    } else {
        right_balances[0] = std::min(right_balances[0], n);
    }


    // Calculate initial total balance
    int total_balance = 0;
    for (int x : a) {
        total_balance += (x == 1 ? 1 : -1);
    }

    int min_jars_removed = 2 * n; // Max possible jars removed

    // Iterate through all possible balances for the left side
    // For each `bal_L` and its corresponding `jars_removed_L`,
    // we need `bal_R` such that `bal_L + bal_R = 0`.
    // So, `bal_R = -bal_L`.
    for (auto const& [bal_L, jars_removed_L] : left_balances) {
        int target_bal_R = -bal_L;
        if (right_balances.count(target_bal_R)) {
            int jars_removed_R = right_balances[target_bal_R];
            min_jars_removed = std::min(min_jars_removed, jars_removed_L + jars_removed_R);
        }
    }

    std::cout << min_jars_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long m;
    std::cin >> n >> m;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2; // current candidate for X

        bool possible = true;
        long long prev_b = 0; // b_0 is effectively 0 for the first element

        for (int i = 0; i < n; ++i) {
            long long current_a = a[i];
            long long current_b;

            // Case 1: current_b = current_a + x_i, where x_i <= mid
            // We want current_b >= prev_b.
            // Smallest possible current_b is current_a.
            // If current_a >= prev_b, we can set x_i = 0, so current_b = current_a.
            // This is valid if 0 <= mid.
            if (current_a >= prev_b) {
                // We can potentially set current_b = current_a.
                // This requires x_i = 0, which is <= mid.
                // So, current_b can be current_a.
                current_b = current_a;
            } else { // current_a < prev_b
                // We must increment current_a to reach at least prev_b.
                // The value current_a + x_i must be >= prev_b.
                // The smallest value current_a can become is current_a.
                // The largest value current_a can become is (current_a + mid) % m.
                // If we increment current_a by x_i, it becomes (current_a + x_i) % m.
                // We need (current_a + x_i) % m >= prev_b.
                // The smallest value current_a can take that is >= prev_b is prev_b itself.
                // To reach prev_b from current_a, we need x_i = (prev_b - current_a + m) % m.
                // If this x_i is <= mid, then it's possible to make current_b = prev_b.
                long long x_needed_to_reach_prev_b = (prev_b - current_a + m) % m;
                if (x_needed_to_reach_prev_b <= mid) {
                    current_b = prev_b;
                } else {
                    // It's not possible to reach prev_b by incrementing current_a by at most mid.
                    // The maximum value current_a can become is (current_a + mid) % m.
                    // If this maximum value is still less than prev_b, then it's impossible.
                    // This happens if current_a + mid < prev_b (without modulo).
                    // Example: a=0, m=7, prev_b=6, mid=1. (0+1)%7 = 1. 1 < 6. Impossible.
                    // Example: a=0, m=7, prev_b=6, mid=6. (0+6)%7 = 6. 6 >= 6. Possible.
                    // The condition is that (current_a + mid) % m must be >= prev_b.
                    // But this is tricky with modulo.
                    // Let's consider the two ranges:
                    // 1. [current_a, m-1]
                    // 2. [0, (current_a + mid) % m] (if current_a + mid >= m)
                    // If current_a < prev_b, we need to increment current_a.
                    // The values current_a can take are current_a, (current_a+1)%m, ..., (current_a+mid)%m.
                    // We need to find if any of these values are >= prev_b.
                    // If current_a + mid < m:
                    //   The values are current_a, ..., current_a + mid.
                    //   If current_a + mid < prev_b, then it's impossible.
                    // If current_a + mid >= m:
                    //   The values are current_a, ..., m-1, 0, ..., (current_a + mid) % m.
                    //   Since current_a < prev_b, and prev_b <= m-1,
                    //   and current_a can reach m-1, it can definitely reach prev_b.
                    //   So, if current_a + mid >= m, it's always possible to find a b_i >= prev_b.
                    //   We can set current_b = prev_b.
                    //
                    // Combining:
                    // If current_a < prev_b:
                    //   We need to increment current_a.
                    //   If (current_a + mid) % m >= prev_b, and current_a + mid < m,
                    //     then current_a + mid is the largest value we can reach.
                    //     If current_a + mid < prev_b, then impossible.
                    //   If (current_a + mid) % m < prev_b, and current_a + mid < m,
                    //     then impossible.
                    //   If current_a + mid >= m:
                    //     We can always reach prev_b.
                    //
                    // The condition `x_needed_to_reach_prev_b <= mid` correctly captures this.
                    // If `x_needed_to_reach_prev_b > mid`, it means we cannot reach `prev_b` from `current_a`
                    // by incrementing at most `mid` times.
                    // In this case, the smallest possible `b_i` we can achieve is `current_a`.
                    // But `current_a < prev_b`, so this is not valid.
                    // Thus, if `x_needed_to_reach_prev_b > mid`, it's impossible.
                    possible = false;
                    break;
                }
            }
            prev_b = current_b;
        }

        if (possible) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// In the worst case, y could be n * 2 * max(a_i) which is 2*10^5 * 2 * 10^9 = 4*10^14.
// x is an index, so it fits in int.

// dp[i][0] stores the final x value if starting at index i with an "add" step.
// dp[i][1] stores the final y value if starting at index i with an "add" step.
// dp[i][2] stores the final x value if starting at index i with a "subtract" step.
// dp[i][3] stores the final y value if starting at index i with a "subtract" step.
// We use -1 for x values to indicate termination or non-termination.
// For y values, -1 indicates non-termination.
std::vector<std::vector<long long>> dp;
std::vector<bool> visited; // To detect cycles (non-termination)
std::vector<bool> visiting; // To detect cycles during DFS

int N;
std::vector<long long> A_vals; // 0-indexed, A_vals[0] is a_1, A_vals[i] is a_{i+1}

// Function to solve for a given starting index and operation type
// type = 0 for "add" step, type = 1 for "subtract" step
void solve(int current_x, int type) {
    if (current_x <= 0 || current_x > N) {
        // Terminated
        dp[current_x][0] = current_x;
        dp[current_x][1] = 0;
        dp[current_x][2] = current_x;
        dp[current_x][3] = 0;
        return;
    }

    if (visited[current_x]) {
        // Already computed
        return;
    }

    if (visiting[current_x]) {
        // Cycle detected, non-terminating
        dp[current_x][0] = -1;
        dp[current_x][1] = -1;
        dp[current_x][2] = -1;
        dp[current_x][3] = -1;
        return;
    }

    visiting[current_x] = true;

    long long val_at_x = A_vals[current_x - 1]; // a_x

    // Case 1: Start with "add" step (type 0)
    long long next_x_add = current_x + val_at_x;
    long long y_increase_add = val_at_x;

    // The next step is "subtract"
    solve(next_x_add, 1); // Recursively solve for the next state

    if (dp[next_x_add][2] == -1) { // If the subsequent path is non-terminating
        dp[current_x][0] = -1;
        dp[current_x][1] = -1;
    } else {
        dp[current_x][0] = dp[next_x_add][2];
        dp[current_x][1] = y_increase_add + dp[next_x_add][3];
    }

    // Case 2: Start with "subtract" step (type 1)
    long long next_x_sub = current_x - val_at_x;
    long long y_increase_sub = val_at_x;

    // The next step is "add"
    solve(next_x_sub, 0); // Recursively solve for the next state

    if (dp[next_x_sub][0] == -1) { // If the subsequent path is non-terminating
        dp[current_x][2] = -1;
        dp[current_x][3] = -1;
    } else {
        dp[current_x][2] = dp[next_x_sub][0];
        dp[current_x][3] = y_increase_sub + dp[next_x_sub][1];
    }

    visiting[current_x] = false;
    visited[current_x] = true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    A_vals.resize(N);
    // a_1 is set by the loop, a_2 to a_n are read
    for (int i = 1; i < N; ++i) {
        std::cin >> A_vals[i];
    }

    // Initialize DP table. Size N+2 to handle x=0 and x=N+1 boundary conditions.
    // dp[x][0]: final x if starting at x with add
    // dp[x][1]: final y if starting at x with add
    // dp[x][2]: final x if starting at x with subtract
    // dp[x][3]: final y if starting at x with subtract
    dp.assign(N + 2, std::vector<long long>(4, 0));
    visited.assign(N + 2, false);
    visiting.assign(N + 2, false);

    // Pre-calculate for all possible x values (1 to N)
    // We need to call solve for each x from 1 to N, for both starting types.
    // The loop below ensures all states are computed.
    for (int i = 1; i <= N; ++i) {
        if (!visited[i]) {
            solve(i, 0); // Compute starting with add
            solve(i, 1); // Compute starting with subtract
        }
    }

    for (int i = 1; i < N; ++i) {
        A_vals[0] = i; // Set a_1 = i for this run

        // Initial state: x = 1, y = 0. First step is "add".
        // We need to find the result of starting at x=1 with an "add" step.
        // This is stored in dp[1][0] (final x) and dp[1][1] (final y).

        // The total y value is A_vals[0] (from the first add step) + the y accumulated from the rest of the path.
        // The final y value from dp[1][1] already includes the A_vals[0] from the first step.
        // So, if dp[1][1] is -1, it's non-terminating. Otherwise, it's the answer.
        std::cout << dp[1][1] << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> L(n, 0), R(n, 0);

    // Calculate L[i]: length of consecutive identical values ending at i
    L[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == a[i - 1]) {
            L[i] = L[i - 1] + 1;
        } else {
            L[i] = 1;
        }
    }

    // Calculate R[i]: length of consecutive identical values starting at i
    R[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == a[i + 1]) {
            R[i] = R[i + 1] + 1;
        } else {
            R[i] = 1;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) { // Find max_k for 0s
            if (i > 0 && a[i - 1] == 1) { // 10...
                max_k = std::max(max_k, (L[i] + 1) / 2);
            }
            if (i < n - 1 && a[i + 1] == 1) { // ...01
                max_k = std::max(max_k, (R[i] + 1) / 2);
            }
        }
    }

    std::vector<int> b = a;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            int left_len = (i == 0 || a[i-1] == 0) ? L[i] : 0; // Length of 0s ending at i
            int right_len = (i == n-1 || a[i+1] == 0) ? R[i] : 0; // Length of 0s starting at i

            if (i > 0 && a[i-1] == 1) { // 10...
                left_len = L[i];
            } else {
                left_len = n + 1; // Effectively infinite, won't be limited by left 1
            }

            if (i < n-1 && a[i+1] == 1) { // ...01
                right_len = R[i];
            } else {
                right_len = n + 1; // Effectively infinite, won't be limited by right 1
            }

            if (left_len <= max_k && right_len <= max_k) {
                // This 0 is part of a 10...01 pattern that will flip to 1
                // if it's within max_k distance from both ends.
                // This logic is tricky. Let's simplify.
                // A 0 at index i flips to 1 if it's part of a 10...01 block
                // and its distance to both 1s is <= max_k.
                // The distance is (length of 0s block + 1) / 2.
                // If a[i] is 0, and it's surrounded by 1s (or boundaries)
                // 1...1 0...0 1...1
                // The 0s block has length L[i] (if looking left) or R[i] (if looking right).
                // The actual length of the 0s block is L[i] if a[i-1] is 1, or R[i] if a[i+1] is 1.
                // If a[i] is 0, and it's part of a 10...01 block, it will flip to 1 if
                // its distance from the left 1 is <= max_k AND its distance from the right 1 is <= max_k.
                // The distance from left 1 is i - (first_0_idx_in_block - 1).
                // The distance from right 1 is (last_0_idx_in_block + 1) - i.
                // This is equivalent to checking if i is within the range [first_0_idx + max_k, last_0_idx - max_k].
                // A 0 at index `i` will become 1 if `i` is `k` steps away from a `1` on its left AND `k` steps away from a `1` on its right.
                // The `k` steps here is `max_k`.
                // So, if `i` is `j` positions from the left `1` and `p` positions from the right `1`,
                // and `j <= max_k` and `p <= max_k`, then `b[i]` becomes `1`.
                // The `j` is `i - (idx_of_left_1)`. The `p` is `(idx_of_right_1) - i`.
                // This is equivalent to:
                // `i - (i - L[i]) <= max_k` (if a[i-1] == 1) => `L[i] <= max_k`
                // `(i + R[i]) - i <= max_k` (if a[i+1] == 1) => `R[i] <= max_k`
                // This is not quite right. The `L[i]` and `R[i]` are lengths of consecutive identical values.
                // If `a[i] == 0`, `L[i]` is the length of the block of 0s ending at `i`.
                // If `a[i-1] == 1`, then `i-L[i]` is the index of the first 0 in the block.
                // The distance from `a[i-1]` to `a[i]` is 1.
                // The distance from `a[i-1]` to `a[i-L[i]+1]` is 1.
                // The distance from `a[i-1]` to `a[i]` is `i - (i-L[i]) = L[i]`.
                // No, this is not distance. This is length.
                // The number of steps for a 0 to flip to 1 is `ceil(length_of_0_block / 2)`.
                // If `a[i]` is 0, and it's part of a block of 0s of length `len_0`.
                // If `a[i-1] == 1` and `a[i+len_0] == 1`, then this block of 0s will eventually become 1s.
                // The time it takes is `ceil(len_0 / 2)`.
                // So, if `a[i]` is 0, and it's `k` steps away from a `1` on its left, and `p` steps away from a `1` on its right.
                // `b[i]` becomes `1` if `k <= max_k` and `p <= max_k`.
                // `k` is `i - (index of nearest 1 to the left)`.
                // `p` is `(index of nearest 1 to the right) - i`.
                // Let's find the nearest 1 to the left and right for each 0.
                int dist_left_1 = n + 1; // Effectively infinity
                if (i == 0) { // Boundary condition
                    dist_left_1 = 0;
                } else if (a[i-1] == 1) {
                    dist_left_1 = 1;
                } else { // a[i-1] == 0
                    dist_left_1 = L[i-1] + 1; // Distance to the 1 before the block of 0s
                }

                int dist_right_1 = n + 1; // Effectively infinity
                if (i == n - 1) { // Boundary condition
                    dist_right_1 = 0;
                } else if (a[i+1] == 1) {
                    dist_right_1 = 1;
                } else { // a[i+1] == 0
                    dist_right_1 = R[i+1] + 1; // Distance to the 1 after the block of 0s
                }

                // If a[i] is 0, it will flip to 1 if it's "close enough" to 1s on both sides.
                // "Close enough" means its distance to the nearest 1 on left AND right is <= max_k.
                // The distance is measured in terms of indices.
                // For a 0 at index `i`, if `a[i-1]` is 1, its distance to left 1 is 1.
                // If `a[i-1]` is 0, and `a[i-2]` is 1, its distance to left 1 is 2.
                // This is `L[i]` if `a[i-L[i]]` is 1.
                // No, this is `L[i]` if `a[i-L[i]]` is 1.
                // The distance from `i` to the nearest `1` on its left is `L[i]` if `a[i-L[i]] == 1`.
                // The distance from `i` to the nearest `1` on its right is `R[i]` if `a[i+R[i]] == 1`.
                // This is not correct.
                // Let's re-evaluate the final state.
                // A 0 at index `i` will become 1 if it's part of a `10...01` block
                // and its distance to the left `1` is `d_L` and to the right `1` is `d_R`.
                // It flips if `d_L <= max_k` AND `d_R <= max_k`.
                // `d_L` is `i - (index of left 1)`.
                // `d_R` is `(index of right 1) - i`.

                // Find index of nearest 1 to the left of i
                int idx_left_1 = -1;
                if (i == 0) idx_left_1 = 0; // Boundary acts as a 1 if a[0] is 1
                else if (a[i-1] == 1) idx_left_1 = i-1;
                else idx_left_1 = i - L[i]; // L[i] is length of 0s ending at i. So a[i-L[i]] is the element before the 0s block.

                // Find index of nearest 1 to the right of i
                int idx_right_1 = n;
                if (i == n-1) idx_right_1 = n-1; // Boundary acts as a 1 if a[n-1] is 1
                else if (a[i+1] == 1) idx_right_1 = i+1;
                else idx_right_1 = i + R[i]; // R[i] is length of 0s starting at i. So a[i+R[i]] is the element after the 0s block.

                // If a[i] is 0, and it's surrounded by 1s (or boundaries acting as 1s)
                // it will flip to 1 if it's "close enough" to both.
                // The distance from `i` to `idx_left_1` is `i - idx_left_1`.
                // The distance from `i` to `idx_right_1` is `idx_right_1 - i`.
                // If `a[i]` is 0, and `a[idx_left_1]` is 1 (or `idx_left_1 == 0`), and `a[idx_right_1]` is 1 (or `idx_right_1 == n-1`).
                // Then `b[i]` becomes 1 if `i - idx_left_1 <= max_k` AND `idx_right_1 - i <= max_k`.

                // Special handling for boundaries:
                // If a[0] is 0, idx_left_1 is 0. dist_left_1 = i.
                // If a[n-1] is 0, idx_right_1 is n-1. dist_right_1 = (n-1) - i.

                int current_dist_left_1 = (idx_left_1 == -1) ? n + 1 : (i - idx_left_1);
                int current_dist_right_1 = (idx_right_1 == n) ? n + 1 : (idx_right_1 - i);

                if (a[i] == 0 && current_dist_left_1 <= max_k && current_dist_right_1 <= max_k) {
                    b[i] = 1;
                }
            } else if (a[i] == 1) {
                // A 1 at index `i` will become 0 if it's part of a `01...10` block
                // and its distance to the left `0` is `d_L` and to the right `0` is `d_R`.
                // It flips if `d_L <= max_k` AND `d_R <= max_k`.
                // `d_L` is `i - (index of left 0)`.
                // `d_R` is `(index of right 0) - i`.

                // Find index of nearest 0 to the left of i
                int idx_left_0 = -1;
                if (i == 0) idx_left_0 = 0; // Boundary acts as a 0 if a[0] is 0
                else if (a[i-1] == 0) idx_left_0 = i-1;
                else idx_left_0 = i - L[i]; // L[i] is length of 1s ending at i. So a[i-L[i]] is the element before the 1s block.

                // Find index of nearest 0 to the right of i
                int idx_right_0 = n;
                if (i == n-1) idx_right_0 = n-1; // Boundary acts as a 0 if a[n-1] is 0
                else if (a[i+1] == 0) idx_right_0 = i+1;
                else idx_right_0 = i + R[i]; // R[i] is length of 1s starting at i. So a[i+R[i]] is the element after the 1s block.

                int current_dist_left_0 = (idx_left_0 == -1) ? n + 1 : (i - idx_left_0);
                int current_dist_right_0 = (idx_right_0 == n) ? n + 1 : (idx_right_0 - i);

                if (a[i] == 1 && current_dist_left_0 <= max_k && current_dist_right_0 <= max_k) {
                    b[i] = 0;
                }
            }
        }
    }

    std::cout << max_k << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false; // This child is cured and leaves the line

        long long current_v_effect = children[i].v;
        long long accumulated_d_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_effect from previous children who left
            if (accumulated_d_effect > 0) {
                children[j].p -= accumulated_d_effect;
            }

            // Apply current_v_effect from the child being cured
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect = std::max(0LL, current_v_effect - 1);
            }

            // Check if child j's confidence drops below zero
            if (children[j].p < 0) {
                children[j].in_line = false;
                accumulated_d_effect += children[j].d;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    long long min_goodness = -1;
    std::vector<int> best_partition(n);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // This is only possible if n < 2, but problem states n >= 2.
    // If n >= 2, then there are always pairs in the same subsequence.
    // If all elements are in one subsequence, say S1, then S2 is empty.
    // All f(a_i, a_j) values are a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-1].value + a[n-2].value
    // Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    // This is a baseline partition.
    {
        long long current_goodness = (a[n - 1].value + a[n - 2].value) - (a[0].value + a[1].value);
        min_goodness = current_goodness;
        for (int i = 0; i < n; ++i) {
            best_partition[a[i].original_index] = 1;
        }
    }

    // Case 2: Partition where a[0] is in S1, and a[1]...a[n-1] are in S2.
    // Or more generally, a[0] is in S1, and all other elements are in S2.
    // This means a[0] is separated from all other elements.
    // The values of f are:
    // 1. a[i] + a[j] for i, j > 0 (both in S2)
    // 2. a[0] + a[i] + h for i > 0 (a[0] in S1, a[i] in S2)
    //
    // min_f:
    //   - If n-1 >= 2 (i.e., n >= 3), then min(a[i]+a[j] for i,j>0) = a[1].value + a[2].value.
    //   - min(a[0]+a[i]+h for i>0) = a[0].value + a[1].value + h.
    //   So, min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h) if n >= 3.
    //   If n=2, S2 only has a[1]. No pairs in S2. min_f = a[0].value + a[1].value + h.
    //
    // max_f:
    //   - max(a[i]+a[j] for i,j>0) = a[n-1].value + a[n-2].value.
    //   - max(a[0]+a[i]+h for i>0) = a[0].value + a[n-1].value + h.
    //   So, max_f = std::max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h) if n >= 3.
    //   If n=2, max_f = a[0].value + a[1].value + h.
    //
    // Let's simplify.
    // The minimum possible sum is a[0].value + a[1].value.
    // The maximum possible sum is a[n-1].value + a[n-2].value.
    //
    // If we put a[0] in S1 and all others in S2:
    // min_f_val:
    //   - If n >= 3: min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    //   - If n == 2: a[0].value + a[1].value + h
    // max_f_val:
    //   - If n >= 3: max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h)
    //   - If n == 2: a[0].value + a[1].value + h
    //
    // This partition strategy is generally good when h is large, as it minimizes the number of pairs
    // that cross the partition boundary (only n-1 such pairs).
    //
    // Let's calculate the goodness for this specific partition:
    // a[0] in S1, a[1]...a[n-1] in S2.
    long long current_min_f, current_max_f;
    if (n == 2) {
        current_min_f = a[0].value + a[1].value + h;
        current_max_f = a[0].value + a[1].value + h;
    } else { // n >= 3
        current_min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
        current_max_f = std::max(a[n - 1].value + a[n - 2].value, a[0].value + a[n - 1].value + h);
    }
    long long current_goodness = current_max_f - current_min_f;

    if (current_goodness < min_goodness) {
        min_goodness = current_goodness;
        best_partition[a[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            best_partition[a[i].original_index] = 2;
        }
    }

    // Case 3: Partition where a[0] and a[1] are in S1, and a[2]...a[n-1] are in S2.
    // This is only relevant if n >= 3.
    // This partition is good when h is small.
    //
    // min_f:
    //   - a[0].value + a[1].value (in S1)
    //   - If n >= 4: a[2].value + a[3].value (in S2)
    //   - a[0].value + a[2].value + h (a[0] in S1, a[2] in S2)
    //   - a[1].value + a[2].value + h (a[1] in S1, a[2] in S2)
    //
    // max_f:
    //   - a[0].value + a[1].value (in S1)
    //   - If n >= 4: a[n-1].value + a[n-2].value (in S2)
    //   - a[1].value + a[n-1].value + h (a[1] in S1, a[n-1] in S2)
    //   - a[0].value + a[n-1].value + h (a[0] in S1, a[n-1] in S2)
    //
    // The minimum possible sum is a[0].value + a[1].value.
    // The maximum possible sum is a[n-1].value + a[n-2].value.
    //
    // Let's calculate the goodness for this specific partition:
    // a[0], a[1] in S1, a[2]...a[n-1] in S2.
    if (n >= 3) {
        long long min_f_val_S1 = a[0].value + a[1].value;
        long long min_f_val_S2 = (n >= 4) ? (a[2].value + a[3].value) : (2LL * 10000000000LL); // Effectively infinity
        long long min_f_val_diff = a[0].value + a[2].value + h; // Smallest from S1 to S2

        current_min_f = std::min({min_f_val_S1, min_f_val_S2, min_f_val_diff});

        long long max_f_val_S1 = a[0].value + a[1].value; // Only one pair in S1
        long long max_f_val_S2 = (n >= 4) ? (a[n - 1].value + a[n - 2].value) : (0LL); // Effectively negative infinity
        long long max_f_val_diff = a[1].value + a[n - 1].value + h; // Largest from S1 to S2

        current_max_f = std::max({max_f_val_S1, max_f_val_S2, max_f_val_diff});

        current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[a[0].original_index] = 1;
            best_partition[a[1].original_index] = 1;
            for (int i = 2; i < n; ++i) {
                best_partition[a[i].original_index] = 2;
            }
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
