bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // Cut s into s[0...i-1] and s[i...N-1]
    // New string is s[i...N-1] + s[0...i-1]
    // We need this new string to be a palindrome and not equal to s.
    for (int i = 1; i < n; ++i) {
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string new_s = s2 + s1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2.
    // The problem statement guarantees that s is a palindrome.
    // If all characters in s are the same (e.g., "aaaa"), then no matter how we cut and rearrange,
    // the resulting string will always be "aaaa". In this case, it's impossible to get a different string.
    // We can check this by counting distinct characters.
    // If there's only one distinct character, it's impossible.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work,
        // then k=2 is always possible.
        // Consider the string s = "nolon". n=5.
        // s[0...0] = "n", s[1...1] = "o", s[2...2] = "l", s[3...3] = "o", s[4...4] = "n"
        // If we cut s into s[0...i-1], s[i...j-1], s[j...N-1]
        // For example, cut "nolon" into "no", "l", "on".
        // Rearrange to "on", "l", "no" -> "onlno". This is a palindrome and != "nolon".
        // This strategy works for any palindrome s that is not composed of all identical characters.
        // The strategy is: take s[0...N/2-1], s[N/2], s[N/2+1...N-1].
        // For example, s = "abacaba". N=7.
        // s1 = "aba", s2 = "c", s3 = "aba".
        // Rearrange to s3 + s2 + s1 = "abacaba" (original).
        // This specific rearrangement doesn't work.
        //
        // A simpler argument for k=2:
        // If s is a palindrome and not all characters are the same,
        // then s must have at least two distinct characters.
        // Consider the string s' formed by reversing the first half of s and appending the second half.
        // Example: s = "abacaba".
        // s[0...N/2-1] = "aba". Reverse it: "aba".
        // s[N/2...N-1] = "caba".
        // This is not how cuts work. Cuts are substrings.
        //
        // Let's re-evaluate the k=2 case.
        // If s is a palindrome and not all characters are the same,
        // then there must be at least one character s[i] such that s[i] != s[0].
        // Since s is a palindrome, s[i] == s[N-1-i].
        //
        // Consider the string s. If it's not all same characters, then there exists some `i` such that `s[i] != s[0]`.
        // Since `s` is a palindrome, `s[i] == s[N-1-i]`.
        //
        // If `N` is odd, `N = 2m+1`. `s = s[0...m-1] + s[m] + s[m+1...2m]`.
        // `s[0...m-1]` is the reverse of `s[m+1...2m]`.
        // Let `P1 = s[0...m-1]`, `P2 = s[m]`, `P3 = s[m+1...2m]`.
        // `s = P1 + P2 + P3`.
        // We know `P1` is the reverse of `P3`.
        // If we rearrange to `P3 + P2 + P1`, this is `s` reversed. Since `s` is a palindrome, `s` reversed is `s`.
        // So `P3 + P2 + P1 = s`. This doesn't work.
        //
        // The example "nolon" -> "onlno" uses 2 cuts.
        // "no" | "l" | "on" -> "on" | "l" | "no"
        // This is `s[3...4]` + `s[2...2]` + `s[0...1]`.
        // This is a valid rearrangement of 3 pieces.
        //
        // The problem states: "cut the paper minimum number of times k, so they got k+1 pieces of paper with substrings of the initial string, and then unite those pieces together to get a new string."
        //
        // If `s` is a palindrome and not all characters are the same, then `s` must contain at least two distinct characters.
        // This implies that `s` is not of the form `aaaa...a`.
        //
        // Consider the string `s`. If `N` is even, `N=2m`. `s = s[0...m-1] + s[m...2m-1]`.
        // `s[0...m-1]` is the reverse of `s[m...2m-1]`.
        // Let `A = s[0...m-1]` and `B = s[m...2m-1]`.
        // `s = A + B`. We know `A = reverse(B)`.
        // If we swap them, `B + A`. Since `A = reverse(B)`, `B = reverse(A)`.
        // So `B + A = reverse(A) + reverse(B)`. This is `reverse(A+B) = reverse(s) = s`.
        // So for even length palindromes, swapping the two halves always results in `s`.
        // This means `k=1` (one cut in the middle) will never produce a different string for even length palindromes.
        // Example: "otto". `A="ot"`, `B="to"`. `B+A = "toot"`. This is a palindrome and `!= "otto"`.
        // My reasoning above was flawed. `A = reverse(B)` means `A[i] = B[m-1-i]`.
        // `s = A + B`. `s[0...m-1] = A`, `s[m...2m-1] = B`.
        // `s[i] = s[N-1-i]`.
        // For `i < m`, `s[i] = A[i]`. `s[N-1-i] = B[m-1-i]`. So `A[i] = B[m-1-i]`.
        // The new string is `B + A`.
        // Is `B + A` a palindrome?
        // `(B+A)[j] = B[j]` for `j < m`.
        // `(B+A)[j] = A[j-m]` for `j >= m`.
        // `reverse(B+A)`:
        // `reverse(B+A)[j] = (B+A)[N-1-j]`.
        // If `j < m`: `reverse(B+A)[j] = (B+A)[N-1-j] = A[N-1-j-m] = A[m-1-j]`.
        // We need `B[j] == A[m-1-j]`. This is true from `A[i] = B[m-1-i]`.
        // So `B+A` is always a palindrome.
        //
        // So for `k=1`, if `s` has even length `N`, cutting in the middle `s[0...N/2-1]` and `s[N/2...N-1]`
        // and swapping them always produces a palindrome.
        // We just need to check if `s_new != s`.
        // This is exactly what the loop `for (int i = 1; i < n; ++i)` does.
        // If `s` is "otto", `i=2`. `s1="ot"`, `s2="to"`. `new_s = "toot"`. `new_s != s` and `is_palindrome(new_s)`. So `k=1`.
        //
        // The only case where `k=1` fails is if `new_s == s` for all possible cuts.
        // If `s` is a palindrome and not all characters are the same, then `k=2` is always possible.
        // The example "nolon" -> "onlno" shows this.
        // "nolon" is not all same characters. `k=1` fails for "nolon".
        // `i=1`: "olon" + "n" = "olonn" (not palindrome)
        // `i=2`: "lon" + "no" = "lonno" (not palindrome)
        // `i=3`: "on" + "nol" = "onnol" (not palindrome)
        // `i=4`: "n" + "nolo" = "nnolo" (not palindrome)
        // So for "nolon", `k=1` is not possible.
        // But "nolon" is not all same characters, so `k=2` is the answer.
        //
        // The logic seems to be:
        // 1. Try `k=1`. If any cut and swap works, output 1.
        // 2. If `k=1` doesn't work:
        //    a. If all characters in `s` are the same, output "Impossible".
        //    b. Otherwise (not all characters are the same), output 2.
        std::cout << 2 << std::endl;
    }

    return 0;
}

