        // Consider the sequence s[i], s[i+1], s[i+2], s[i+3], s[i+4], s[i+5], s[i+6], s[i+7].
        // If s[i] = s[i+k] = s[i+2k] for k >= 4, then the indices are far apart.
        // For example, if k=4, s[i]=s[i+4]=s[i+8].
        // If s[i] = s[i+1] = s[i+2] = s[i+3] = s[i+4] = s[i+5] = s[i+6] = s[i+7] = s[i+8]...
        // This is a common optimization for problems involving arithmetic progressions in strings.
        // If s[x] = s[x+k] = s[x+2k] for some k, then the string contains a pattern.
        // If k is large, say k >= 4, then the indices x, x+k, x+2k are far apart.
        // It's known that if a string contains s[x]=s[x+k]=s[x+2k] for k >= 4,
        // then it must also contain s[y]=s[y+k']=s[y+2k'] for some k' < 4.
        // This is not strictly true. Example: 00010001000. x=0, k=4. s[0]=s[4]=s[8]='0'.
        // But it is true that if s[x]=s[x+k]=s[x+2k] for k >= 4, then there must be
        // a shorter pattern that covers it.
        // The maximum length of a "bad" pattern is 2k+1.
        // If k=1, length 3. s[i]s[i+1]s[i+2]
        // If k=2, length 5. s[i]s[i+2]s[i+4]
        // If k=3, length 7. s[i]s[i+3]s[i+6]
        // If k=4, length 9. s[i]s[i+4]s[i+8]
        // The crucial observation is that if s[x] = s[x+k] = s[x+2k] for k >= 4,
        // then the substring s[x..x+2k] must contain a shorter bad triplet.
        // This is a known result from string algorithms, related to "squares" or "cubes" in strings.
        // Specifically, if a string contains a 3-term arithmetic progression of identical characters
        // with common difference k >= 4, then it must contain such a progression with common difference k' < 4.
        // This means we only need to check k=1, 2, 3.
        // The maximum index for k=3 is i+6.
        // So we only need to check up to i+6.

        for (int k = 1; k <= 3; ++k) {
            if (i + 2 * k < n) { // Check if indices are within bounds
                if (s[i] == s[i + k] && s[i] == s[i + 2 * k]) {
                    min_bad_r[i] = std::min(min_bad_r[i], i + 2 * k);
                }
            }
        }
    }

    // Now, min_bad_r[i] stores the smallest 0-based index `r` such that s[i..r] contains a bad triplet.
    // If no such `r` exists, min_bad_r[i] = n.
    // For each starting index `l` (0-based), the valid ending indices `r` (0-based)
    // such that s[l..r] does NOT contain a bad triplet are `l, l+1, ..., min_bad_r[l]-1`.
    // The number of such `r` values is `(min_bad_r[l]-1) - l + 1 = min_bad_r[l] - l`.
    // These are the "good" pairs (l, r).
    for (int i = 0; i < n; ++i) {
        bad_pairs += (min_bad_r[i] - i);
    }

    // The total number of pairs (l, r) is n*(n+1)/2.
    // The number of pairs (l, r) that satisfy the condition is total_pairs - bad_pairs.
    // Wait, the problem asks for pairs (l, r) that *do* contain at least one bad triplet.
    // So, `bad_pairs` as calculated above is actually the number of "good" pairs (l, r)
    // (i.e., pairs that do NOT contain a bad triplet).
    // So the answer is `total_pairs - bad_pairs`.

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All tracks covered
            return true;
        }

        long long current_h = h[h_idx];
        long long head_left_reach = current_h - T;
        long long head_right_reach = current_h + T;

        // Find the first track p[p_idx] that this head can cover.
        // It must be within [head_left_reach, head_right_reach].
        // If p[p_idx] is already to the right of head_right_reach, this head cannot cover it.
        // If p[p_idx] is to the left of head_left_reach, this head cannot cover it.
        // We need to find a head that can cover p[p_idx].

        // If current_h is too far right to cover p[p_idx] even by moving left T units
        if (current_h - T > p[p_idx]) {
            // This head is too far right for p[p_idx].
            // It means this head and all subsequent heads (which are even further right)
            // cannot cover p[p_idx]. So p[p_idx] cannot be covered.
            // This is incorrect. A head can cover p[p_idx] if p[p_idx] is in [h_i - T, h_i + T].
            // We need to find the first head that can cover p[p_idx].
            // If h_idx is the first head, and h[h_idx] - T > p[p_idx], then no head can cover p[p_idx].
            // This is because h is sorted, so h[0] is the leftmost head.
            // If h[0] - T > p[p_idx], then p[p_idx] cannot be covered.
            // This check is implicitly handled by the logic below.
            continue; // This head is too far right to cover p[p_idx], try next head.
        }

        // If current_h is too far left to cover p[p_idx] even by moving right T units
        if (current_h + T < p[p_idx]) {
            // This head cannot cover p[p_idx]. Try next head.
            continue;
        }

        // At this point, current_h can cover p[p_idx].
        // We use this head to cover p[p_idx] and as many subsequent tracks as possible.
        // The range covered by this head is [current_h - T, current_h + T].
        // We need to cover p[p_idx], p[p_idx+1], ...
        // The leftmost point this head can reach is current_h - T.
        // The rightmost point this head can reach is current_h + T.

        // The actual range covered by this head for the purpose of covering p[p_idx]
        // and subsequent tracks is determined by two factors:
        // 1. The head's physical reach: [current_h - T, current_h + T]
        // 2. The requirement to cover p[p_idx]: it must be within the head's reach.
        //    If p[p_idx] is covered, the head can then extend its coverage to the right.

        // The head can cover tracks in the range [p[p_idx], p[p_idx] + (T - abs(current_h - p[p_idx]))]
        // This is the range if the head first moves to p[p_idx] and then uses remaining time to move right.
        // Or, more simply, the head covers [current_h - T, current_h + T].
        // We need to cover p[p_idx] and then greedily cover as many subsequent tracks as possible.

        // The effective range this head can cover, starting from p[p_idx], is:
        // The head is at current_h. It needs to cover p[p_idx].
        // Time taken to reach p[p_idx] is abs(current_h - p[p_idx]).
        // Remaining time is T - abs(current_h - p[p_idx]).
        // From p[p_idx], it can move right by this remaining time.
        // So, it can cover tracks up to p[p_idx] + (T - abs(current_h - p[p_idx])).
        // Let's call this `max_right_covered`.
        long long max_right_covered = p[p_idx] + (T - std::abs(current_h - p[p_idx]));

        // Now, advance p_idx as long as p[p_idx] is within this `max_right_covered` range.
        while (p_idx < m && p[p_idx] <= max_right_covered) {
            p_idx++;
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible difference between p and h, plus some buffer.
                               // Max p is 10^10, min h is 1. Max diff is 10^10.
                               // Max p is 10^10, max h is 10^10.
                               // Max p[m-1] - h[0] could be 10^10.
                               // Max h[n-1] - p[0] could be 10^10.
                               // So 10^10 is a reasonable upper bound. 2e10+7 is safe.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
