#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        long long a_i;
        std::cin >> a_i;
        current_sum += a_i;
        current_xor ^= a_i;
    }

    // Case 1: Array is already good.
    // If current_sum == 2 * current_xor, we don't need to add anything.
    if (current_sum == 2 * current_xor) {
        std::cout << 0 << std::endl << std::endl;
        return;
    }

    // Case 2: Add two elements.
    // We want to find b1, b2 such that:
    // (current_sum + b1 + b2) = 2 * (current_xor ^ b1 ^ b2)
    // Let b1 = current_xor.
    // Then the equation becomes:
    // (current_sum + current_xor + b2) = 2 * (current_xor ^ current_xor ^ b2)
    // (current_sum + current_xor + b2) = 2 * b2
    // current_sum + current_xor = b2
    // So, b2 = current_sum + current_xor.
    // The two elements to add are current_xor and (current_sum + current_xor).
    // Let's verify this:
    // New sum = current_sum + current_xor + (current_sum + current_xor) = 2 * current_sum + 2 * current_xor
    // New xor = current_xor ^ current_xor ^ (current_sum + current_xor) = current_sum + current_xor
    // Is New sum = 2 * New xor?
    // (2 * current_sum + 2 * current_xor) = 2 * (current_sum + current_xor)
    // Yes, this holds true.
    // This strategy always works and adds 2 elements.

    std::cout << 2 << std::endl;
    std::cout << current_xor << " " << (current_sum + current_xor) << std::endl;
}

