}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool possible = false;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        char last1 = '0' - 1; // Represents -infinity
        char last2 = '0' - 1; // Represents -infinity
        bool current_possible = true;

        for (int i = 0; i < n; ++i) {
            char d_i = s[i];

            bool can_color_1 = (d_i >= last1);
            bool can_color_2 = (d_i >= last2);

            if (d_i < pivot_digit) { // Must be color 1
                if (can_color_1) {
                    result[i] = '1';
                    last1 = d_i;
                } else {
                    current_possible = false;
                    break;
                }
            } else if (d_i > pivot_digit) { // Must be color 2
                if (can_color_2) {
                    result[i] = '2';
                    last2 = d_i;
                } else {
                    current_possible = false;
                    break;
                }
            } else { // d_i == pivot_digit
                // Try to put in color 1 if possible and it maintains sorted order for color 1
                // and it's "better" to put it in color 1 (i.e., last1 <= pivot_digit)
                // If it can go into color 2, it's also fine.
                // The greedy choice here is to put it into color 2 if possible,
                // because that leaves more room for future smaller digits in color 1.
                // However, the problem states that S1S2 must be sorted.
                // This means last_S1 <= first_S2.
                // If we put pivot_digit into S1, then last1 becomes pivot_digit.
                // If we put pivot_digit into S2, then last2 becomes pivot_digit.
                // The critical point is that all digits in S1 must be <= all digits in S2.
                // So, if d_i == pivot_digit, it can go into S1 if d_i >= last1.
                // It can go into S2 if d_i >= last2.
                // If we put it into S1, then last1 becomes pivot_digit.
                // If we put it into S2, then last2 becomes pivot_digit.
                // The constraint is that all digits in S1 must be <= pivot_digit, and all digits in S2 must be >= pivot_digit.
                // This is exactly what the `pivot_digit` logic ensures.
                // So, if d_i == pivot_digit, we can put it into color 1 if it maintains S1's order.
                // Or we can put it into color 2 if it maintains S2's order.
                // To maximize chances, we should put it into color 2 if possible,
                // as it keeps last1 smaller, allowing more digits to be put into color 1 later.
                if (can_color_2) { // Prefer color 2 for pivot_digit if possible
                    result[i] = '2';
                    last2 = d_i;
                } else if (can_color_1) { // Otherwise, try color 1
                    result[i] = '1';
                    last1 = d_i;
                } else { // Cannot place d_i
                    current_possible = false;
                    break;
                }
            }
        }

        if (current_possible) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, LLONG_MAX); // b[i] stores the maximum possible initial value for a[i]
                                          // initialized to a very large value (effectively infinity)

    // Process operations in reverse to find constraints on initial values
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // Type 1: a_j = a_j + d
            // This operation adds d to a_j.
            // If we are working backwards, this means that the value of a_j *before* this operation
            // was (a_j_after - d).
            // So, if b[j] was the max allowed initial value for a_j based on later operations,
            // then for operations *before* this one, the max allowed initial value for a_j
            // effectively becomes b[j] - d.
            // We need to apply this to all j in [l, r].
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                if (b[j] != LLONG_MAX) { // Only adjust if it's not already unconstrained
                    b[j] -= ops[i].val;
                }
            }
        } else {
            // Type 2: max(a_j) = m for j in [l, r]
            // This means that for all j in [l, r], a_j <= m.
            // So, the initial value a_0[j] must be <= m (after accounting for future type 1 ops).
            // We update b[j] = min(b[j], m).
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val);
            }
        }
    }

    // If b[i] is still LLONG_MAX, it means there were no upper bound constraints on a_0[i].
    // We can set it to 0, as per problem statement |a_i| <= 10^9.
    // A value of 0 is safe and within bounds.
    for (int i = 0; i < n; ++i) {
        if (b[i] == LLONG_MAX) {
            b[i] = 0;
        }
    }

    // Now, verify the solution by simulating operations with the derived initial array `b`.
    std::vector<long long> current_a = b; // This will store the array state during simulation

    for (const auto& op : ops) {
        if (op.type == 1) {
            // Apply type 1 operation: a_j = a_j + d
            for (int j = op.l; j <= op.r; ++j) {
                current_a[j] += op.val;
            }
        } else {
            // Check type 2 operation: max(a_j) = m
            long long max_val = LLONG_MIN;
            for (int j = op.l; j <= op.r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // If all checks pass, print YES and the initial array `b`.
    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

