#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The simplest strategy is to reverse the permutation.
    // Let p' be the reversed permutation of p.
    // p'_i = p_{n-i-1}
    // The adjacent sums for p are [p_0+p_1, p_1+p_2, ..., p_{n-2}+p_{n-1}]
    // The adjacent sums for p' are [p'_0+p'_1, p'_1+p'_2, ..., p'_{n-2}+p'_{n-1}]
    // which are [p_{n-1}+p_{n-2}, p_{n-2}+p_{n-3}, ..., p_1+p_0]
    // These are the same set of sums, just in reverse order.
    // Sorting them will yield the same fingerprint.
    // The only case where p' might be equal to p is if p is a palindrome.
    // However, the problem statement guarantees that a solution exists.
    // For n=2, p=[1,2], p'=[2,1]. They are different.
    // For n=3, p=[1,2,3], p'=[3,2,1]. They are different.
    // For n=3, p=[1,3,2], p'=[2,3,1]. They are different.
    // A permutation p is a palindrome if p_i = p_{n-1-i} for all i.
    // For example, [1,2,1] is a palindrome, but it's not a permutation of length 3.
    // A permutation of length n can only be a palindrome if n is odd and the middle element is unique,
    // and elements are paired up. E.g., [1,2,3,2,1] is not a permutation of length 5.
    // A permutation cannot be a palindrome unless n=1 (which is not allowed here, n>=2).
    // For example, if p_0 = p_{n-1}, then p_0 and p_{n-1} must be the same value.
    // But a permutation must have distinct values. So p_0 cannot be equal to p_{n-1} unless n=1.
    // Therefore, for any n >= 2, p_0 != p_{n-1}.
    // This means that reversing any permutation of length n >= 2 will always result in a different permutation.
    // Specifically, p_0 != p_{n-1} implies that the first element of p is different from the first element of p'.
    // So p != p'.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

