        int n, d;
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        int max_a1 = a[0]; // Initial haybales in pile 1

        for (int i = 1; i < n; ++i) { // Iterate through piles from 2 to n (index 1 to n-1)
            int pile_idx = i;
            int haybales_in_pile = a[pile_idx];
            int cost_per_haybale = pile_idx; // Cost to move one haybale from pile (idx+1) to pile 1

            if (haybales_in_pile > 0 && d >= cost_per_haybale) {
                // Calculate how many haybales can be moved from this pile
                int num_can_move = d / cost_per_haybale;

                // Move min(haybales_in_pile, num_can_move) haybales
                int moved_haybales = std::min(haybales_in_pile, num_can_move);

                max_a1 += moved_haybales;
                d -= moved_haybales * cost_per_haybale;
            }
            if (d == 0) { // If no days left, stop
                break;
            }
        }
        std::cout << max_a1 << std::endl;
    }
    return 0;
}

