        // This means -1 must be divisible by 3, which is false.
        // So, the sum of digits (3n-1) is never divisible by 3.
        // Therefore, the number is never divisible by 3.
        // This strategy works for all n >= 2.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
