void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n); // 0 for white, 1 for black

    // For elements a_i such that 2*a_i = T, we need to alternate their colors.
    // We can assign 0 to the first, 1 to the second, 0 to the third, etc.
    // This minimizes pairs of (a_i, a_i) in the same group.
    // For example, if we have [T/2, T/2, T/2, T/2], we assign colors [0, 1, 0, 1].
    // This puts two T/2s in group 0 and two T/2s in group 1.
    // Each group will have 1 pair, total 2 pairs.
    // If we put all in one group, it would be 6 pairs.
    // If we put [0,0,1,1], group 0 has 1 pair, group 1 has 1 pair, total 2 pairs.
    // The alternating strategy is optimal for these specific elements.

    int current_color_for_half_T = 0;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (2 * a[i] < T) {
            p[i] = 0; // Smaller than T/2, assign to group 0
        } else if (2 * a[i] > T) {
            p[i] = 1; // Larger than T/2, assign to group 1
        } else { // 2 * a[i] == T
            p[i] = current_color_for_half_T;
            current_color_for_half_T = 1 - current_color_for_half_T; // Alternate color
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

