#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_dist = 0;
        int last_R_pos = -1; // Represents the last position from which a right jump was possible.
                             // Initially, the frog is at cell 0, which allows jumping right.
                             // So, effectively, the "last R" is at -1, and the distance to the next cell is 1.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // If we encounter an 'R', it means we can jump from this cell to the right.
                // The distance covered by the previous sequence of 'L's (or from the start)
                // is (current_R_pos - last_R_pos).
                // We need to be able to jump over this distance.
                max_dist = std::max(max_dist, i - last_R_pos);
                last_R_pos = i;
            }
        }

        // After iterating through the string, we might have a sequence of 'L's at the end,
        // or the entire string might be 'L's.
        // The final jump needs to be from the last 'R' cell (or cell 0 if no 'R's)
        // to cell n+1.
        // The distance for this final jump is (n + 1 - last_R_pos).
        max_dist = std::max(max_dist, n + 1 - last_R_pos);

        std::cout << max_dist << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents 2^i - 1 for the i-th staircase
        while (true) {
            long long cells_for_k_staircase = k * (k + 1) / 2;
            if (current_cost + cells_for_k_staircase <= x) {
                current_cost += cells_for_k_staircase;
                count++;
                k = k * 2 + 1; // Next staircase size is 2^(i+1) - 1
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

