#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the triangle from the apex up to height x_i
        // should be i times the area of a single piece.
        // Total area of carrot = (1/2) * 1 * h = h/2.
        // Area of one piece = (h/2) / n = h / (2n).
        // Area of triangle up to x_i = i * (h / (2n)).
        // Also, Area(x_i) = x_i^2 / (2h).
        // So, x_i^2 / (2h) = i * h / (2n).
        // x_i^2 = i * h^2 / n.
        // x_i = sqrt(i * h^2 / n) = h * sqrt(i / n).
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we will use for the alternating pattern to generate k distinct differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between left and right pointers.
    // The numbers used will be from 1 to k+1.
    // Example: k=3. Numbers 1, 2, 3, 4.
    // left=1, right=4.
    // Print 1. left becomes 2.
    // Print 4. right becomes 3.
    // Print 2. left becomes 3.
    // Print 3. right becomes 2.
    // Sequence: 1 4 2 3. Differences: |1-4|=3, |4-2|=2, |2-3|=1. Distinct: 1, 2, 3. (k=3 distinct differences)

    bool use_left = true;
    for (int i = 0; i <= k; ++i) { // We need k+1 numbers to generate k differences
        if (use_left) {
            std::cout << left << " ";
            left++;
        } else {
            std::cout << right << " ";
            right--;
        }
        use_left = !use_left;
    }

    // After generating k distinct differences using numbers from 1 to k+1,
    // the remaining numbers are k+2, k+3, ..., n.
    // We can append these numbers in increasing order.
    // This will only introduce a difference of 1 (e.g., |(k+1) - (k+2)| = 1).
    // Since 1 is already one of the k distinct differences (unless k=0, which is not allowed),
    // this does not add new distinct differences.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;
    int current_balance = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_needed > 0) {
                result += '(';
                open_needed--;
                current_balance++;
            }
        } else { // c == ')'
            if (close_needed > 0 && current_balance > 0) {
                result += ')';
                close_needed--;
                current_balance--;
            }
        }
        if (result.length() == k) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    int p = n - 1;

    // Find the end of the non-increasing suffix
    while (p > 0 && a[p-1] >= a[p]) {
        p--;
    }

    // Find the end of the non-decreasing suffix before that
    while (p > 0 && a[p-1] <= a[p]) {
        p--;
    }

    std::cout << p << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m > n) {
            std::cout << 0 << "\n";
            continue;
        }

        long long count = n / m;
        long long last_digit_m = m % 10;

        std::vector<long long> cycle_sums(10);
        for (int i = 1; i <= 10; ++i) {
            cycle_sums[i - 1] = (i * last_digit_m) % 10;
        }

        long long sum_of_one_cycle = 0;
        for (long long val : cycle_sums) {
            sum_of_one_cycle += val;
        }

        long long num_full_cycles = count / 10;
        long long remaining_elements = count % 10;

        long long total_sum = num_full_cycles * sum_of_one_cycle;

        for (int i = 0; i < remaining_elements; ++i) {
            total_sum += cycle_sums[i];
        }
        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
