int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);
    bool n_found = false;

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) {
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        // If max_val_in_row is n-1, then p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic is based on the observation that if p[i] is not n,
        // then there must be some p[k] = n. Then a[i][k] = min(p[i], n) = p[i].
        // So max_val_in_row will be p[i].
        // If p[i] is n, then for all j!=i, a[i][j] = min(n, p[j]) = p[j].
        // So max_val_in_row will be max(p[j] for j!=i) = n-1.
        if (max_val_in_row == n - 1) {
            p[i] = n;
            n_found = true;
