        // We need to find one such element and change its value to 'n'.
        for (int i = 0; i < n; ++i) {
            if (p[i] == current_max_val_in_p) {
                p[i] = n;
                break; // Only one element should be 'n'
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
