#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');

    // For m=1, the number 1 is always beautiful.
    // The subsegment is just [1] at its position.
    result[0] = '1';

    // For m > 1, we expand the current segment that contains 1, ..., m-1
    // to include m.
    // We maintain the minimum and maximum indices (left and right)
    // of the current segment that contains 1, ..., current_m.
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 2; m <= n; ++m) {
        int m_pos = pos[m];

        // Update the range [current_min_idx, current_max_idx]
        // to include the position of 'm'.
        current_min_idx = std::min(current_min_idx, m_pos);
        current_max_idx = std::max(current_max_idx, m_pos);

        // Check if the current segment [current_min_idx, current_max_idx]
        // is a permutation of 1, ..., m.
        // This requires its length to be exactly m.
        if (current_max_idx - current_min_idx + 1 == m) {
            result[m - 1] = '1';
        }
    }

    std::cout << result << std::endl;
}

