        }
    }

    // Let's find the maximum `k` such that `a[k-1], ..., a[n-1]` can be made `..., 1, 0`.
    // This means `a[i] >= (n-1-i)` for `k-1 <= i < n`.
    int min_right_idx = n;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            min_right_idx = i;
        } else {
            break;
        }
    }

    // If there is any `k` such that `a[0], ..., a[k-1]` can be `0, ..., k-1`
    // AND `a[k-1], ..., a[n-1]` can be `k-1, ..., 0` (relative to peak)
    // The peak element is `a[k-1]`.
    // For the left part: `a[0] < a[1] < ... < a[k-1]`. We can make this `0, 1, ..., k-1`.
    // This requires `a[i] >= i` for `0 <= i < k`.
    // For the right part: `a[k-1] > a[k] > ... > a[n-1]`. We can make this `k-1, k-2, ..., k-(n-k)`.
    // This requires `a[i] >= (k-1) - (i-(k-1))` for `k <= i < n`.
    // Which simplifies to `a[i] >= 2*(k-1) - i`.
    // Or, more simply, `a[i]` must be at least `n-1-i` if we want to make the right part `..., 1, 0`.
    // The peak `a[k-1]` must be able to be `k-1` (from left) and `n-k` (from right).
    // So `a[k-1]` must be at least `max(k-1, n-k)`.
    // But we can choose `a[k-1]` to be any value `v` such that `v >= k-1` and `v >= n-k`.
    // The crucial part is that `a[i]` must be able to be `i` for the left part,
    // and `a[i]` must be able to be `n-1-i` for the right part.
    // If we can find *any* `k` (1-indexed, so `a[k-1]` is the peak) such that:
    // 1. `a[i] >= i` for all `0 <= i < k`
    // 2. `a[i] >= (n-1-i)` for all `k <= i < n`
    // Then we can make the array sharpened.
    // The peak element `a[k-1]` must satisfy `a[k-1] >= k-1` and `a[k-1] >= n-k`.
    // This is covered by the two conditions.

    // The `max_left_idx` is the largest index `i` such that `a[0], ..., a[i]` can be `0, ..., i`.
    // The `min_right_idx` is the smallest index `i` such that `a[i], ..., a[n-1]` can be `n-1-i, ..., 0`.
    // If we pick `k-1` as the peak index, then `k-1` must be `<= max_left_idx`
    // AND `k-1` must be `>= min_right_idx`.
    // So, we need to check if `min_right_idx <= max_left_idx`.
    // If `min_right_idx <= max_left_idx`, it means there is at least one index `p`
    // such that `a[0...p]` can be `0...p` AND `a[p...n-1]` can be `p-(p-p)...p-(n-1-p)` (i.e. `p, p-1, ..., p-(n-1-p)`).
    // The second condition is `a[i] >= (n-1-i)` for `i >= p`.
    // So, if `min_right_idx <= max_left_idx`, we can choose any index `p` in `[min_right_idx, max_left_idx]` as the peak.
    // For such a `p`, `a[i] >= i` for `i <= p` and `a[i] >= n-1-i` for `i >= p`.
    // This means we can construct the array `0, 1, ..., p, p-1, ..., p-(n-1-p)`.
    // This is a sharpened array.

    if (min_right_idx <= max_left_idx) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

