// Function to check if Box 1 can be the special box
// Box 1: (-inf, -1]
bool can_be_box1(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 1) {
        return A == 1;
    }

    // Case 1: Final product is negative.
    // This requires an odd number of negative factors.
    // The magnitude must be >= 1.

    // To get a negative product, B must be odd, or A must be odd.
    // If A is odd, we can always make the product negative.
    // If A is even, B must be odd.
    // So, (A % 2) ^ (B % 2) must be 1.
    bool can_be_negative = ((A % 2) ^ (B % 2)) == 1;

    if (!can_be_negative) {
        return false; // Cannot be negative, so cannot be in Box 1.
    }

    // Now we know the product can be negative. We need its magnitude to be >= 1.
    // This means we need to be able to make the product large enough.

    // If there's at least one toy in Box 1 or Box 4, we can potentially make the product large.
    // If A > 0 or D > 0, we have at least one toy with magnitude >= 1.
    // If we have at least one such toy, and we can make the product negative,
    // we can always arrange multiplications to ensure the final product is >= 1 in magnitude.
    // For example, multiply all toys from Box 2 and Box 3 first.
    // Their product will be in (0, 1) if positive, or (-1, 0) if negative.
    // Then multiply this with a toy from Box 1 or Box 4.
    // If we have a toy from Box 1 (e.g., -2) and a toy from Box 4 (e.g., 2),
    // we can multiply them to get -4, which is in Box 1.
    // If we have a toy from Box 1 (e.g., -2) and a toy from Box 2 (e.g., -0.5),
    // we can multiply them to get 1, which is in Box 4.
    // If we have a toy from Box 1 (e.g., -2) and a toy from Box 3 (e.g., 0.5),
    // we can multiply them to get -1, which is in Box 1.
    // If we have a toy from Box 4 (e.g., 2) and a toy from Box 2 (e.g., -0.5),
    // we can multiply them to get -1, which is in Box 1.
    // If we have a toy from Box 4 (e.g., 2) and a toy from Box 3 (e.g., 0.5),
    // we can multiply them to get 1, which is in Box 4.

    // The only way to guarantee the magnitude is < 1 is if all initial toys have magnitude < 1.
    // This means A=0 and D=0.
    // If A=0 and D=0, then all toys are from Box 2 or Box 3.
    // Their product will always have magnitude < 1 (unless B=0 and C=0, which is not possible as total_toys > 0).
    // So, if A=0 and D=0, the final product will be in Box 2 or Box 3.
    // Thus, if A=0 and D=0, Box 1 cannot be the special box.
    if (A == 0 && D == 0) {
        return false;
    }

    // Otherwise, if we can make the product negative, and there's at least one toy with magnitude >= 1,
    // we can always make the final product negative and magnitude >= 1.
    // Example: If we have a toy X with |X| >= 1, and we need a negative product.
    // If the current product is P, and we need to multiply by X.
    // If P is positive, and X is negative (from Box 1), P*X is negative.
    // If P is negative, and X is positive (from Box 4), P*X is negative.
    // We can always pick values such that the magnitude is preserved or increased.
    // For example, if we have -3 (Box 1), -0.5 (Box 2), 0.5 (Box 3), 3 (Box 4).
    // We want Box 1. We need negative and >= 1.
    // (-0.5) * (0.5) = -0.25 (Box 2)
    // (-3) * (-0.25) = 0.75 (Box 3)
    // (3) * (0.75) = 2.25 (Box 4)
    // This sequence doesn't work.

    // Let's re-evaluate the magnitude part.
    // If A > 0 or D > 0, we have at least one toy with magnitude >= 1.
    // If we have at least one toy with magnitude >= 1, say $x_k$.
    // We can multiply all other $N-1$ toys first. Let their product be $P'$.
    // $P'$ can be arbitrarily close to 0 or 1 or -1 depending on the values.
    // Then we multiply $P'$ by $x_k$.
    // If $x_k$ is from Box 1, we can pick $x_k = -1$. Then $P' \cdot (-1)$ has the same magnitude as $P'$ but opposite sign.
    // If $x_k$ is from Box 4, we can pick $x_k = 1$. Then $P' \cdot 1$ has the same magnitude and sign as $P'$.
    // This doesn't help much with magnitude.

    // The crucial observation for magnitude is that if there is at least one toy with magnitude >= 1 (i.e., A > 0 or D > 0),
    // we can always choose values such that the final product has magnitude >= 1.
    // For example, if we have a toy $X$ from Box 1 or Box 4.
    // We can choose $X$ to be very large (e.g., $X = -100$ or $X = 100$).
    // All other toys $Y_i$ can be chosen to be very close to 1 or -1 (e.g., $Y_i = 0.99$ or $Y_i = -0.99$).
    // The product of $N-1$ toys with magnitude close to 1 will still have magnitude close to 1.
    // Then multiplying by $X$ will result in a large magnitude.
    // So, if A > 0 or D > 0, we can always achieve magnitude >= 1.

    // Combining:
    // 1. Product must be negative: (A % 2) ^ (B % 2) == 1.
    // 2. Product must have magnitude >= 1: A > 0 or D > 0.
    // If both conditions are met, Box 1 can be the special box.
    return can_be_negative && (A > 0 || D > 0);
}

// Function to check if Box 2 can be the special box
// Box 2: (-1, 0)
bool can_be_box2(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 1) {
        return B == 1;
    }

    // Case 1: Final product is negative.
    // This requires an odd number of negative factors.
    // So, (A % 2) ^ (B % 2) must be 1.
    bool can_be_negative = ((A % 2) ^ (B % 2)) == 1;

    if (!can_be_negative) {
        return false; // Cannot be negative, so cannot be in Box 2.
    }

    // Now we know the product can be negative. We need its magnitude to be < 1.
    // This means we need to be able to make the product small enough.

    // If all initial toys have magnitude < 1 (i.e., A=0 and D=0),
    // then the product of any subset of these toys will also have magnitude < 1.
    // So, if A=0 and D=0, and we can make the product negative, then it will be in Box 2.
    if (A == 0 && D == 0) {
        return true;
    }

    // What if A > 0 or D > 0? Can we still make the magnitude < 1?
    // Yes, we can. We can choose values for toys in Box 2 and Box 3 to be very small (e.g., 0.01 or -0.01).
    // We can choose values for toys in Box 1 and Box 4 to be very close to -1 or 1 (e.g., -1.01 or 1.01).
    // If we have a toy from Box 1 (e.g., -1.01) and a toy from Box 2 (e.g., -0.01),
    // their product is 0.0101 (Box 3).
    // If we have a toy from Box 1 (e.g., -1.01) and a toy from Box 3 (e.g., 0.01),
    // their product is -0.0101 (Box 2).
    // If we have a toy from Box 4 (e.g., 1.01) and a toy from Box 2 (e.g., -0.01),
    // their product is -0.0101 (Box 2).
    // If we have a toy from Box 4 (e.g., 1.01) and a toy from Box 3 (e.g., 0.01),
    // their product is 0.0101 (Box 3).

    // The key is that we can choose the values.
    // If we need a negative product with magnitude < 1:
    // We can pick all toys from Box 1 and Box 4 to be very close to -1 or 1 respectively.
    // For example, Box 1 toys are -1.000001, Box 4 toys are 1.000001.
    // Box 2 toys are -0.000001, Box 3 toys are 0.000001.
    // The product of all toys will be very small in magnitude.
    // The sign is determined by (A % 2) ^ (B % 2).
    // So, if we can make the product negative, we can always make its magnitude < 1 by choosing appropriate values.
    // For example, pick one toy from Box 2 (e.g., -0.001). Multiply all other toys.
    // The product of all other toys can be made arbitrarily close to 1 (if positive) or -1 (if negative).
    // Then multiply by -0.001. The result will be very small in magnitude.
    // The sign will be determined by the parity of negative numbers.
    // So, if (A % 2) ^ (B % 2) == 1, Box 2 can be the special box.
    return can_be_negative;
}

// Function to check if Box 3 can be the special box
// Box 3: (0, 1)
bool can_be_box3(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 1) {
        return C == 1;
    }

    // Case 1: Final product is positive.
    // This requires an even number of negative factors.
    // So, (A % 2) ^ (B % 2) must be 0.
    bool can_be_positive = ((A % 2) ^ (B % 2)) == 0;

    if (!can_be_positive) {
        return false; // Cannot be positive, so cannot be in Box 3.
    }

    // Now we know the product can be positive. We need its magnitude to be < 1.
    // This means we need to be able to make the product small enough.

    // If all initial toys have magnitude < 1 (i.e., A=0 and D=0),
    // then the product of any subset of these toys will also have magnitude < 1.
    // So, if A=0 and D=0, and we can make the product positive, then it will be in Box 3.
    if (A == 0 && D == 0) {
        return true;
    }

    // Similar to Box 2, if we can make the product positive, we can always make its magnitude < 1
    // by choosing appropriate values (e.g., all toys from Box 1 and Box 4 are close to -1 or 1,
    // and one toy from Box 3 is very small, like 0.001).
    // So, if (A % 2) ^ (B % 2) == 0, Box 3 can be the special box.
    return can_be_positive;
}

// Function to check if Box 4 can be the special box
// Box 4: [1, inf)
bool can_be_box4(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 1) {
        return D == 1;
    }

    // Case 1: Final product is positive.
    // This requires an even number of negative factors.
    // So, (A % 2) ^ (B % 2) must be 0.
    bool can_be_positive = ((A % 2) ^ (B % 2)) == 0;

    if (!can_be_positive) {
        return false; // Cannot be positive, so cannot be in Box 4.
    }

    // Now we know the product can be positive. We need its magnitude to be >= 1.
    // This means we need to be able to make the product large enough.

    // If there's at least one toy in Box 1 or Box 4, we can potentially make the product large.
    // If A > 0 or D > 0, we have at least one toy with magnitude >= 1.
    // Similar to Box 1, if A > 0 or D > 0, we can always achieve magnitude >= 1.
    // The only way to guarantee the magnitude is < 1 is if all initial toys have magnitude < 1.
    // This means A=0 and D=0.
    // If A=0 and D=0, then all toys are from Box 2 or Box 3.
    // Their product will always have magnitude < 1.
    // So, if A=0 and D=0, Box 4 cannot be the special box.
    if (A == 0 && D == 0) {
        return false;
    }

    // Combining:
    // 1. Product must be positive: (A % 2) ^ (B % 2) == 0.
    // 2. Product must have magnitude >= 1: A > 0 or D > 0.
    // If both conditions are met, Box 4 can be the special box.
    return can_be_positive && (A > 0 || D > 0);
}

