#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<ElementB> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    std::sort(a_elements.begin(), a_elements.end(), compareA);
    std::sort(b_elements.begin(), b_elements.end(), compareB);

    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // The i-th smallest B value (b_elements[i].value)
        // should be paired with the (m-1-i)-th largest A value (a_elements[m-1-i].value)
        // The original index of this B value is b_elements[i].original_index
        // This is where the A value should be placed in the output array.
        result_a_prime[b_elements[i].original_index] = a_elements[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a prefix of length `len` is a permutation
bool is_prefix_permutation(int len, const std::vector<int>& a, const std::vector<int>& prefix_max_val, const std::vector<bool>& prefix_distinct_ok) {
    if (len == 0) return false; // Permutations have non-zero length
    return prefix_max_val[len - 1] == len && prefix_distinct_ok[len - 1];
}

// Function to check if a suffix of length `len` is a permutation
bool is_suffix_permutation(int len, int n, const std::vector<int>& a, const std::vector<int>& suffix_max_val, const std::vector<bool>& suffix_distinct_ok) {
    if (len == 0) return false; // Permutations have non-zero length
    return suffix_max_val[n - len] == len && suffix_distinct_ok[n - len];
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute for prefixes
    std::vector<int> prefix_max_val(n);
    std::vector<bool> prefix_distinct_ok(n);
    std::vector<bool> seen_prefix(n + 1, false); // Max value can be n, so size n+1
    int current_max_prefix = 0;
    bool current_distinct_ok_prefix = true;

    for (int i = 0; i < n; ++i) {
        if (a[i] > n || seen_prefix[a[i]]) { // a[i] > n is technically not possible given constraints a_i <= n-1, but good for robustness
            current_distinct_ok_prefix = false;
        }
        if (a[i] > i + 1) { // If any element is greater than current length, it cannot be a permutation
            current_distinct_ok_prefix = false;
        }
        seen_prefix[a[i]] = true;
        current_max_prefix = std::max(current_max_prefix, a[i]);
        prefix_max_val[i] = current_max_prefix;
        prefix_distinct_ok[i] = current_distinct_ok_prefix;
    }

    // Precompute for suffixes
    std::vector<int> suffix_max_val(n);
    std::vector<bool> suffix_distinct_ok(n);
    std::vector<bool> seen_suffix(n + 1, false); // Max value can be n, so size n+1
    int current_max_suffix = 0;
    bool current_distinct_ok_suffix = true;

    for (int i = n - 1; i >= 0; --i) {
        int current_suffix_len = n - i;
        if (a[i] > n || seen_suffix[a[i]]) { // a[i] > n is technically not possible given constraints a_i <= n-1, but good for robustness
            current_distinct_ok_suffix = false;
        }
        if (a[i] > current_suffix_len) { // If any element is greater than current length, it cannot be a permutation
            current_distinct_ok_suffix = false;
        }
        seen_suffix[a[i]] = true;
        current_max_suffix = std::max(current_max_suffix, a[i]);
        suffix_max_val[i] = current_max_suffix;
        suffix_distinct_ok[i] = current_distinct_ok_suffix;
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 ranges from 1 to n-1
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        bool p1_is_perm = is_prefix_permutation(l1, a, prefix_max_val, prefix_distinct_ok);
        bool p2_is_perm = is_suffix_permutation(l2, n, a, suffix_max_val, suffix_distinct_ok);

        if (p1_is_perm && p2_is_perm) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

