char get_winning_move(char opponent_move) {
    if (opponent_move == 'R') return 'P';
    if (opponent_move == 'S') return 'R';
    if (opponent_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;

        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Iterate through R, P, S in a fixed order to ensure deterministic output
        // if counts are equal. The problem statement says "any of them" is fine.
        // R, P, S order is arbitrary but consistent.
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }

        char my_optimal_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < s.length(); ++i) {
            std::cout << my_optimal_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
    // A simple strategy is to append at most 3 elements.
    // Let's try to append two elements first.
    // We want S + b1 + b2 = 2 * (X ^ b1 ^ b2)
    // Consider appending X and then S+X.
    // New XOR sum: X' = X ^ X = 0
    // New sum: S' = S + X
    // This doesn't work directly because we need S' = 2X'.
    // If X' = 0, then we need S' = 0, which is not generally true.

    // Let's try to append two elements: X and current_sum.
    // This is not quite right. The problem states we can append at most 3 elements.
    // A common trick for these problems is to make the XOR sum 0, or make it equal to some value.

    // Let's try to append two elements: current_xor_sum and current_sum + current_xor_sum.
    // Let b1 = current_xor_sum.
    // The new XOR sum becomes X' = current_xor_sum ^ b1 = current_xor_sum ^ current_xor_sum = 0.
    // The new sum becomes S' = current_sum + b1 = current_sum + current_xor_sum.
    // Now we need S' = 2 * X', which means current_sum + current_xor_sum = 2 * 0 = 0.
    // This is only true if current_sum = 0 and current_xor_sum = 0, which is not general.

    // Let's try to append two elements: current_xor_sum and a value 'val' such that the final XOR sum is 'val'.
    // This is a common pattern:
    // 1. Append current_xor_sum.
    //    New sum: S_1 = current_sum + current_xor_sum
    //    New XOR sum: X_1 = current_xor_sum ^ current_xor_sum = 0
    // 2. Now we have S_1 and X_1 = 0. We need S_1 + b2 = 2 * (X_1 ^ b2) = 2 * b2.
    //    So, S_1 + b2 = 2 * b2
    //    S_1 = b2
    //    So, b2 should be S_1.
    //
    // This means we append two elements:
    // b1 = current_xor_sum
    // b2 = current_sum + current_xor_sum
    //
    // Let's check this:
    // Final sum S_final = current_sum + b1 + b2
    //                   = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    //                   = 2 * (current_sum + current_xor_sum)
    //
    // Final XOR sum X_final = current_xor_sum ^ b1 ^ b2
    //                       = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    //                       = 0 ^ (current_sum + current_xor_sum)
    //                       = current_sum + current_xor_sum
    //
    // Is S_final = 2 * X_final?
    // 2 * (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum)
    // Yes, it is!
    //
    // This strategy always works and appends exactly 2 elements.
    // The problem states "at most 3 elements", so 2 is fine.
    // The appended elements can be large, up to 10^18.
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // current_xor_sum can be up to 2^30 - 1 (approx 10^9).
    // So current_sum + current_xor_sum can be up to 10^14 + 10^9, which fits in long long.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

