#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it can be combined with all 'a's to its left
            // that are currently active.
            // Each 'a' to its left will eventually form an 'ab' with this 'b'.
            // When 'ab' -> 'bba', the 'a' moves past the 'b', and a new 'b' is created.
            // The new 'b' effectively doubles the number of 'a's that can pass this point.
            // So, if we have 'k' 'a's to the left of this 'b',
            // they will generate 'k' steps.
            // After these 'k' 'a's pass, they will have generated 'k' new 'b's.
            // These 'k' new 'b's effectively double the 'a's that can pass the *next* 'b' to the left.
            // This means the 'count_a' effectively doubles for the next 'b'.
            // The number of steps added by this 'b' is `count_a`.
            total_steps = (total_steps + count_a) % mod;

            // After this 'b' is processed, it effectively doubles the number of 'a's
            // that can pass through this position for any 'b's further to the left.
            // This is because each 'a' that passes this 'b' creates a new 'b'.
            // So, the 'a's that pass this 'b' effectively become '2a's for the next 'b' to the left.
            // This is equivalent to saying that the 'count_a' for the next 'b' is doubled.
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it adds to the current count of 'a's
            // that are waiting to be processed by a 'b' to their left.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        if (n == 0) { // Edge case, though constraints say n >= 1
            std::cout << 0 << "\n";
            continue;
        }
        if (n == 1) { // A single day cannot have a later lower price
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        int min_suffix_price = a[n - 1]; // Initialize with the last price

        // Iterate from the second to last day backwards
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix_price) {
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_suffix_price,
                // it means a[i] is less than or equal to the current minimum.
                // This a[i] could potentially become the new minimum for elements before it.
                min_suffix_price = a[i];
            }
        }
        std::cout << bad_prices_count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [x_coord, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [y_coord, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs counted twice (those with same x AND same y, i.e., identical points)
    for (auto const& [coords, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    if (n == 1) {
        return 1;
    }

    if (n % 2 != 0) { // N is odd
        return (n + 1) / 2; // Chanek takes 1, N becomes N-1 (even). Then N-1/2. Total (N-1)/2 + 1 = (N+1)/2
    } else { // N is even
        // Option 1: Chanek takes 1
        // N becomes N-1 (odd). Opponent takes (N-1+1)/2 = N/2.
        // Chanek gets 1 + (N-1)/2 = (N+1)/2.
        // This is the same as if N was odd.

        // Option 2: Chanek takes N/2
        // N becomes N/2.
        // Now it's opponent's turn with N/2 coins.
        // If N/2 is odd, opponent takes (N/2+1)/2 coins. Chanek gets N/2 + (N/2-1)/2.
        // If N/2 is even, opponent can take 1 or N/4.
        // This suggests a recursive structure.

        // Let's analyze the optimal strategy for even N.
        // If N is a power of 2 (N = 2^k):
        // Chanek can always take N/2.
        // N -> N/2 -> N/4 -> ... -> 2 -> 1.
        // Chanek takes N/2, N/8, N/32, ...
        // Opponent takes N/4, N/16, N/64, ...
        // If k is odd, Chanek takes N/2, N/8, ..., 2. Opponent takes N/4, N/16, ..., 1.
        // Chanek's total: N/2 + N/8 + ... + 2 = N * (1/2 + 1/8 + ... + 1/2^k)
        // Opponent's total: N/4 + N/16 + ... + 1 = N * (1/4 + 1/16 + ... + 1/2^k)
        // Sum of geometric series: a(1-r^m)/(1-r)
        // Chanek: N/2 * (1 - (1/4)^((k+1)/2)) / (1 - 1/4) = N/2 * (1 - 1/2^(k+1)) / (3/4) = 2N/3 * (1 - 1/2^(k+1))
        // Opponent: N/4 * (1 - (1/4)^((k-1)/2)) / (1 - 1/4) = N/4 * (1 - 1/2^(k-1)) / (3/4) = N/3 * (1 - 1/2^(k-1))
        // This is getting complicated.

        // Let's consider the total coins taken by Chanek (C) and Opponent (O). C+O = N.
        // Chanek wants to maximize C. Opponent wants to maximize O.
