                // C(2^k) = (2^(k+1) + (-1)^k) / 3.
                // Let's check this formula for k >= 1:
                // k=1 (N=2): (2^2 + (-1)^1)/3 = (4-1)/3 = 1. Correct.
                // k=2 (N=4): (2^3 + (-1)^2)/3 = (8+1)/3 = 3. Correct.
                // k=3 (N=8): (2^4 + (-1)^3)/3 = (16-1)/3 = 5. Correct.
                // k=4 (N=16): (2^5 + (-1)^4)/3 = (32+1)/3 = 11. Correct.
                // This formula works for powers of 2.

                // The general recursive solution is robust.
                // Let's implement it.

                // The iterative approach:
                // chanek_coins = 0
                // current_n = N
                // turn = 0 (0 for Chanek, 1 for Opponent)
                // while current_n > 0:
                //   if current_n == 1:
                //     if turn == 0: chanek_coins += 1
                //     break
                //   if current_n % 2 != 0: // odd
                //     if turn == 0: chanek_coins += 1
                //     current_n -= 1
                //   else: // even
                //     // This is the tricky part.
                //     // If it's Chanek's turn and N is even, he can take 1 or N/2.
                //     // If he takes 1, N becomes N-1 (odd). Opponent takes 1. N becomes N-2.
                //     // If he takes N/2, N becomes N/2.
                //     // The optimal strategy for even N is to take N/2 if N/2 is odd, or if N/2 is even and N/4 is odd.
                //     // This is not simple. The recursive definition is simpler.

                // Let's use the recursive definition.
                // C(N) = N - C(N/2) if N is even
                // C(N) = 1 + C((N-1)/2) if N is odd
                // Base case C(1) = 1.

                // This can be implemented iteratively by simulating the recursion.
                // We need to keep track of the current N and whether we are adding or subtracting.
                // Let `res` be the final answer.
                // `sign` = 1 initially (for N).
                // `current_n` = N.
                // while `current_n` > 1:
                //   if `current_n` % 2 != 0: // odd
                //     res += sign * 1;
                //     current_n = (current_n - 1) / 2;
                //   else: // even
                //     res += sign * current_n;
                //     sign *= -1;
                //     current_n /= 2;
                // res += sign * 1; // for C(1)

                // Let's trace N=6:
                // res = 0, sign = 1, current_n = 6
                // current_n=6 (even): res += 1 * 6 = 6. sign = -1. current_n = 3.
                // current_n=3 (odd): res += -1 * 1 = 5. current_n = (3-1)/2 = 1.
                // current_n=1: loop ends.
                // res += sign * 1 = 5 + (-1) * 1 = 4. Correct.

                // Let's trace N=5:
                // res = 0, sign = 1, current_n = 5
                // current_n=5 (odd): res += 1 * 1 = 1. current_n = (5-1)/2 = 2.
                // current_n=2 (even): res += 1 * 2 = 3. sign = -1. current_n = 1.
                // current_n=1: loop ends.
                // res += sign * 1 = 3 + (-1) * 1 = 2. Correct.

                // This iterative approach seems to work and is efficient.
                // The `sign` variable correctly handles the alternating addition/subtraction.
                // The `res` variable accumulates the terms.
                // The base case C(1)=1 is handled by the final `res += sign * 1`.
            }
        }
    }
}

long long calculate_chanek_score(long long n) {
    if (n == 1) {
        return 1;
    }
    if (n % 2 != 0) { // N is odd
        return 1 + calculate_chanek_score((n - 1) / 2);
    } else { // N is even
        // Check if N is a power of 2.
        // If N is a power of 2, the formula (2^(k+1) + (-1)^k) / 3 applies.
        // This is faster than recursion for powers of 2.
        // A number is a power of 2 if (n & (n-1)) == 0.
        if ((n & (n - 1)) == 0) {
            // N = 2^k. Find k.
            long long k = 0;
            long long temp_n = n;
            while (temp_n > 1) {
                temp_n /= 2;
                k++;
            }
            // k is the exponent.
            // C(2^k) = (2^(k+1) + (-1)^k) / 3.
            // 2^(k+1) can be calculated as n * 2.
            if (k % 2 == 0) { // k is even
                return (n * 2 + 1) / 3;
            } else { // k is odd
                return (n * 2 - 1) / 3;
            }
        } else {
            // N is even but not a power of 2.
            // The recursive formula N - C(N/2) is used.
            return n - calculate_chanek_score(n / 2);
        }
    }
}

