    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    for (int k = 0; k <= n; ++k) { // k is the number of items taken from the left
        int left_count = k;
        int right_count = n - k;

        long long current_energy = 0;

        // Energy for items taken from left
        current_energy += (prefix_sum[left_count] - prefix_sum[0]) * l;

        // Energy for items taken from right
        current_energy += (prefix_sum[n] - prefix_sum[n - right_count]) * r;

        // Penalty for left side
        if (left_count > right_count) {
            current_energy += (left_count - right_count - 1) * Ql;
        }
        // Penalty for right side
        else if (right_count > left_count) {
            current_energy += (right_count - left_count - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

