// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    if (n == 0) {
        return "0";
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) {
            pattern += '0';
        } else {
            pattern += '1';
        }
        n /= 10;
    }
    // Pad with '0's to the left to a fixed length (18 for max 10^18)
    // This ensures all patterns have the same length for map keys
    // and simplifies matching logic by making all patterns 18 chars long.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;

            // Pad the query pattern with '0's to the left to match the fixed length (18)
            // of the stored patterns.
            std::string padded_s = s;
            while (padded_s.length() < 18) {
                padded_s = '0' + padded_s;
            }

            // The stored patterns are reversed (right-to-left digits become left-to-right in string).
            // The query pattern `s` is given left-to-right, but its digits are matched right-to-left.
            // So, we need to reverse `s` to match the stored format.
            std::reverse(padded_s.begin(), padded_s.end());

            std::cout << counts[padded_s] << "\n";
        }
    }

    return 0;
}

