long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    std::map<long long, int> q_prime_factors;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            while (temp_q % i == 0) {
                q_prime_factors[i]++;
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        q_prime_factors[temp_q]++;
    }

    // Iterate through each prime factor of q
    for (auto const& [prime_factor, exponent] : q_prime_factors) {
        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= prime_factor;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

