#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    bool possible = true;

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char u = s[i];
        char v = s[i+1];
        adj[u - 'a'].insert(v);
        adj[v - 'a'].insert(u);
    }

    for (int i = 0; i < 26; ++i) {
        if (adj[i].size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    // Find starting points for paths (characters with 1 neighbor)
    // or isolated characters (0 neighbors)
    for (int i = 0; i < 26; ++i) {
        if (adj[i].size() <= 1 && !visited[i]) {
            char current_char = (char)('a' + i);

            // Build path
            while (current_char != 0 && !visited[current_char - 'a']) {
                visited[current_char - 'a'] = true;
                layout += current_char;

                char next_char = 0;
                for (char neighbor : adj[current_char - 'a']) {
                    if (!visited[neighbor - 'a']) {
                        next_char = neighbor;
                        break;
                    }
                }
                current_char = next_char;
            }
        }
    }

    if (layout.length() != 26) {
        // This means there's a cycle or a character with 2 neighbors that wasn't part of a path
        // starting from a 0 or 1 neighbor node.
        // Given the problem constraints (at most 2 neighbors), this implies a cycle.
        // A single row keyboard cannot contain cycles.
        std::cout << "NO\n";
        return;
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

