void solve() {
    int n;
    std::cin >> n;

    long long min_x = -2000000000LL; // Effectively negative infinity
    long long max_x = 2000000000LL;  // Effectively positive infinity
    long long min_y = -2000000000LL; // Effectively negative infinity
    long long max_y = 2000000000LL;  // Effectively positive infinity

    for (int i = 0; i < n; ++i) {
        long long x, y;
        int f1, f2, f3, f4;
        std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

        // f1: can move left (x-1, y)
        // If f1 == 0, robot cannot move left. So target X must be >= current x.
        if (f1 == 0) {
            min_x = std::max(min_x, x);
        }

        // f2: can move up (x, y+1)
        // If f2 == 0, robot cannot move up. So target Y must be <= current y.
        if (f2 == 0) {
            max_y = std::min(max_y, y);
        }

        // f3: can move right (x+1, y)
        // If f3 == 0, robot cannot move right. So target X must be <= current x.
        if (f3 == 0) {
            max_x = std::min(max_x, x);
        }

        // f4: can move down (x, y-1)
        // If f4 == 0, robot cannot move down. So target Y must be >= current y.
        if (f4 == 0) {
            min_y = std::max(min_y, y);
        }
    }

    if (min_x <= max_x && min_y <= max_y) {
        // A valid point exists. We can pick any point in the intersection.
        // The problem guarantees that if a point exists, one exists within [-10^5, 10^5].
        // Our current min_x, min_y might be outside this range if all robots
        // restrict it to be outside. However, the problem statement implies
        // that if a solution exists, we can find one within the bounds.
        // So, we can just output min_x and min_y.
        // The problem statement says "Both X and Y should not exceed 10^5 by absolute value".
        // This implies that if min_x is, say, 10^6, but a valid point (10^5, Y) exists,
        // we should output (10^5, Y).
        // However, the constraints on x_i, y_i are -10^5 to 10^5.
        // If a robot at (10^5, Y) cannot move right (f3=0), then max_x becomes 10^5.
        // If a robot at (-10^5, Y) cannot move left (f1=0), then min_x becomes -10^5.
        // So, min_x and max_x will naturally be within [-10^5, 10^5] if a solution exists
        // and is constrained by robot positions.
        // The "guaranteed" part means we don't need to clamp min_x, min_y to [-10^5, 10^5].
        // If min_x is 10^6, it means all robots require X >= 10^6.
        // If a solution exists, then min_x will be <= 10^5.
        // So, simply outputting min_x, min_y is correct.
        std::cout << 1 << " " << min_x << " " << min_y << "\n";
    } else {
        std::cout << 0 << "\n";
    }
}

