#include <iostream>
#include <algorithm> // For std::abs, std::min, std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        long long N = std::abs(n);
        long long M = std::abs(m);

        // Ensure N >= M for simpler logic
        if (N < M) {
            std::swap(N, M);
        }

        // Minimum moves required to reach (N, M) is N (by making M diagonal moves and N-M axial moves).
        // If k is less than N, it's impossible.
        if (k < N) {
            std::cout << -1 << "\n";
            continue;
        }

        // Calculate the number of diagonal moves if we reach (N, M) in exactly N moves.
        // This involves M diagonal moves (to reach (M, M)) and N-M axial moves (to reach (N, M)).
        // The remaining k - N moves must be "wasted" moves.
        long long remaining_moves = k - N;

        // If remaining_moves is even, we can waste them by moving (1,0) then (-1,0) or (1,1) then (-1,-1).
        // Each such pair of moves cancels out the position change and uses 2 moves.
        // These "wasted" moves can be made diagonal or axial.
        // To maximize diagonal moves, we prefer to make them diagonal.
        // If we have an even number of remaining_moves, we can make all of them diagonal.
        // For example, (x,y) -> (x+1, y+1) -> (x, y). This uses 2 diagonal moves.
        // So, if remaining_moves is even, we can add all of them as diagonal moves.
        if (remaining_moves % 2 == 0) {
            std::cout << k << "\n";
        } else {
            // If remaining_moves is odd, we cannot make all of them diagonal and end up at (N,M).
            // We must use at least one axial move among the "wasted" moves.
            // Consider the parity of coordinates.
            // If N and M have the same parity (e.g., (2,2) or (3,1)),
            // then after N moves, the current position (N,M) has coordinates with the same parity.
            // If we make an odd number of additional moves, the parity of one or both coordinates will flip.
            // For example, if we are at (N,M) and N,M are both even.
            // If we make one more move, we go to (N+dx, M+dy).
            // If dx=0, dy=1, we go to (N, M+1). N is even, M+1 is odd. Parity differs.
            // If dx=1, dy=1, we go to (N+1, M+1). N+1 is odd, M+1 is odd. Parity is same.
            // The key is that after an odd number of moves, the parity of the sum of coordinates (x+y) flips.
            // (0,0) has sum 0 (even).
            // After 1 move, (x,y) can be (1,0), (1,1), (0,1), etc. Sums are 1, 2, 1.
            // The parity of (x+y) changes with each move.
            // So, after k moves, the parity of (N+M) must be the same as the parity of k.
            // If (N+M) % 2 != k % 2, it's impossible.
            // This is equivalent to (N+M-k) % 2 != 0.
            // Or, (N-M) % 2 != (k-M) % 2.
            // Or, (N-k) % 2 != (M-k) % 2.
            // Let's use the (N+M) % 2 vs k % 2 condition.
            // If (N+M) % 2 != k % 2, it's impossible.
            // Example: (10,1) in 9 moves. N=10, M=1, k=9.
            // N+M = 11 (odd). k = 9 (odd). Parity matches.
            // Minimum moves N=10. k=9 < N=10. Impossible. This is caught by k < N.

            // Example: (2,2) in 3 moves. N=2, M=2, k=3.
            // k >= N is true.
            // remaining_moves = k - N = 3 - 2 = 1 (odd).
            // N+M = 4 (even). k = 3 (odd). Parity (N+M)%2 != k%2.
            // This means we cannot reach (N,M) in k moves if we only use diagonal moves for the "wasted" moves.
            // If remaining_moves is odd, we must use at least one axial move for the "wasted" moves.
            // This means we can't make all k moves diagonal.
            // We can make k-1 moves diagonal, and one axial move.
            // This one axial move will reduce the total diagonal moves by 1.
            // So, if remaining_moves is odd, we can achieve k-1 diagonal moves.
            // This is because we can make N-1 diagonal moves to reach (N-1, M-1), then one axial move to (N, M-1) or (N-1, M),
            // then one diagonal move to (N, M). This uses N+1 moves.
            // Or, more simply, if we have an odd number of remaining moves, we can use one axial move and remaining even moves as diagonal.
            // This means we lose 1 diagonal move from k.
            // So, the answer is k-1.

            // However, there's a special case. If N and M have different parities, and k has the same parity as N (and thus different from M).
            // Example: (4,3) in 7 moves. N=4, M=3, k=7.
            // k >= N is true.
            // remaining_moves = k - N = 7 - 4 = 3 (odd).
            // N+M = 7 (odd). k = 7 (odd). Parity matches.
            // So, we can reach it.
            // The logic for k-1 applies here. Output should be k-1 = 6.

            // The condition for impossibility is (N+M)%2 != k%2.
            // If (N+M)%2 != k%2, then it's impossible.
            // This is because each move changes the parity of (x+y).
            // (0,0) has (0+0)%2 = 0.
            // After k moves, the point (N,M) must have (N+M)%2 = k%2.
            // If this condition is not met, it's impossible.
            if ((N + M) % 2 != k % 2) {
                std::cout << -1 << "\n";
            } else {
                // If remaining_moves is odd, and (N+M)%2 == k%2,
                // it means we must have N and M with different parities.
                // (N+M) is odd. k is odd.
                // In this case, we can make k-2 diagonal moves and 2 axial moves.
                // For example, (0,0) -> (N-1, M-1) using M-1 diagonal moves.
                // Then (N-1, M-1) -> (N, M-1) using 1 axial move.
                // Then (N, M-1) -> (N, M) using 1 axial move.
                // This uses M-1 + 1 + 1 = M+1 moves.
                // The remaining k - (M+1) moves are wasted.
                // If N and M have different parities, then N-M is odd.
                // The minimum number of moves is N.
                // If k-N is odd, and N and M have different parities,
                // then N is even, M is odd, or vice versa.
                // (N+M) is odd. k is odd.
                // We can make N-1 diagonal moves to reach (N-1, M-1).
                // Then one axial move to (N, M-1).
                // Then one axial move to (N, M).
                // This uses N-1 + 1 + 1 = N+1 moves.
                // The number of diagonal moves is N-1.
                // The remaining k - (N+1) moves are even.
                // These can be made diagonal.
                // So total diagonal moves = (N-1) + (k - (N+1)) = k-2.
                std::cout << k - 2 << "\n";
            }
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < n; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int p = 2; p <= n; ++p) { // Vasya chooses position p (1-indexed), so index p-1
        double current_p_win_prob = 0.0;

        // Iterate over all possible first characters t[0]
        for (int c1_idx = 0; c1_idx < 26; ++c1_idx) {
            if (char_indices[c1_idx].empty()) continue;

            // Map to store counts of (t[0], t[p-1]) pairs
            // Key: t[p-1] character index, Value: count of occurrences
            std::map<int, int> pair_counts;

            // For each k such that s[k] == c1_char
            for (int k : char_indices[c1_idx]) {
                int c2_char_idx = s[(k + p - 1) % n] - 'a';
                pair_counts[c2_char_idx]++;
            }

            // Calculate win probability for this specific t[0]
            // Sum of (count of (t[0], t[p-1]) pairs where count is 1)
            int win_count_for_c1 = 0;
            for (auto const& [c2_char_idx, count] : pair_counts) {
                if (count == 1) {
                    win_count_for_c1++;
                }
            }

            // The number of times t[0] == c1_char occurs is char_indices[c1_idx].size()
            // The probability of observing t[0] == c1_char is char_indices[c1_idx].size() / N
            // If Vasya observes t[0] == c1_char, his conditional win probability is win_count_for_c1 / char_indices[c1_idx].size()
            // Contribution to total probability for this p and c1_char:
            // (char_indices[c1_idx].size() / N) * (win_count_for_c1 / char_indices[c1_idx].size())
            // which simplifies to win_count_for_c1 / N
            current_p_win_prob += static_cast<double>(win_count_for_c1);
        }
        current_p_win_prob /= n; // Divide by N to get probability

        total_win_prob = std::max(total_win_prob, current_p_win_prob);
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob << std::endl;

    return 0;
}

#include <iostream>
