void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    std::string result(n, ' ');
    bool found_solution = false;

    for (int pivot_val = 0; pivot_val <= 9; ++pivot_val) {
        std::vector<int> current_d1;
        std::vector<int> current_d2;
        std::string current_result(n, ' ');
        bool possible_for_pivot = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < pivot_val) {
                current_result[i] = '1';
                current_d1.push_back(d[i]);
            } else if (d[i] > pivot_val) {
                current_result[i] = '2';
                current_d2.push_back(d[i]);
            }
        }

        // Check if current_d1 is sorted
        for (size_t i = 0; i + 1 < current_d1.size(); ++i) {
            if (current_d1[i] > current_d1[i+1]) {
                possible_for_pivot = false;
                break;
            }
        }
        if (!possible_for_pivot) continue;

        // Check if current_d2 is sorted
        for (size_t i = 0; i + 1 < current_d2.size(); ++i) {
            if (current_d2[i] > current_d2[i+1]) {
                possible_for_pivot = false;
                break;
            }
        }
        if (!possible_for_pivot) continue;

        // Assign remaining digits (equal to pivot_val)
        // Greedily assign to color 2 if possible, otherwise to color 1
        // This ensures that digits equal to pivot_val are placed after all digits < pivot_val
        // and before all digits > pivot_val.
        // The crucial part is that all digits equal to pivot_val must be assigned to the same color
        // or split such that those assigned to 1 come before those assigned to 2.
        // The strategy is: assign all digits equal to pivot_val to color 2.
        // This is the simplest way to ensure the non-decreasing property for digits equal to pivot_val.
        // If we assign to color 1, it must be after all other color 1 digits.
        // If we assign to color 2, it must be before all other color 2 digits.
        // The problem is that digits equal to pivot_val can be interleaved.
        // The correct greedy strategy for digits equal to pivot_val is:
        // Assign to color 1 if it maintains sorted order for color 1.
        // Otherwise, assign to color 2 if it maintains sorted order for color 2.
        // This is equivalent to finding the first occurrence of pivot_val that must be color 2.
        // All pivot_val digits before that must be color 1. All pivot_val digits after that must be color 2.

        int last_d1_val = -1;
        if (!current_d1.empty()) {
            last_d1_val = current_d1.back();
        }

        int first_d2_val = 10;
        if (!current_d2.empty()) {
            first_d2_val = current_d2.front();
        }

        // Find the split point for digits equal to pivot_val
        int split_idx = -1; // Index of the first digit 'pivot_val' that must be colored '2'
        for (int i = 0; i < n; ++i) {
            if (d[i] == pivot_val) {
                if (current_result[i] == ' ') { // Only consider unassigned digits
                    if (d[i] < last_d1_val) { // This should not happen if last_d1_val is correctly updated
                        // This means a digit equal to pivot_val is smaller than a previous d1 digit.
                        // This implies an issue with the logic or an impossible case.
                        // Given the construction, last_d1_val will be < pivot_val.
                        // So d[i] (which is pivot_val) cannot be < last_d1_val.
                    }
                    if (d[i] < first_d2_val) { // Can be color 1 or 2
                        // Try to assign to color 1
                        // If current_d1 is empty or d[i] >= current_d1.back()
                        // This is the point where we decide.
                        // If we assign to 1, it must be >= last_d1_val.
                        // If we assign to 2, it must be <= first_d2_val.
                        // The strategy is to assign to 1 as long as possible.
                        // The first time we cannot assign to 1 (because it would break sorted order of d1),
                        // we must assign to 2. All subsequent pivot_val digits must also be 2.
                        // This is equivalent to finding the first pivot_val that is smaller than a later pivot_val that is forced to be 2.
                        // Or, more simply, find the first pivot_val that is greater than a previous pivot_val that was colored 1.
                        // This is not quite right.
                        // The correct approach for digits equal to pivot_val:
                        // All digits d[i] == pivot_val that are colored '1' must appear before all digits d[j] == pivot_val that are colored '2'.
                        // And within color '1' group, they must be non-decreasing.
                        // And within color '2' group, they must be non-decreasing.
                        // Since they are all 'pivot_val', this means their relative order must be preserved.
                        // So, we need to find a split point `k` such that d[i] == pivot_val for i < k are '1' and for i >= k are '2'.
                        // This split point `k` must satisfy:
                        // 1. last_d1_val <= pivot_val (always true by construction)
                        // 2. pivot_val <= first_d2_val (always true by construction)
                        // 3. The last '1' digit (which is pivot_val) must be <= the first '2' digit (which is pivot_val).
                        // This means we can pick any split point.
                        // To maximize chances of success, we want to make the '1' sequence as long as possible.
                        // So, we assign '1' to all pivot_val digits that appear before any '2' digit.
                        // And '2' to all pivot_val digits that appear after any '1' digit.
                        // This is the same as: find the first index `k` such that `d[k] == pivot_val` and `d[k]` must be colored '2'.
                        // This happens if `d[k]` is smaller than some `d[j]` where `j > k` and `d[j]` is colored '1'.
                        // This is getting complicated. Let's simplify.

                        // The condition is: last_digit_of_S1 <= first_digit_of_S2.
                        // If we assign a digit `d[i] == pivot_val` to color 1, it must be >= `last_d1_val`.
                        // If we assign a digit `d[i] == pivot_val` to color 2, it must be <= `first_d2_val`.
                        // Both are true since `last_d1_val < pivot_val < first_d2_val`.
                        // So, for digits equal to `pivot_val`, we can assign them to either color 1 or 2.
                        // The only constraint is that all `1`s must come before all `2`s among these `pivot_val` digits.
                        // This means there must be some index `k` such that `d[i] == pivot_val` for `i < k` are '1' and for `i >= k` are '2'.
                        // We need to find the largest `k` such that `d[i] == pivot_val` for `i < k` can be '1'.
                        // This means `d[i]` for `i < k` must be >= `last_d1_val`.
                        // And `d[i]` for `i >= k` must be <= `first_d2_val`.
                        // Since `d[i] == pivot_val`, these conditions are always met.
                        // So, we can pick any split point for `pivot_val` digits.
                        // Let's try to find the first `pivot_val` digit that is *forced* to be color 2.
                        // A `pivot_val` digit at index `i` is forced to be color 2 if there is some `d[j]` with `j > i` and `d[j] < pivot_val`.
                        // Because `d[j]` must be color 1, and `d[i]` (pivot_val) cannot be after `d[j]` (which is < pivot_val) in the color 1 sequence.
                        // So, `d[i]` must be color 2.

                        // Find the rightmost index `k` such that `d[k] < pivot_val`.
                        // All `d[i] == pivot_val` for `i < k` can be color 1.
                        // All `d[i] == pivot_val` for `i > k` must be color 2.
                        // This is the key.
                        // Let's find the first `pivot_val` digit that must be color 2.
                        // This happens if there's a `d[j] < pivot_val` after it.
                        // So, we iterate from right to left to find the first `d[j] < pivot_val`.
                        // All `d[i] == pivot_val` to the right of this `d[j]` must be color 2.
                        // All `d[i] == pivot_val` to the left of this `d[j]` can be color 1.

                        // Let's refine the split point for `pivot_val` digits.
                        // We want to assign as many `pivot_val` digits to color 1 as possible,
                        // while maintaining the non-decreasing property for color 1.
                        // And then assign the rest to color 2, maintaining non-decreasing for color 2.
                        // This means we find the first `d[i] == pivot_val` that we *must* assign to color 2.
                        // This happens if `d[i]` is followed by some `d[j]` (where `j > i`) such that `d[j] < pivot_val`.
                        // If `d[i]` were color 1, then `d[j]` would also have to be color 1 (since `d[j] < pivot_val`).
                        // But then `d[i]` (pivot_val) would be followed by `d[j]` (< pivot_val) in the color 1 sequence, breaking sorted order.
                        // So, `d[i]` must be color 2.
                        // All `d[k] == pivot_val` for `k < i` can be color 1.
                        // All `d[k] == pivot_val` for `k >= i` must be color 2.

                        int first_pivot_to_be_2 = n; // Index of the first d[i] == pivot_val that must be color 2
                        int min_suffix = 10; // Minimum digit in suffix d[i+1...n-1]
                        for (int i = n - 1; i >= 0; --i) {
                            if (d[i] == pivot_val) {
                                if (min_suffix < pivot_val) {
                                    first_pivot_to_be_2 = i;
                                }
                            } else if (d[i] < pivot_val) {
                                min_suffix = std::min(min_suffix, d[i]);
                            }
                        }

                        for (int i = 0; i < n; ++i) {
                            if (d[i] == pivot_val) {
                                if (i < first_pivot_to_be_2) {
                                    current_result[i] = '1';
                                    current_d1.push_back(d[i]);
                                } else {
                                    current_result[i] = '2';
                                    current_d2.push_back(d[i]);
                                }
                            }
                        }

                        // Re-check sortedness of current_d1 and current_d2 after adding pivot_val digits
                        for (size_t i = 0; i + 1 < current_d1.size(); ++i) {
                            if (current_d1[i] > current_d1[i+1]) {
                                possible_for_pivot = false;
                                break;
                            }
                        }
                        if (!possible_for_pivot) continue;

                        for (size_t i = 0; i + 1 < current_d2.size(); ++i) {
                            if (current_d2[i] > current_d2[i+1]) {
                                possible_for_pivot = false;
                                break;
                            }
                        }
                        if (!possible_for_pivot) continue;

                        // Check the merge condition: last_d1 <= first_d2
                        if (!current_d1.empty() && !current_d2.empty()) {
                            if (current_d1.back() > current_d2.front()) {
                                possible_for_pivot = false;
                            }
                        }
                        if (!possible_for_pivot) continue;

                        found_solution = true;
                        result = current_result;
                        break; // Found a solution for this pivot_val
                    }
                }
            }
        }

        if (found_solution) break;
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

