#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // diff_L[k] = (count of 1s among a_1...a_k) - (count of 2s among a_1...a_k)
    // We are interested in suffix sums from the perspective of eating from right to left.
    // Let's define diff_L[k] as the balance of jars a_k, a_{k+1}, ..., a_n
    // when k jars are eaten from the left, the remaining jars are a_1, ..., a_{n-k}
    // This is equivalent to considering the balance of jars a_1, ..., a_i for i from 0 to n.
    // Let's use a map to store balances for the left side.
    // map_L[balance] = number of jars eaten from left to achieve this balance.
    // The jars eaten are a_n, a_{n-1}, ..., a_{n-k+1}.
    // The remaining jars are a_1, ..., a_{n-k}.
    // Let's compute balance for the *remaining* jars.
    // balance_L[k] = (count of 1s in a_1...a_{n-k}) - (count of 2s in a_1...a_{n-k})
    // where k is the number of jars eaten from the left (from a_n down to a_1).
    // k ranges from 0 to n.
    // If k jars are eaten, the remaining jars are a_1, ..., a_{n-k}.
    // The balance for these remaining jars is what we need.
    // Let's compute this from left to right for a_1...a_n.
    // `left_balances[i]` will store the balance of `a_1...a_i`.
    // `left_balances_map[balance]` will store the minimum `i` such that `a_1...a_i` has `balance`.
    // No, this is not quite right. We need to know the balance of the *remaining* jars.
    // If we eat `k_L` jars from the left, we eat `a_n, a_{n-1}, ..., a_{n-k_L+1}`.
    // The remaining jars on the left are `a_1, ..., a_{n-k_L}`.
    // Let `bal_L[k_L]` be the balance of `a_1, ..., a_{n-k_L}`.
    // `k_L` goes from 0 to `n`.
    // `bal_L[0]` is the balance of `a_1, ..., a_n`.
    // `bal_L[1]` is the balance of `a_1, ..., a_{n-1}`.
    // ...
    // `bal_L[n]` is the balance of an empty set of jars (0).

    std::map<int, int> left_balances_map; // balance -> jars_eaten_from_left
    left_balances_map[0] = 0; // Initial state: 0 jars eaten, balance 0 (empty set of remaining jars)

    int current_balance_L = 0;
    for (int i = n - 1; i >= 0; --i) { // Iterate from a_n down to a_1
        if (a[i] == 1) {
            current_balance_L++;
        } else {
            current_balance_L--;
        }
        int jars_eaten_from_left = n - i;
        if (left_balances_map.find(current_balance_L) == left_balances_map.end()) {
            left_balances_map[current_balance_L] = jars_eaten_from_left;
        }
    }

    // Calculate prefix sums for the right side (jars n+1 to 2n)
    // `bal_R[k_R]` is the balance of `a_{n+k_R+1}, ..., a_{2n}`.
    // `k_R` goes from 0 to `n`.
    // `bal_R[0]` is the balance of `a_{n+1}, ..., a_{2n}`.
    // `bal_R[1]` is the balance of `a_{n+2}, ..., a_{2n}`.
    // ...
    // `bal_R[n]` is the balance of an empty set of jars (0).

    int min_total_eaten = 2 * n; // Max possible jars eaten

    // Case 1: No jars eaten from the right.
    // The balance of remaining right jars is `current_balance_R = 0`.
    // We need `current_balance_L + 0 = 0`, so `current_balance_L = 0`.
    // If `left_balances_map` contains 0, then `jars_eaten_from_left = left_balances_map[0]`.
    // Total eaten = `jars_eaten_from_left + 0`.
    if (left_balances_map.count(0)) {
        min_total_eaten = std::min(min_total_eaten, left_balances_map[0]);
    }

    int current_balance_R = 0;
    for (int i = n; i < 2 * n; ++i) { // Iterate from a_{n+1} up to a_{2n}
        if (a[i] == 1) {
            current_balance_R++;
        } else {
            current_balance_R--;
        }
        int jars_eaten_from_right = i - n + 1;

        // We need `balance_L + current_balance_R = 0`, so `balance_L = -current_balance_R`.
        if (left_balances_map.count(-current_balance_R)) {
            min_total_eaten = std::min(min_total_eaten, jars_eaten_from_right + left_balances_map[-current_balance_R]);
        }
    }

    std::cout << min_total_eaten << std::endl;
}

