    std::vector<int> right_ones; // Indices of 1s that are part of a 010 pattern

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 1 && a[i - 1] == 0 && a[i + 1] == 0) {
            left_ones.push_back(i);
            right_ones.push_back(i);
        }
    }

    if (left_ones.empty()) { // Already stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> L(left_ones.size());
    std::vector<int> R(right_ones.size());

    for (size_t i = 0; i < left_ones.size(); ++i) {
        int current_idx = left_ones[i];
        int count = 0;
        while (current_idx > 0 && a[current_idx - 1] == 1) {
            current_idx--;
            count++;
        }
        L[i] = count;
    }

    for (size_t i = 0; i < right_ones.size(); ++i) {
        int current_idx = right_ones[i];
        int count = 0;
        while (current_idx < n - 1 && a[current_idx + 1] == 1) {
            current_idx++;
            count++;
        }
        R[i] = count;
    }

    int max_k = 0;
    for (size_t i = 0; i < left_ones.size(); ++i) {
        if (L[i] != R[i]) {
            std::cout << -1 << std::endl;
            return 0;
        }
        max_k = std::max(max_k, L[i]);
    }

    std::cout << max_k + 1 << std::endl;

    std::vector<int> result_a = a;
    for (size_t i = 0; i < left_ones.size(); ++i) {
        int center_idx = left_ones[i];
        int len = L[i]; // This is the length of the block of 1s starting at center_idx and extending left
                        // or starting at center_idx and extending right.
                        // The actual block is from center_idx - len to center_idx + len.

        // The 1s in the range [center_idx - len, center_idx + len] will become 0s.
        // The number of steps for this block to become all zeros is len + 1.
        // Since we need max_k + 1 steps, all these 1s will eventually become 0s.
        // So, we set them to 0 in the final sequence.
        for (int j = center_idx - len; j <= center_idx + len; ++j) {
            result_a[j] = 0;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << result_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        long long good_substrings_count = 0;

        // Precompute prefix sums for '0's
        std::vector<int> prefix_zeros(n + 1, 0);
        for (int i = 0; i < n; ++i) {
            prefix_zeros[i + 1] = prefix_zeros[i] + (s[i] == '0');
        }

        for (int i = 0; i < n; ++i) {
            if (s[i] == '0') {
                continue; // Substring must start with '1' to have a non-zero value
            }

            long long current_val = 0;
            for (int j = i; j < n; ++j) {
                // Max length for current_val to be within reasonable bounds (2*10^5)
                // is about 18-19 bits.
                // If j - i + 1 > 19, current_val can exceed 2*10^5.
                // For L > 19, 2^L - 1 is much larger than L.
                // The maximum possible value for current_val is N, which is 2*10^5.
                // So, we only need to consider up to 18-19 bits.
                // 2^17 = 131072, 2^18 = 262144. So max 18 bits.
                // If j - i + 1 > 18, current_val will be > 2^18, which is > 2*10^5.
                // So, we can limit j to i + 18.
                if (j - i + 1 > 18) { // Max length of N is 2*10^5, 2^18 > 2*10^5
                    break;
                }

                current_val = (current_val << 1) | (s[j] - '0');

                if (current_val == 0) { // Should not happen if s[i] == '1'
                    continue;
                }

                int len = j - i + 1;
                if (current_val == len) {
                    good_substrings_count++;
                }
            }

            // Handle cases where the binary value is small, but the substring starts with '1'
            // and has leading zeros in its binary representation.
            // Example: s = "0001000", i = 3 (s[3] = '1')
            // Substring "1" (len 1, val 1) -> good
            // Substring "10" (len 2, val 2) -> good
            // Substring "100" (len 3, val 4) -> not good
            // Substring "1000" (len 4, val 8) -> not good
            //
            // Consider a substring s[i...j] where s[i] = '1'.
            // Its value is V = f(s[i...j]). Its length is L = j - i + 1.
            // We are looking for V = L.
            //
            // If V is small (e.g., V <= 18), then L is also small.
            // The loop above handles these cases.
            //
            // What if V is large, but the actual substring starts with '0's?
            // The problem statement says "substring s_l ... s_r is good if r - l + 1 = f(s_l ... s_r)".
            // And f(t) is "decimal representation of integer t written in binary form (possibly with leading zeroes)".
            // Example: f(011) = 3. Here, the binary string is "011", its length is 3. f("011") = 3. So "011" is good.
            //
            // This means we need to consider substrings starting with '0' as well.
            // The outer loop `for (int i = 0; i < n; ++i)` should not skip `s[i] == '0'`.
            // Let's restart the logic.

            // The maximum possible value for f(t) is N (2*10^5).
            // The maximum length of a binary string that can represent a value up to 2*10^5 is 18 bits (2^17 = 131072, 2^18 = 262144).
            // So, for any good substring s[l...r], its length L = r - l + 1 must be equal to f(s[l...r]).
            // This implies L <= 2*10^5.
            // If s[l] is '1', then f(s[l...r]) is at least 2^(L-1).
            // If s[l] is '0', then f(s[l...r]) is at most 2^(L-1)-1 (if there's a '1' later) or 0 (if all '0's).
            //
            // Case 1: Substring s[l...r] starts with '1'.
            // The value f(s[l...r]) is at least 2^(L-1).
            // We need L = f(s[l...r]).
            // Since L <= 2*10^5, we must have 2^(L-1) <= 2*10^5.
            // This means L-1 <= 17, so L <= 18.
            // So, for substrings starting with '1', we only need to check lengths up to 18.
            // The loop `for (int j = i; j < n; ++j)` with `if (j - i + 1 > 18) break;` handles this.
        }

        // Case 2: Substring s[l...r] starts with '0'.
        // Let s[l...r] be a good substring. Its length is L = r - l + 1.
        // Its value is V = f(s[l...r]). We need V = L.
        // Since s[l] = '0', the actual binary value V is determined by the first '1' and subsequent bits.
        // For example, if s[l...r] = "00101", L=5, V=5. This is good.
        //
        // Let's iterate through all possible starting positions `i`.
        // For each `i`, we find the first '1' at index `k >= i`.
        // If no '1' exists from `i` to `n-1`, then all substrings starting at `i` are all '0's.
        // For "000", L=3, V=0. Not good. Only "0" (L=1, V=0) is not good.
        // The only good substring of all '0's is "0" if L=0, but L must be >= 1.
        // So, if a substring is all '0's, it's never good (L >= 1, V = 0).
        //
        // So, for a substring s[i...j] to be good and start with '0', there must be at least one '1' in s[i...j].
        // Let `k` be the index of the first '1' in s[i...j]. So `i <= k <= j`.
        // The value V = f(s[i...j]) is equal to f(s[k...j]).
        // The length is L = j - i + 1.
        // We need L = f(s[k...j]).
        //
        // Let `val_k_j = f(s[k...j])`.
        // We need `j - i + 1 = val_k_j`.
        // This means `i = j - val_k_j + 1`.
        //
        // We can iterate `k` from `0` to `n-1`. If `s[k] == '1'`:
        // From this `k`, we can form binary numbers `s[k...j]`.
        // Let `val = f(s[k...j])`.
        // The length of `s[k...j]` is `len_k_j = j - k + 1`.
        // We are looking for a starting index `i` such that `i <= k` and `j - i + 1 = val`.
        // This means `i = j - val + 1`.
        //
        // For this `i` to be valid, two conditions must hold:
        // 1. `i >= 0` (always true if `j - val + 1 >= 0`)
        // 2. `i <= k` (meaning `j - val + 1 <= k`)
        // 3. All characters `s[i...k-1]` must be '0'.
        //
        // The maximum value of `val` is `N` (2*10^5).
        // So `len_k_j` can be at most 18.
        // We can iterate `k` from `0` to `n-1`.
        // If `s[k] == '1'`:
        //   Iterate `j` from `k` to `min(n-1, k + 17)`. (Max length of `s[k...j]` is 18)
        //   Calculate `val = f(s[k...j])`.
        //   If `val > N` (or `val > j+1` which is max possible length for `i=0`), break.
        //   Calculate `i_candidate = j - val + 1`.
        //   If `i_candidate < 0`, this `val` is too large for any valid `i`. Break.
        //   If `i_candidate <= k`:
        //     We need to check if `s[i_candidate...k-1]` are all '0's.
        //     This can be done efficiently using prefix sums of zeros.
        //     `prefix_zeros[k] - prefix_zeros[i_candidate]` gives the count of zeros in `s[i_candidate...k-1]`.
        //     If this count is equal to `k - i_candidate`, then all are zeros.
        //     If `k - i_candidate == 0`, it means `i_candidate == k`, so no leading zeros.
        //     In this case, `s[i_candidate]` is '1', which is handled by the first loop.
        //     So we only need to check `i_candidate < k`.
        //     If `i_candidate < k` and `prefix_zeros[k] - prefix_zeros[i_candidate] == k - i_candidate`, then we found a good substring.

        good_substrings_count = 0; // Reset count for the combined logic

        for (int k = 0; k < n; ++k) {
            long long current_val = 0;
            for (int j = k; j < n; ++j) {
                // Max length of s[k...j] is 18 for current_val to be <= N (2*10^5)
                if (j - k + 1 > 18) {
                    break;
                }
                current_val = (current_val << 1) | (s[j] - '0');

                if (current_val == 0) { // If s[k...j] is all zeros, it's not good (L >= 1, V = 0)
                    continue;
                }

                // Now we have a binary string s[k...j] with value `current_val`.
                // We are looking for a starting index `i` such that s[i...j] is good.
                // This means `j - i + 1 = current_val`.
                // So, `i = j - current_val + 1`.

                int i_candidate = j - static_cast<int>(current_val) + 1;

                // Conditions for i_candidate:
                // 1. i_candidate must be a valid index: `i_candidate >= 0`.
                // 2. The substring s[i_candidate...k-1] must consist only of '0's.
                //    This is true if `prefix_zeros[k] - prefix_zeros[i_candidate] == k - i_candidate`.
                // 3. `i_candidate <= k`. (If `i_candidate > k`, then `s[k]` is not the first '1' in `s[i_candidate...j]`,
                //    which contradicts our assumption that `k` is the first '1' for `f(s[k...j])` to be `current_val`).
                //    Actually, `i_candidate` can be equal to `k`. If `i_candidate == k`, then `s[k]` is the first char,
                //    and `s[k...j]` is the substring. This is the case where the substring starts with '1'.
                //    If `i_candidate < k`, then `s[i_candidate...k-1]` must be all '0's.

                if (i_candidate >= 0 && i_candidate <= k) {
                    // Check if s[i_candidate...k-1] are all '0's
                    if (prefix_zeros[k] - prefix_zeros[i_candidate] == k - i_candidate) {
                        good_substrings_count++;
                    }
                }
            }
        }

        std::cout << good_substrings_count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
