int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and_mask = 1023; // All bits 0-9 are 1
    int current_or_mask = 0;    // All bits 0-9 are 0
    int current_xor_mask = 0;   // All bits 0-9 are 0

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        if (op_char == '&') {
            current_and_mask &= val;
            current_or_mask &= val;
            current_xor_mask &= val;
        } else if (op_char == '|') {
            current_and_mask |= val;
            current_or_mask |= val;
            current_xor_mask |= val;
        } else if (op_char == '^') {
            current_and_mask ^= val;
            current_or_mask ^= val;
            current_xor_mask ^= val;
        }
    }

    std::vector<std::pair<char, int>> result_ops;

    // The final transformation for an input bit 'b' is:
    // ( (b & current_and_mask) | current_or_mask ) ^ current_xor_mask

    // We want to find A, O, X such that for any b in {0,1}:
    // ( (b & A) | O ) ^ X == ( (b & current_and_mask) | current_or_mask ) ^ current_xor_mask

    // Let's find the equivalent A, O, X for the two states of input bit b:
    // For b=0: (0 & A) | O ) ^ X = O ^ X
    // For b=1: (1 & A) | O ) ^ X = (A | O) ^ X

    // For b=0, the original transformation gives:
    // ( (0 & current_and_mask) | current_or_mask ) ^ current_xor_mask = current_or_mask ^ current_xor_mask
    // So, O ^ X must be equal to current_or_mask ^ current_xor_mask

    // For b=1, the original transformation gives:
    // ( (1 & current_and_mask) | current_or_mask ) ^ current_xor_mask = (current_and_mask | current_or_mask) ^ current_xor_mask
    // So, (A | O) ^ X must be equal to (current_and_mask | current_or_mask) ^ current_xor_mask

    // We can construct the final operations by considering each bit position independently.
    // For each bit j (0 to 9):
    // Let b_j be the j-th bit of the input.
    // Let A_j, O_j, X_j be the j-th bits of A, O, X.
    // Let and_j, or_j, xor_j be the j-th bits of current_and_mask, current_or_mask, current_xor_mask.

    // We need to find A_j, O_j, X_j such that:
    // ( (b_j & A_j) | O_j ) ^ X_j == ( (b_j & and_j) | or_j ) ^ xor_j

    // Case b_j = 0:
    // (0 & A_j) | O_j ) ^ X_j = O_j ^ X_j
    // (0 & and_j) | or_j ) ^ xor_j = or_j ^ xor_j
    // So, O_j ^ X_j = or_j ^ xor_j

    // Case b_j = 1:
    // (1 & A_j) | O_j ) ^ X_j = (A_j | O_j) ^ X_j
    // (1 & and_j) | or_j ) ^ xor_j = (and_j | or_j) ^ xor_j
    // So, (A_j | O_j) ^ X_j = (and_j | or_j) ^ xor_j

    // Let's try to find A, O, X.
    // A good strategy is to try to simplify the operations.
    // The final state of a bit `b` can be one of four functions:
    // 1. `0` (always 0)
    // 2. `1` (always 1)
    // 3. `b` (identity)
    // 4. `~b` (negation)

    // Let's determine the final state for each bit `j` for input `0` and `1`.
    // `f_j(0)` = ( (0 & current_and_mask) | current_or_mask ) ^ current_xor_mask
    // `f_j(1)` = ( (1 & current_and_mask) | current_or_mask ) ^ current_xor_mask

    // We can compute `f_j(0)` and `f_j(1)` for each bit `j`.
    // `f_j(0)` is the j-th bit of `(0 & current_and_mask) | current_or_mask) ^ current_xor_mask`
    // `f_j(1)` is the j-th bit of `(1 & current_and_mask) | current_or_mask) ^ current_xor_mask`

    // Let's define `val_0 = (0 & current_and_mask) | current_or_mask) ^ current_xor_mask`
    // Let's define `val_1 = (1 & current_and_mask) | current_or_mask) ^ current_xor_mask`

    // We need to find A, O, X such that:
    // `(0 & A) | O) ^ X == val_0`
    // `(1 & A) | O) ^ X == val_1`

    // This simplifies to:
    // `O ^ X == val_0`
    // `(A | O) ^ X == val_1`

    // From the first equation, `X = O ^ val_0`.
    // Substitute `X` into the second equation:
    // `(A | O) ^ (O ^ val_0) == val_1`

    // This is true for each bit. Let's find A, O, X bit by bit.
    // For each bit `j`:
    // `O_j ^ X_j = (val_0)_j`
    // `(A_j | O_j) ^ X_j = (val_1)_j`

    // We can choose `O_j` and `X_j` to satisfy the first equation.
    // For example, we can set `O_j = (val_0)_j` and `X_j = 0`.
    // Or `O_j = 0` and `X_j = (val_0)_j`.
    // Or `O_j = 1` and `X_j = 1 ^ (val_0)_j`.

    // Let's try to construct A, O, X directly.
    // We want to find A, O, X such that for any bit `b`:
    // `(b & A) | O) ^ X` is the desired output bit.

    // Consider the bits of `A`, `O`, `X`.
    // `A` will control which bits are affected by the input `b`.
    // `O` will set bits to 1 regardless of `b` (if `A` allows).
    // `X` will flip bits.

    // Let's try to construct the final `&`, `|`, `^` operations.
    // The final `&` mask will be `A`.
    // The final `|` mask will be `O`.
    // The final `^` mask will be `X`.

    // We need to find `A`, `O`, `X` such that:
    // `(x & A) | O) ^ X` is the final result.

    // Let's determine `A`, `O`, `X` bit by bit.
    // For each bit `j` from 0 to 9:
    // Let `b_j` be the j-th bit of the input `x`.
    // Let `and_j`, `or_j`, `xor_j` be the j-th bits of `current_and_mask`, `current_or_mask`, `current_xor_mask`.

    // The final output bit `res_j` is `((b_j & and_j) | or_j) ^ xor_j`.

    // We want to find `A_j`, `O_j`, `X_j` such that `((b_j & A_j) | O_j) ^ X_j = res_j`.

    // Let's analyze the four possible outcomes for `res_j` based on `b_j`:
    // 1. `res_j` is always 0 (i.e., `res_j` is 0 when `b_j=0` AND `res_j` is 0 when `b_j=1`).
    //    This means `((0 & and_j) | or_j) ^ xor_j = 0` AND `((1 & and_j) | or_j) ^ xor_j = 0`.
    //    This implies `(or_j ^ xor_j) = 0` AND `((and_j | or_j) ^ xor_j) = 0`.
    //    So, `or_j = xor_j` AND `(and_j | or_j) = xor_j`.
    //    Substituting `or_j = xor_j` into the second: `(and_j | xor_j) = xor_j`.
    //    This means `and_j` must be 0.
    //    So, if `and_j = 0` and `or_j = xor_j`, then `res_j` is always 0.
    //    To achieve this with `A_j, O_j, X_j`: set `A_j=0, O_j=0, X_j=0`. Then `((b_j & 0) | 0) ^ 0 = 0`.

    // 2. `res_j` is always 1 (i.e., `res_j` is 1 when `b_j=0` AND `res_j` is 1 when `b_j=1`).
    //    This means `(or_j ^ xor_j) = 1` AND `((and_j | or_j) ^ xor_j) = 1`.
    //    So, `or_j != xor_j` AND `(and_j | or_j) != xor_j`.
    //    If `or_j != xor_j`, then `or_j ^ xor_j = 1`.
    //    If `(and_j | or_j) != xor_j`, then `(and_j | or_j) ^ xor_j = 1`.
    //    This implies `or_j = ~xor_j` and `(and_j | or_j) = ~xor_j`.
    //    Substituting `or_j = ~xor_j`: `(and_j | ~xor_j) = ~xor_j`.
    //    This means `and_j` must be 0.
    //    So, if `and_j = 0` and `or_j != xor_j`, then `res_j` is always 1.
    //    To achieve this with `A_j, O_j, X_j`: set `A_j=0, O_j=1, X_j=0`. Then `((b_j & 0) | 1) ^ 0 = 1`.

    // 3. `res_j` is `b_j` (identity).
    //    This means `res_j` is 0 when `b_j=0` AND `res_j` is 1 when `b_j=1`.
    //    So, `(or_j ^ xor_j) = 0` AND `((and_j | or_j) ^ xor_j) = 1`.
    //    This implies `or_j = xor_j` AND `(and_j | or_j) != xor_j`.
    //    Substituting `or_j = xor_j`: `(and_j | xor_j) != xor_j`.
    //    This means `and_j` must be 1.
    //    So, if `and_j = 1` and `or_j = xor_j`, then `res_j` is `b_j`.
    //    To achieve this with `A_j, O_j, X_j`: set `A_j=1, O_j=0, X_j=0`. Then `((b_j & 1) | 0) ^ 0 = b_j`.

    // 4. `res_j` is `~b_j` (negation).
    //    This means `res_j` is 1 when `b_j=0` AND `res_j` is 0 when `b_j=1`.
    //    So, `(or_j ^ xor_j) = 1` AND `((and_j | or_j) ^ xor_j) = 0`.
    //    This implies `or_j != xor_j` AND `(and_j | or_j) = xor_j`.
    //    Substituting `or_j = ~xor_j`: `(and_j | ~xor_j) = xor_j`.
    //    This means `and_j` must be 1.
    //    So, if `and_j = 1` and `or_j != xor_j`, then `res_j` is `~b_j`.
    //    To achieve this with `A_j, O_j, X_j`: set `A_j=1, O_j=0, X_j=1`. Then `((b_j & 1) | 0) ^ 1 = ~b_j`.

    // Summary for each bit `j`:
    // Let `f0 = (current_or_mask >> j) & 1;`
    // Let `f1 = ((current_and_mask >> j) & 1) | ((current_or_mask >> j) & 1);`
    // Let `fxor = (current_xor_mask >> j) & 1;`
    // `final_f0 = f0 ^ fxor;`
    // `final_f1 = f1 ^ fxor;`

    // If `final_f0 == 0` and `final_f1 == 0`: `res_j` is always 0.
    // If `final_f0 == 1` and `final_f1 == 1`: `res_j` is always 1.
    // If `final_f0 == 0` and `final_f1 == 1`: `res_j` is `b_j`.
    // If `final_f0 == 1` and `final_f1 == 0`: `res_j` is `~b_j`.

    // We can construct the final A, O, X masks:
    int final_A = 0; // for &
    int final_O = 0; // for |
    int final_X = 0; // for ^

    for (int j = 0; j < 10; ++j) {
        int and_j = (current_and_mask >> j) & 1;
        int or_j = (current_or_mask >> j) & 1;
        int xor_j = (current_xor_mask >> j) & 1;

        int res_0 = (or_j ^ xor_j);
        int res_1 = ((and_j | or_j) ^ xor_j);

        if (res_0 == 0 && res_1 == 0) { // Always 0
            // A_j=0, O_j=0, X_j=0
            // (b_j & 0) | 0) ^ 0 = 0
        } else if (res_0 == 1 && res_1 == 1) { // Always 1
            // A_j=0, O_j=1, X_j=0
            // (b_j & 0) | 1) ^ 0 = 1
            final_O |= (1 << j);
        } else if (res_0 == 0 && res_1 == 1) { // Identity (b_j)
            // A_j=1, O_j=0, X_j=0
            // (b_j & 1) | 0) ^ 0 = b_j
            final_A |= (1 << j);
        } else { // res_0 == 1 && res_1 == 0 (Negation (~b_j))
            // A_j=1, O_j=0, X_j=1
            // (b_j & 1) | 0) ^ 1 = ~b_j
            final_A |= (1 << j);
            final_X |= (1 << j);
        }
    }

    // Now, we have final_A, final_O, final_X.
    // The operations are: `& final_A`, `| final_O`, `^ final_X`.
    // We need to output them if they are not identity operations.
    // `& 1023` is identity.
    // `| 0` is identity.
    // `^ 0` is identity.

    if (final_A != 1023) {
        result_ops.push_back({'&', final_A});
    }
    if (final_O != 0) {
        result_ops.push_back({'|', final_O});
    }
    if (final_X != 0) {
        result_ops.push_back({'^', final_X});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, LLONG_MAX); // Store upper bounds for initial_a[i]
                                                  // Initialize with a very large value

    // Process operations in reverse to determine initial_a bounds
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // If we add d to a[j] in forward pass, it means a[j] was a[j]-d before this op.
            // So, if initial_a[j] was bounded by X, it's now bounded by X-d.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                if (initial_a[j] != LLONG_MAX) { // Only adjust if it's already bounded
                    initial_a[j] -= ops[i].val;
                }
            }
        } else { // type == 2
            // This operation states max(a[j]) = m.
            // In reverse, this means that for all j in [l, r], initial_a[j] must be <= m.
            // And for at least one j in [l, r], initial_a[j] must be exactly m.
            // For now, we only set the upper bound.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val);
            }
        }
    }

    // If any initial_a[j] is still LLONG_MAX, it means it was never constrained by a type 2 op.
    // We can set it to 0, as it won't affect any max constraints.
    // The problem states |a_i| <= 10^9, so 0 is a valid choice.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == LLONG_MAX) {
            initial_a[i] = 0;
        }
    }

    // Verify the solution
    std::vector<long long> current_a = initial_a;
    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_a[j] += op.val;
            }
        } else { // type == 2
            long long max_val = LLONG_MIN;
            for (int j = op.l; j <= op.r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>

int count_ones(const std::string& s) {
    return std::count(s.begin(), s.end(), '1');
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a, b;
    std::cin >> a >> b;

    int ones_a = count_ones(a);
    int ones_b = count_ones(b);

    // If initial string 'a' has odd number of ones, we can append '1' to make it even.
    // If initial string 'a' has even number of ones, we can append '0' to keep it even.
    // In either case, after one 'append parity' operation, the string will have an even number of ones.
    // And any subsequent 'append parity' operation will append '0' (since parity is 0),
    // maintaining an even number of ones.
    // So, the maximum number of ones we can achieve in 'a' is ones_a + (ones_a % 2).
    // This is equivalent to (ones_a + 1) / 2 * 2, or simply ones_a if ones_a is even, and ones_a + 1 if ones_a is odd.
    // A simpler way to express this is: if ones_a is odd, we can make it ones_a + 1.
    // If ones_a is even, it stays ones_a.
    // So, the maximum number of ones we can have in 'a' (after potentially one parity op) is ones_a_max.
    int ones_a_max = ones_a;
    if (ones_a % 2 != 0) {
        ones_a_max++;
    }

    // We can always remove characters from the beginning of 'a'.
    // This means we can always reduce the length of 'a' down to 1 (or 0 if we remove all).
    // The number of ones in 'a' can also be reduced by removing '1's from the beginning.
    // The maximum length 'a' can reach is |a| + (number of parity operations).
    // The minimum length 'a' can reach is 1 (or 0 if we consider empty string, but problem implies non-empty).
    // We need to be able to form 'b'.
    // This means the number of ones in 'b' must be less than or equal to the maximum number of ones we can achieve in 'a'.
    // And the length of 'b' must be less than or equal to the maximum length 'a' can achieve.

    // The maximum number of ones we can have in 'a' (after potentially one parity op) is ones_a_max.
    // If ones_b is greater than ones_a_max, it's impossible.
    if (ones_b > ones_a_max) {
        std::cout << "NO\n";
        return 0;
    }

    // The length of 'b' must be less than or equal to the length of 'a' after any necessary parity operations.
    // The maximum length 'a' can effectively have for comparison is |a| + (1 if ones_a is odd, else 0).
    // This is because if ones_a is odd, we must perform one parity operation to get an even number of ones.
    // If ones_a is already even, we don't strictly need to perform a parity operation to get an even number of ones,
    // but we can still perform it (appending '0') to increase length.
    // However, the crucial point is that if we need to match 'b', we can always append '0's to 'a'
    // (after its parity becomes 0) to increase its length until it's at least |b|.
    // The only constraint is the number of '1's.
    // So, if ones_b <= ones_a_max, it means we can achieve at least 'ones_b' number of '1's.
    // And we can always make the string long enough by appending '0's (since parity will be 0).
    // The only remaining constraint is that the length of 'b' must be achievable.
    // The minimum length of 'a' is 1. The maximum length of 'a' is effectively infinite if we keep appending '0's.
    // So, if ones_b <= ones_a_max, we can always form 'b'.

    std::cout << "YES\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for x and y to prevent overflow, as y can be large.
// x can also become large or small, potentially exceeding int range if a_x is large.
// The problem statement says a_i <= 10^9, so x can become 1 + 10^9, which fits in long long.
// y can accumulate multiple 10^9 values.

// This problem can be modeled as a graph problem or a dynamic programming problem.
// Each state can be defined by (current_x, current_parity_of_step).
// The parity of step determines whether we add a_x to x or subtract a_x from x.
// Let's define states as (current_x, is_add_step).
// is_add_step = true means we are about to execute x = x + a_x.
// is_add_step = false means we are about to execute x = x - a_x.

// The initial state for each run is x=1, y=0.
// The first operation is x = x + a_x, y = y + a_x.
// So, from (1, 0), we first calculate val = a[1].
// New state: x = 1 + val, y = val. This is an 'add' step.
// The next operation will be y = y + a_x, x = x - a_x. This is a 'subtract' step.

// Let's define dp[i][0] as the final y value if we start at x=i and the next operation is x = x + a_i, y = y + a_i.
// Let's define dp[i][1] as the final y value if we start at x=i and the next operation is y = y + a_i, x = x - a_i.
// We also need to store whether it terminates or not. A special value like -2 can indicate non-termination.

// The values of a_i can be up to 10^9. This means x can jump very far.
// The maximum value of n is 2 * 10^5.
// A direct DP approach would be O(N) for each query, leading to O(N^2) total, which is too slow (2e5 * 2e5 = 4e10).

// Since x can jump far, this suggests a "jump" or "square root decomposition" optimization, or a specific DP structure.
// Notice that if x + a_x > N, it terminates. If x - a_x <= 0, it terminates.
// If x + a_x <= N and x - a_x > 0, then the next state is within bounds.
// The key observation is that if x + a_x > N, the next state is out of bounds.
// If x - a_x <= 0, the next state is out of bounds.

// Let's define `memo[x][parity]` to store the result for a state (x, parity).
// `parity = 0` means we are about to do `x = x + a_x`, `y = y + a_x`.
// `parity = 1` means we are about to do `y = y + a_x`, `x = x - a_x`.

// `memo[x][parity]` will store a pair: `{total_y_added, final_x_value}`.
// If it terminates, `final_x_value` will be the x value that caused termination.
// If it loops, `total_y_added` could be -1 or some other indicator.

// The problem has a structure similar to "jumps on an array".
// We can use memoization with path compression.
// For each (x, parity) state, we compute the next state.
// If the next state is out of bounds, we return the current y and the terminating x.
// If the next state is already computed, we use its result.
// If the next state is currently being computed (part of the current path), we detect a cycle.

// Let's define `dp[x][0]` as the pair `{total_y_added, final_x_value}` if we start at `x` and the next step is `x += a_x`.
// Let `dp[x][1]` as the pair `{total_y_added, final_x_value}` if we start at `x` and the next step is `x -= a_x`.
// `final_x_value` is the x value *after* the last valid step, before termination.
// Or, it could be the x value that caused termination. Let's make it the x value *before* the step that causes termination.
// No, it's simpler to just store the total y and the final x.

// `dp[x][parity]` stores `pair<long long, long long>`: `{total_y_accumulated, final_x_position}`.
// `total_y_accumulated` is the sum of `a_val`s added to `y` from this state until termination.
// `final_x_position` is the `x` value *after* the last operation that caused termination.
// If `final_x_position` is 0, it means it terminated with `x <= 0`.
// If `final_x_position` is `n+1`, it means it terminated with `x > n`.
// If it loops, `total_y_accumulated` can be -1.

// `visited[x][parity]` can be used to detect cycles.
// `visited[x][parity] = 0`: not visited
// `visited[x][parity] = 1`: currently visiting (on current recursion stack)
// `visited[x][parity] = 2`: finished visiting (result memoized)

std::vector<long long> a_vals;
int N;

// dp[x][0] for x += a_x, dp[x][1] for x -= a_x
std::vector<std::vector<std::pair<long long, long long>>> dp;
std::vector<std::vector<int>> visited; // 0: unvisited, 1: visiting, 2: visited

// Recursive function to compute dp[x][parity]
// Returns {total_y_added, final_x_value_after_termination}
std::pair<long long, long long> solve(long long current_x, int parity) {
    if (current_x <= 0 || current_x > N) {
        // Already terminated
        return {0, current_x};
    }

    if (visited[current_x][parity] == 1) {
        // Cycle detected
        return {-1, -1}; // Indicate non-termination
    }
    if (visited[current_x][parity] == 2) {
        // Already computed
        return dp[current_x][parity];
    }

    visited[current_x][parity] = 1; // Mark as visiting

    long long val = a_vals[current_x];
    long long next_x;
    long long y_added_this_step = val;

    if (parity == 0) { // x = x + val, y = y + val
        next_x = current_x + val;
        // Next step will be x = x - val, y = y + val (parity 1)
        std::pair<long long, long long> res = solve(next_x, 1);
        if (res.first == -1) { // Cycle detected in subproblem
            dp[current_x][parity] = {-1, -1};
        } else {
            dp[current_x][parity] = {y_added_this_step + res.first, res.second};
        }
    } else { // y = y + val, x = x - val
        next_x = current_x - val;
        // Next step will be x = x + val, y = y + val (parity 0)
        std::pair<long long, long long> res = solve(next_x, 0);
        if (res.first == -1) { // Cycle detected in subproblem
            dp[current_x][parity] = {-1, -1};
        } else {
            dp[current_x][parity] = {y_added_this_step + res.first, res.second};
        }
    }

    visited[current_x][parity] = 2; // Mark as visited
    return dp[current_x][parity];
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    a_vals.resize(N + 1);
    for (int i = 2; i <= N; ++i) {
        std::cin >> a_vals[i];
    }

    dp.resize(N + 1, std::vector<std::pair<long long, long long>>(2, {0, 0}));
    visited.resize(N + 1, std::vector<int>(2, 0));

    for (int i = 1; i < N; ++i) {
        // For each starting a_1 = i
        // Reset visited and dp for each run? No, that would be O(N^2).
        // The DP state is independent of a_1.
        // The only a_val that changes is a_1.
        // So, we only need to compute for a_1 = i.
        // The states (x, parity) where x > 1 are fixed.
        // Only states (1, 0) depend on the current a_1.

        // Initial state: x=1, y=0.
        // First operation: x = x + a_1, y = y + a_1.
        // So, current_x = 1, val = a_1.
        // next_x = 1 + a_1.
        // y_accumulated = a_1.
        // The next state to solve from is (next_x, 1) (because it's a subtract step next).

        a_vals[1] = i; // Set a_1 for this run

        long long initial_val = a_vals[1];
        long long next_x_after_first_step = 1 + initial_val;
        long long y_after_first_step = initial_val;

        // Call solve for the state after the very first operation
        // The first operation is always x = x + a_1, y = y + a_1.
        // So, we are effectively starting the recursive solve from (1 + a_1, parity=1).
        // The total y will be a_1 + result_from_solve.

        // We need to clear visited for the specific path starting from (1,0)
        // This is tricky. If we clear all, it's O(N^2).
        // If we only clear relevant states, it's still potentially O(N) per query.
        // The key is that `a_vals[1]` is the only thing that changes.
        // The `dp` and `visited` arrays are for `a_vals[2...N]` and the current `a_vals[1]`.
        // The `solve` function will compute `dp[x][parity]` for `x > 1` only once across all `i`.
        // For `x = 1`, `dp[1][0]` and `dp[1][1]` are not directly used in the loop.
        // The `solve` function is called with `next_x_after_first_step`.
        // So, `dp` and `visited` for `x > 1` are effectively global memoization.

        // The only state that changes its value based on `i` is `a_vals[1]`.
        // The `solve` function is called with `next_x_after_first_step`.
        // If `next_x_after_first_step` is 1, then it's a special case.
        // But `next_x_after_first_step` is `1 + a_vals[1]`, which is always `1 + i`.
        // Since `i >= 1`, `1 + i >= 2`. So `next_x_after_first_step` is always `>= 2`.
        // This means `solve` is always called for `x >= 2`.
        // Thus, the `dp` and `visited` arrays for `x >= 2` are truly global and can be reused.
        // We don't need to clear `dp` or `visited` for each `i`.

        std::pair<long long, long long> result = solve(next_x_after_first_step, 1);

        if (result.first == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << y_after_first_step + result.first << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // This child is now cured and out of line

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_runaways = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply cry from current_v_cry
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Apply accumulated d_cry from previous runaways
            children[j].p -= total_d_cry_from_runaways;

            // Check if child j runs away
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_cry_from_runaways += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int left_ptr = 0; // Pointer for the elements we want to be smaller (original positions)
    int right_ptr = 0; // Pointer for the elements we want to be larger (permuted positions)

    while (right_ptr < n) {
        // If the current element from the 'larger' pool is strictly greater
        // than the current element from the 'smaller' pool,
        // we can form a pair (a[left_ptr], a[right_ptr]) such that a[right_ptr] > a[left_ptr].
        // We use both elements and increment the count.
        if (a[right_ptr] > a[left_ptr]) {
            count++;
            left_ptr++;
            right_ptr++;
        } else {
            // If a[right_ptr] is not greater than a[left_ptr],
            // we cannot use a[right_ptr] to satisfy the condition for a[left_ptr].
            // We try a larger element for a[right_ptr] by advancing right_ptr.
            // a[left_ptr] remains available to be matched with a potentially larger element later.
            right_ptr++;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long invalid_pairs = 0;

    // max_r_for_l[i] stores the maximum r such that the substring s[i...r]
    // does NOT contain any bad triplet.
    // If max_r_for_l[i] == i-1, it means s[i...i] already contains a bad triplet,
    // or no such r exists (e.g., if i > n).
    // Initialize with n, meaning s[i...n] is initially considered valid.
    std::vector<int> max_r_for_l(n + 1);
    for (int i = 0; i <= n; ++i) {
        max_r_for_l[i] = n;
    }

    // Iterate through all possible x and k to find bad triplets.
    // Indices are 0-based in string, 1-based in problem statement.
    // s_x = s[x-1], s_{x+k} = s[x+k-1], s_{x+2k} = s[x+2k-1]
    // x_0 = x-1, k_0 = k
    // s[x_0] == s[x_0+k_0] == s[x_0+2*k_0]
    // The triplet spans from index x_0 to x_0+2*k_0.
    // In 1-based indexing, this is from x to x+2k.
    // Any interval [l, r] such that l <= x and r >= x+2k is "good".
    // We are interested in intervals [l, r] that are "bad" (do not contain any good triplet).
    // This means we want to find the smallest r_prime = x+2k for each x.
    // For each l, the maximum r such that [l, r] is bad is min(r_prime) - 1 for all r_prime >= l.

    // The problem asks for pairs (l, r) that *do* contain a bad triplet.
    // It's easier to count pairs (l, r) that *do not* contain a bad triplet,
    // and subtract from total.
    // A pair (l, r) does not contain a bad triplet if for all x, k:
    // NOT (l <= x AND x+2k <= r AND s_x = s_{x+k} = s_{x+2k})
    // This means for any bad triplet (x, x+k, x+2k), either l > x or r < x+2k.

    // Let's find the minimum ending point of a bad triplet that starts at or after index i.
    // min_bad_end[i] = min(x+2k) for all bad triplets (x, x+k, x+2k) where x >= i.
    // If no such triplet exists, min_bad_end[i] = n+1.
    std::vector<int> min_bad_end(n + 2, n + 1); // 1-based indexing for l, r

    for (int x_0 = 0; x_0 < n; ++x_0) { // 0-based start index
        for (int k_0 = 1; x_0 + 2 * k_0 < n; ++k_0) { // k_0 is step, 0-based
            if (s[x_0] == s[x_0 + k_0] && s[x_0 + k_0] == s[x_0 + 2 * k_0]) {
                // Found a bad triplet: (x_0, x_0+k_0, x_0+2*k_0)
                // In 1-based indexing: (x_0+1, x_0+k_0+1, x_0+2*k_0+1)
                // The triplet spans from x_0+1 to x_0+2*k_0+1.
                int start_1based = x_0 + 1;
                int end_1based = x_0 + 2 * k_0 + 1;

                // For any l <= start_1based, if r >= end_1based, then (l,r) is a "good" pair.
                // We are interested in "bad" pairs (l,r) that do NOT contain any bad triplet.
                // For a given l, the maximum r such that [l, r] is "bad" is min(end_1based) - 1.
                // So, for each l, we need to find the smallest end_1based such that l <= start_1based.
                // This is equivalent to: for each l, the maximum r for which [l, r] is bad
                // is limited by the first bad triplet that starts at or after l.

                // Update min_bad_end: for any l' from 1 to start_1based,
                // the earliest bad triplet ending point is at least end_1based.
                // So, min_bad_end[l'] = min(min_bad_end[l'], end_1based).
                // This is not quite right. min_bad_end[i] should be the minimum end_1based
                // for any bad triplet (x, x+k, x+2k) where x >= i.
                min_bad_end[start_1based] = std::min(min_bad_end[start_1based], end_1based);
            }
        }
    }

    // Propagate min_bad_end values:
    // min_bad_end[i] should be min(min_bad_end[i], min_bad_end[i+1]).
    // This ensures min_bad_end[i] stores the minimum end_1based for any bad triplet
    // (x, x+k, x+2k) where x >= i.
    for (int i = n; i >= 1; --i) {
        min_bad_end[i] = std::min(min_bad_end[i], min_bad_end[i + 1]);
    }

    // Now, for each l (1-based), the maximum r such that [l, r] does NOT contain
    // any bad triplet is min_bad_end[l] - 1.
    // If min_bad_end[l] == n+1, it means no bad triplet starts at or after l.
    // In this case, all r from l to n are valid "bad" pairs.
    // The number of such r's is n - l + 1.
    // If min_bad_end[l] <= n, then any r >= min_bad_end[l] makes (l,r) a "good" pair.
    // So, r can range from l to min_bad_end[l] - 1.
    // The number of such r's is (min_bad_end[l] - 1) - l + 1 = min_bad_end[l] - l.
    // This count is for "bad" pairs (l,r) that do NOT contain any bad triplet.

    for (int l = 1; l <= n; ++l) {
        // The maximum r such that [l, r] does not contain any bad triplet
        // is min_bad_end[l] - 1.
        // If min_bad_end[l] is n+1, then max_r_for_no_triplet is n.
        // If min_bad_end[l] is some value <= n, then max_r_for_no_triplet is min_bad_end[l]-1.
        // The number of such r's is (max_r_for_no_triplet - l + 1).
        // We need to ensure max_r_for_no_triplet >= l.
        // If min_bad_end[l] <= l, it means a bad triplet starts at or before l and ends at or before l.
        // This implies that even [l,l] contains a bad triplet, which is impossible as x+2k >= x+2.
        // So min_bad_end[l] will always be > l.

        // The number of r's for a given l such that [l, r] does NOT contain a bad triplet
        // is (min_bad_end[l] - 1) - l + 1 = min_bad_end[l] - l.
        // This count is valid as long as min_bad_end[l] - 1 >= l.
        // If min_bad_end[l] - 1 < l, it means there are 0 such r's.
        // This happens if min_bad_end[l] <= l.
        // Example: l=1, min_bad_end[1]=3. r can be 1, 2. Count = 3-1 = 2.
        // Example: l=1, min_bad_end[1]=n+1. r can be 1...n. Count = (n+1)-1 = n.

        invalid_pairs += std::max(0, min_bad_end[l] - l);
    }

    std::cout << total_pairs - invalid_pairs << std::endl;

    return 0;
}

#include <algorithm>
#include <iostream>
