struct Element {
    int value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long min_a = elements[0].value;
    long long max_a = elements[n - 1].value;

    // Case 1: All elements in one subsequence (e.g., subsequence 1).
    // All f(a_i, a_j) = a_i + a_j.
    // min_f = a_1 + a_2
    // max_f = a_{n-1} + a_n
    // Goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    long long goodness1 = (long long)elements[n - 2].value + elements[n - 1].value -
                          ((long long)elements[0].value + elements[1].value);

    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: At least one element in each subsequence.
    // The minimum possible f value is min_a + min_a (if min_a is in a subsequence with another element)
    // or min_a + min_a + h (if min_a is in a different subsequence than another element).
    // The minimum possible f value is always at least min_a + min_a.
    // The maximum possible f value is always at most max_a + max_a + h.

    // Let's consider the minimum possible f value.
    // It must be either a_1 + a_2 (if a_1 and a_2 are in the same group)
    // or a_1 + a_2 + h (if a_1 and a_2 are in different groups).
    // So, min_f = min(a_1 + a_2, a_1 + a_2 + h) = a_1 + a_2.
    // This is incorrect. The minimum f value could be a_1 + a_k for some k > 1.
    // The minimum possible sum of two elements is elements[0].value + elements[1].value.
    // This sum can be either elements[0].value + elements[1].value or elements[0].value + elements[1].value + h.
    // So, the absolute minimum f value is elements[0].value + elements[1].value.

    // Let's consider the maximum possible f value.
    // It must be either a_{n-1} + a_n (if a_{n-1} and a_n are in the same group)
    // or a_{n-1} + a_n + h (if a_{n-1} and a_n are in different groups).
    // So, the absolute maximum f value is elements[n-2].value + elements[n-1].value + h.

    // The minimum possible f value is elements[0].value + elements[1].value.
    // The maximum possible f value is elements[n-1].value + elements[n-2].value + h.
    // Goodness = (elements[n-1].value + elements[n-2].value + h) - (elements[0].value + elements[1].value).
    // This is the goodness if we ensure that elements[0] and elements[1] are in the same group,
    // and elements[n-1] and elements[n-2] are in different groups.
    // This is not necessarily the optimal strategy.

    // Let's consider the two main scenarios for the minimum and maximum f values.
    // The minimum f value will always be `elements[0].value + elements[1].value`.
    // The maximum f value will always be `elements[n-1].value + elements[n-2].value + h`.
    // This is because if we put elements[0] and elements[1] in different groups, their sum is elements[0].value + elements[1].value + h.
    // If we put them in the same group, their sum is elements[0].value + elements[1].value.
    // So the minimum possible f value is elements[0].value + elements[1].value.
    // Similarly, the maximum possible f value is elements[n-1].value + elements[n-2].value + h.

    // The only way to reduce the maximum f value is to put elements[n-1] and elements[n-2] in the same group.
    // The only way to increase the minimum f value is to put elements[0] and elements[1] in different groups.

    // Let's analyze the four critical values:
    // S_min_same = elements[0].value + elements[1].value
    // S_min_diff = elements[0].value + elements[1].value + h
    // S_max_same = elements[n-2].value + elements[n-1].value
    // S_max_diff = elements[n-2].value + elements[n-1].value + h

    // The overall minimum f value for any partition is at least S_min_same.
    // The overall maximum f value for any partition is at most S_max_diff.

    // Consider the partition where elements[0] is in group 1, and all other elements are in group 2.
    // min_f: elements[0].value + elements[1].value + h (from a_0 and a_1)
    // max_f: elements[n-2].value + elements[n-1].value (from a_{n-2} and a_{n-1})
    // Goodness = (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value + h)
    // This goodness can be negative if h is large. This means the min_f is larger than max_f, which is impossible.
    // The actual min_f is min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value).
    // The actual max_f is max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value).

    // Let's consider the two main strategies:
    // Strategy A: Put all elements in one group.
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-2].value + elements[n-1].value
    // Goodness = (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value)
    // This is `goodness1`.

    // Strategy B: Put elements[0] in group 1, and all other elements in group 2.
    // min_f:
    //   - elements[0].value + elements[1].value + h (a_0 in G1, a_1 in G2)
    //   - elements[1].value + elements[2].value (a_1 in G2, a_2 in G2)
    //   So, min_f = std::min((long long)elements[0].value + elements[1].value + h,
    //                        (long long)elements[1].value + elements[2].value);
    // max_f:
    //   - elements[0].value + elements[n-1].value + h (a_0 in G1, a_{n-1} in G2)
    //   - elements[n-2].value + elements[n-1].value (a_{n-2} in G2, a_{n-1} in G2)
    //   So, max_f = std::max((long long)elements[0].value + elements[n-1].value + h,
    //                        (long long)elements[n-2].value + elements[n-1].value);
    // Goodness = max_f - min_f.

    long long min_f_B = std::min((long long)elements[0].value + elements[1].value + h,
                                 (long long)elements[1].value + elements[2].value);
    long long max_f_B = std::max((long long)elements[0].value + elements[n - 1].value + h,
                                 (long long)elements[n - 2].value + elements[n - 1].value);
    long long goodness2 = max_f_B - min_f_B;

    // Strategy C: Put elements[n-1] in group 1, and all other elements in group 2.
    // This is symmetric to Strategy B.
    // min_f:
    //   - elements[0].value + elements[1].value (a_0 in G2, a_1 in G2)
    //   - elements[0].value + elements[n-1].value + h (a_0 in G2, a_{n-1} in G1)
    //   So, min_f = std::min((long long)elements[0].value + elements[1].value,
    //                        (long long)elements[0].value + elements[n-1].value + h);
    // max_f:
    //   - elements[n-2].value + elements[n-1].value + h (a_{n-2} in G2, a_{n-1} in G1)
    //   - elements[n-2].value + elements[n-3].value (a_{n-2} in G2, a_{n-3} in G2)
    //   So, max_f = std::max((long long)elements[n-2].value + elements[n-1].value + h,
    //                        (long long)elements[n-3].value + elements[n-2].value);
    // Goodness = max_f - min_f.
    // This is only relevant if n >= 3. If n=2, this is the same as Strategy B.

    // For n=2, Strategy A: goodness = (a_0+a_1) - (a_0+a_1) = 0. Partition: 1 1.
    // For n=2, Strategy B: a_0 in G1, a_1 in G2.
    // min_f = a_0+a_1+h. max_f = a_0+a_1+h. Goodness = 0. Partition: 1 2.
    // So for n=2, goodness is always 0.

    if (n == 2) {
        std::cout << 0 << std::endl;
        std::cout << "1 1" << std::endl;
        return 0;
    }

    // The problem states that one of the subsequences can be empty.
    // Case 1 (all in one group) is covered by `goodness1`.
    // The other main case is when both groups are non-empty.
    // In this case, the minimum possible f value is `elements[0].value + elements[1].value`.
    // The maximum possible f value is `elements[n-1].value + elements[n-2].value + h`.
    // This is because if elements[0] and elements[1] are in different groups, their sum is `elements[0].value + elements[1].value + h`.
    // If they are in the same group, their sum is `elements[0].value + elements[1].value`.
    // So the minimum possible f value is `elements[0].value + elements[1].value`.
    // Similarly, the maximum possible f value is `elements[n-1].value + elements[n-2].value + h`.

    // The critical observation is that the minimum possible value of f is `elements[0].value + elements[1].value`.
    // The critical observation is that the maximum possible value of f is `elements[n-1].value + elements[n-2].value + h`.
    // This is because if we put elements[0] and elements[1] in different groups, their sum is `elements[0].value + elements[1].value + h`.
    // If we put them in the same group, their sum is `elements[0].value + elements[1].value`.
    // So the minimum possible f value is `elements[0].value + elements[1].value`.
    // Similarly, the maximum possible f value is `elements[n-1].value + elements[n-2].value + h`.

    // The only way to reduce the maximum f value is to put elements[n-1] and elements[n-2] in the same group.
    // The only way to increase the minimum f value is to put elements[0] and elements[1] in different groups.

    // Let's consider the two main candidates for optimal partition:
    // 1. All elements in one group (e.g., group 1).
    //    min_f = elements[0].value + elements[1].value
    //    max_f = elements[n-2].value + elements[n-1].value
    //    Goodness = (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value)
    //    This is `goodness1`.

    // 2. Elements[0] in group 1, and all other elements in group 2.
    //    min_f:
    //      - elements[0].value + elements[1].value + h (a_0 in G1, a_1 in G2)
    //      - elements[1].value + elements[2].value (a_1 in G2, a_2 in G2)
    //      So, min_f = std::min((long long)elements[0].value + elements[1].value + h,
    //                           (long long)elements[1].value + elements[2].value);
    //    max_f:
    //      - elements[0].value + elements[n-1].value + h (a_0 in G1, a_{n-1} in G2)
    //      - elements[n-2].value + elements[n-1].value (a_{n-2} in G2, a_{n-1} in G2)
    //      So, max_f = std::max((long long)elements[0].value + elements[n-1].value + h,
    //                           (long long)elements[n-2].value + elements[n-1].value);
    //    Goodness = max_f - min_f.
    //    This is `goodness2`.

    // The minimum goodness is the minimum of these two strategies.
    // The partition for strategy 1 is all 1s.
    // The partition for strategy 2 is elements[0] gets 1, others get 2.

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << std::endl;
        for (int i = 0; i < n; ++i) {
