    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_ptr = 0; // Pointer for target tracks
    int h_ptr = 0; // Pointer for heads

    while (p_ptr < m) {
        if (h_ptr >= n) {
            return false; // Ran out of heads but still have tracks to cover
        }

        // Find the first head that can potentially cover p[p_ptr]
        // A head h[h_ptr] can cover p[p_ptr] if h[h_ptr] <= p[p_ptr] + T
        // and p[p_ptr] <= h[h_ptr] + T.
        // The second condition is equivalent to h[h_ptr] >= p[p_ptr] - T.
        // So, h[h_ptr] must be in [p[p_ptr] - T, p[p_ptr] + T].
        // We want to use a head that is as far left as possible to cover p[p_ptr],
        // but also not "waste" it on tracks too far left if it can cover p[p_ptr].

        // Skip heads that are too far left to ever reach p[p_ptr]
        // A head h[h_ptr] cannot reach p[p_ptr] if h[h_ptr] + T < p[p_ptr].
        // We can advance h_ptr past such heads.
        while (h_ptr < n && h[h_ptr] + T < p[p_ptr]) {
            h_ptr++;
        }

        if (h_ptr >= n) {
            return false; // No head can reach p[p_ptr]
        }

        // Now h[h_ptr] is the first head such that h[h_ptr] + T >= p[p_ptr].
        // This head can potentially cover p[p_ptr].
        // The range covered by this head is [h[h_ptr] - T, h[h_ptr] + T].
        // If p[p_ptr] is not in this range (i.e., p[p_ptr] < h[h_ptr] - T),
        // then this head is too far right to cover p[p_ptr] without moving left.
        // In this case, we need to use a different head (or this head moves left).
        // But we are trying to cover p[p_ptr] with the *current* h[h_ptr].
        // If p[p_ptr] < h[h_ptr] - T, then h[h_ptr] is too far right.
        // This means no subsequent head h[h_ptr+k] (k>0) can cover p[p_ptr] either,
        // because h[h_ptr+k] > h[h_ptr], so h[h_ptr+k] - T > h[h_ptr] - T.
        // So if h[h_ptr] is too far right, we cannot cover p[p_ptr] with any remaining head.
        if (p[p_ptr] < h[h_ptr] - T) {
            return false;
        }

        // If we reach here, h[h_ptr] can cover p[p_ptr].
        // The head h[h_ptr] covers the range [h[h_ptr] - T, h[h_ptr] + T].
        // We use this head to cover as many tracks as possible to its right.
        long long current_head_coverage_end = h[h_ptr] + T;
        while (p_ptr < m && p[p_ptr] <= current_head_coverage_end) {
            p_ptr++;
        }
        h_ptr++; // Move to the next head
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible distance between p_m and h_1, or p_1 and h_n
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

